// অষ্টকূট পদ্ধতিতে কুষ্ঠি মিলন + YotakBicharEngine\n// পূর্ব ভারতীয় কুষ্ঠি সফটওয়্যার\n// ============================================================\n\n// ==================== ১. নক্ষত্রের ডেটা ====================\n\n// ২৭ নক্ষত্রের গণ (দেব/মনুষ্য/রাক্ষস)\nconst NAKSHATRA_GANA = {\n    \"অশ্বিনী\": \"দেব\", \"ভরণী\": \"মনুষ্য\", \"কৃত্তিকা\": \"রাক্ষস\",\n    \"রোহিণী\": \"মনুষ্য\", \"মৃগশিরা\": \"দেব\", \"আর্দ্রা\": \"মনুষ্য\",\n    \"পুনর্বসু\": \"দেব\", \"পুষ্যা\": \"দেব\", \"অশ্লেষা\": \"রাক্ষস\",\n    \"মঘা\": \"রাক্ষস\", \"পূর্বফাল্গুনী\": \"মনুষ্য\", \"উত্তরফাল্গুনী\": \"মনুষ্য\",\n    \"হস্তা\": \"দেব\", \"চিত্রা\": \"রাক্ষস\", \"স্বাতী\": \"দেব\",\n    \"বিশাখা\": \"রাক্ষস\", \"অনুরাধা\": \"দেব\", \"জ্যেষ্ঠা\": \"রাক্ষস\",\n    \"মূলা\": \"রাক্ষস\", \"পূর্বাষাঢ়া\": \"মনুষ্য\", \"উত্তরাষাঢ়া\": \"মনুষ্য\",\n    \"শ্রবণা\": \"দেব\", \"ধনিষ্ঠা\": \"রাক্ষস\", \"শতভিষা\": \"রাক্ষস\",\n    \"পূর্বভাদ্রপদ\": \"মনুষ্য\", \"উত্তরভাদ্রপদ\": \"মনুষ্য\", \"রেবতী\": \"দেব\"\n};\n\n// নক্ষত্রের বর্ণ\nconst NAKSHATRA_VARNA = {\n    \"অশ্বিনী\": \"ব্রাহ্মণ\", \"ভরণী\": \"ক্ষত্রিয়\", \"কৃত্তিকা\": \"ব্রাহ্মণ\",\n    \"রোহিণী\": \"শূদ্র\", \"মৃগশিরা\": \"ক্ষত্রিয়\", \"আর্দ্রা\": \"ব্রাহ্মণ\",\n    \"পুনর্বসু\": \"বৈশ্য\", \"পুষ্যা\": \"ক্ষত্রিয়\", \"অশ্লেষা\": \"শূদ্র\",\n    \"মঘা\": \"শূদ্র\", \"পূর্বফাল্গুনী\": \"ব্রাহ্মণ\", \"উত্তরফাল্গুনী\": \"ক্ষত্রিয়\",\n    \"হস্তা\": \"বৈশ্য\", \"চিত্রা\": \"শূদ্র\", \"স্বাতী\": \"বৈশ্য\",\n    \"বিশাখা\": \"ক্ষত্রিয়\", \"অনুরাধা\": \"শূদ্র\", \"জ্যেষ্ঠা\": \"বৈশ্য\",\n    \"মূলা\": \"শূদ্র\", \"পূর্বাষাঢ়া\": \"ব্রাহ্মণ\", \"উত্তরাষাঢ়া\": \"ক্ষত্রিয়\",\n    \"শ্রবণা\": \"ব্রাহ্মণ\", \"ধনিষ্ঠা\": \"বৈশ্য\", \"শতভিষা\": \"শূদ্র\",\n    \"পূর্বভাদ্রপদ\": \"ব্রাহ্মণ\", \"উত্তরভাদ্রপদ\": \"ক্ষত্রিয়\", \"রেবতী\": \"শূদ্র\"\n};\n\n// ==================== ২. মাঙ্গলিক দোষ ====================\n\nfunction checkManglikDosha(marsRashi, lagnaRashi) {\n    const rashiOrder = [\"মেষ\", \"বৃষ\", \"মিথুন\", \"কর্কট\", \"সিংহ\", \"কন্যা\", \"তুলা\", \"বৃশ্চিক\", \"ধনু\", \"মকর\", \"কুম্ভ\", \"মীন\"];\n    const marsIdx = rashiOrder.indexOf(marsRashi);\n    const lagnaIdx = rashiOrder.indexOf(lagnaRashi);\n    \n    if (marsIdx === -1 || lagnaIdx === -1) return { isManglik: false, house: -1, description: \"তথ্য নেই\" };\n    \n    const house = ((marsIdx - lagnaIdx + 12) % 12) + 1;\n    const isManglik = [1, 2, 4, 7, 8, 12].includes(house);\n    \n    return {\n        isManglik,\n        hasDosha: isManglik,\n        house,\n        description: isManglik\n            ? `মঙ্গল ${house}ম ভাবে — মাঙ্গলিক দোষ আছে`\n            : `মঙ্গল ${house}ম ভাবে — মাঙ্গলিক দোষ নেই`\n    };\n}\n\n// ==================== ২ক. কালসর্প যোগ ====================\n// রাহু-কেতু অক্ষের একদিকে সাতটি গ্রহ (সূর্য, চন্দ্র, মঙ্গল, বুধ, বৃহস্পতি, শুক্র, শনি) থাকলে কালসর্প যোগ হয়\nfunction checkKaalSarpaYoga(planets) {\n    if (!Array.isArray(planets)) return { hasYoga: false, description: \"তথ্য নেই\" };\n\n    const rahu = planets.find(p => p.name === \"রাহু\");\n    const ketu = planets.find(p => p.name === \"কেতু\");\n    if (!rahu || !ketu) return { hasYoga: false, description: \"তথ্য নেই\" };\n\n    const others = planets.filter(p => ![\"রাহু\", \"কেতু\", \"লগ্ন\"].includes(p.name));\n    if (others.length === 0) return { hasYoga: false, description: \"তথ্য নেই\" };\n\n    function inArc(lon, start, end) {\n        const diff = ((lon - start) % 360 + 360) % 360;\n        const arcLen = ((end - start) % 360 + 360) % 360;\n        return diff <= arcLen;\n    }\n\n    const allInForward = others.every(p => inArc(p.lon, rahu.lon, ketu.lon));\n    const allInBackward = others.every(p => inArc(p.lon, ketu.lon, rahu.lon));\n    const hasYoga = allInForward || allInBackward;\n\n    return {\n        hasYoga,\n        type: allInForward ? 'rahu-ketu' : (allInBackward ? 'ketu-rahu' : null),\n        description: hasYoga\n            ? \"সমস্ত গ্রহ রাহু-কেতু অক্ষের একদিকে — কালসর্প যোগ আছে\"\n            : \"কালসর্প যোগ নেই\"\n    };\n}\n\n// ==================== ৩. পূর্ণাঙ্গ মিলন (YotakBicharEngine সহ) ====================\n\nfunction calculateMatchMaking(girlData, boyData) {\n    // YotakBicharEngine — একমাত্র উৎস-অফ-ট্রুথ (একই ফাইলে সংযুক্ত, সর্বদা উপলব্ধ)\n    if (typeof YotakBicharEngine === 'undefined') {\n        throw new Error(\"YotakBicharEngine লোড হয়নি — গণনা সম্ভব নয়।\");\n    }\n    const engine = new YotakBicharEngine();\n    const result = engine.match(girlData, boyData);\n    const k = result.kootas;\n\n    // Normalize kootas keys to match the HTML display (vasu, bhakoota)\n    const kootas = {\n        varna:       k.varna,\n        vasu:        k.vashya,      // engine uses \"vashya\", HTML expects \"vasu\"\n        tara:        k.tara,\n        yoni:        k.yoni,\n        grahaMaitri: k.grahaMaitri,\n        gana:        k.gana,\n        bhakoota:    k.rashi,        // engine uses \"rashi\", HTML expects \"bhakoota\"\n        nadi:        k.nadi\n    };\n\n    return {\n        totalScore:  result.total,\n        totalPoints: result.total,  // alias used by HTML display\n        maxScore:    result.max,\n        result:      result.verdict,\n        varna: k.varna.points, vashya: k.vashya.points, tara: k.tara.points,\n        yoni: k.yoni.points, graha: k.grahaMaitri.points, gana: k.gana.points,\n        bhakoot: k.rashi.points, nadi: k.nadi.points,\n        kootas,\n        manglik: result.manglik,\n        isRajaYotak: result.isRajaYotak,\n        verdictFull: result.verdictFull,\n        remedies: result.remedies,\n        fullPredictions: {\n            varna: k.varna.full, vashya: k.vashya.full, tara: k.tara.full,\n            yoni: k.yoni.full, grahaMaitri: k.grahaMaitri.full, gana: k.gana.full,\n            rashi: k.rashi.full, nadi: k.nadi.full\n        }\n    };\n}\n\n// ==================== ৪. পূর্ণাঙ্গ রিপোর্ট ====================\n\nfunction generateMatchMakingReport(matchResult, girlName, boyName) {\n    const gName = girlName || \"কন্যা\";\n    const bName = boyName || \"বর\";\n    const SEP = \"\\n\" + \"- \".repeat(20) + \"\\n\";\n\n    let output = \"💑 কুষ্ঠি মিলন — যোটক-বিচার ফলাফল\\n\" + SEP;\n\n    output += `👰 কন্যা: ${gName}\\n🤵 বর: ${bName}\\n\\n`;\n    output += `📊 মোট গুণ: ${matchResult.totalScore} / ${matchResult.maxScore}\\n`;\n    output += `📋 ফলাফল: ${matchResult.result}\\n\\n`;\n\n    if (matchResult.isRajaYotak) output += \"👑 রাজযোটক যোগ বিদ্যমান!\\n\\n\";\n    output += matchResult.verdictFull + \"\\n\\n\";\n\n    output += \"📝 অষ্টকূট বিবরণ:\" + SEP;\n    const kootaDefs = [\n        { name: \"বর্ণকূট\", key: \"varna\", max: 1 },\n        { name: \"বশ্যকূট\", key: \"vashya\", max: 2 },\n        { name: \"তারাকূট\", key: \"tara\", max: 3 },\n        { name: \"যোনিকূট\", key: \"yoni\", max: 4 },\n        { name: \"গ্রহমৈত্রীকূট\", key: \"grahaMaitri\", max: 5 },\n        { name: \"গণমৈত্রীকূট\", key: \"gana\", max: 6 },\n        { name: \"রাশিকূট (ভকূট)\", key: \"rashi\", max: 7 },\n        { name: \"ত্রিনাড়ীকূট\", key: \"nadi\", max: 8 }\n    ];\n\n    kootaDefs.forEach(k => {\n        const _ko1=matchResult.kootas[k.key]||{};\n        const pts = (_ko1.points!=null?_ko1.points:0) || 0;\n        const icon = pts === k.max ? \"✨\" : pts === 0 ? \"⚠️\" : \"🔸\";\n        output += `${icon} ${k.name}: ${pts}/${k.max} গুণ\\n`;\n    });\n\n    output += \"\\n📖 বিস্তারিত ফলাফল:\" + SEP;\n\n    kootaDefs.forEach(k => {\n        const full = matchResult.fullPredictions[k.key];\n        if (full) output += `🕉️ ${k.name}:\\n${full}\\n\\n`;\n    });\n\n    output += \"🔴 মাঙ্গলিক দোষ:\" + SEP;\n    output += `👰 ${gName}: ${matchResult.manglik.girl.full}\\n\\n`;\n    output += `🤵 ${bName}: ${matchResult.manglik.boy.full}\\n\\n`;\n\n    if (matchResult.manglik.match) {\n        output += \"✅ উভয়ের মাঙ্গলিক অবস্থা সমান — দোষ পরস্পর বাতিল।\\n\\n\";\n    } else {\n        output += \"⚠️ উভয়ের মাঙ্গলিক অবস্থা অসমান — প্রতিকার আবশ্যক।\\n\\n\";\n    }\n\n    output += \"🙏 প্রতিকার:\" + SEP;\n    (matchResult.remedies || []).forEach(r => output += r + \"\\n\");\n\n    output += SEP + \"🕉️ ওঁ নমঃ শিবায়। বিবাহ মহাবন্ধন—সঠিক বিচার করে তবেই এই বন্ধনে আবদ্ধ হোন।\\nশুভম ভবতু। মাঙ্গল্যম ভবতু।\\n\";\n\n    return output;\n}\n\nconsole.log(\"✅ match-making.js — YotakBicharEngine সহ সম্পূর্ণ লোড\");\nconsole.log(\"🔍 calculateMatchMaking(girlData, boyData)\");\nconsole.log(\"🔍 generateMatchMakingReport(result, 'মেয়ের নাম', 'ছেলের নাম')\");\n\n/**\n * ============================================================\n * yotak-bichar.js — COMPLETE UPDATED VERSION\n * Vedic Astrology Ashtakoot Match Making (যোটক-বিচার)\n * 8 Kootas × Detailed Philosophical Predictions\n * Language: Bengali (বাংলা) | Personal Address (আপনাদের)\n * Classical References + Remedies + Manglik Dosha\n * ============================================================\n */\n\nclass YotakBicharEngine {\n    constructor() {\n        // ==================== মৌলিক ডেটা ====================\n        this.rashiNames = [\n            \"মেষ\", \"বৃষ\", \"মিথুন\", \"কর্কট\", \"সিংহ\", \"কন্যা\",\n            \"তুলা\", \"বৃশ্চিক\", \"ধনু\", \"মকর\", \"কুম্ভ\", \"মীন\"\n        ];\n\n        this.nakshatraNames = [\n            \"অশ্বিনী\", \"ভরণী\", \"কৃত্তিকা\", \"রোহিণী\", \"মৃগশিরা\", \"আর্দ্রা\",\n            \"পুনর্বসু\", \"পুষ্যা\", \"অশ্লেষা\", \"মঘা\", \"পূর্বফাল্গুনী\", \"উত্তরফাল্গুনী\",\n            \"হস্তা\", \"চিত্রা\", \"স্বাতী\", \"বিশাখা\", \"অনুরাধা\", \"জ্যেষ্ঠা\",\n            \"মূলা\", \"পূর্বাষাঢ়া\", \"উত্তরাষাঢ়া\", \"শ্রবণা\", \"ধনিষ্ঠা\", \"শতভিষা\",\n            \"পূর্বভাদ্রপদ\", \"উত্তরভাদ্রপদ\", \"রেবতী\"\n        ];\n\n        // রাশি অনুযায়ী বর্ণ (শাস্ত্রীয়)\n        this.rashiVarna = {\n            \"মীন\": \"বিপ্র\", \"কর্কট\": \"বিপ্র\", \"বৃশ্চিক\": \"বিপ্র\",\n            \"মেষ\": \"ক্ষত্রিয়\", \"সিংহ\": \"ক্ষত্রিয়\", \"ধনু\": \"ক্ষত্রিয়\",\n            \"বৃষ\": \"বৈশ্য\", \"কন্যা\": \"বৈশ্য\", \"মকর\": \"বৈশ্য\",\n            \"মিথুন\": \"শূদ্র\", \"তুলা\": \"শূদ্র\", \"কুম্ভ\": \"শূদ্র\"\n        };\n        this.varnaRank = { \"বিপ্র\": 4, \"ক্ষত্রিয়\": 3, \"বৈশ্য\": 2, \"শূদ্র\": 1 };\n\n        // নক্ষত্র গণ\n        this.nakshatraGana = {\n            \"অশ্বিনী\":\"দেব\", \"মৃগশিরা\":\"দেব\", \"পুনর্বসু\":\"দেব\", \"পুষ্যা\":\"দেব\",\n            \"হস্তা\":\"দেব\", \"স্বাতী\":\"দেব\", \"অনুরাধা\":\"দেব\", \"শ্রবণা\":\"দেব\", \"রেবতী\":\"দেব\",\n            \"ভরণী\":\"নর\", \"রোহিণী\":\"নর\", \"আর্দ্রা\":\"নর\", \"পূর্বফাল্গুনী\":\"নর\",\n            \"উত্তরফাল্গুনী\":\"নর\", \"পূর্বাষাঢ়া\":\"নর\", \"উত্তরাষাঢ়া\":\"নর\",\n            \"পূর্বভাদ্রপদ\":\"নর\", \"উত্তরভাদ্রপদ\":\"নর\",\n            \"কৃত্তিকা\":\"রাক্ষস\", \"অশ্লেষা\":\"রাক্ষস\", \"মঘা\":\"রাক্ষস\",\n            \"চিত্রা\":\"রাক্ষস\", \"বিশাখা\":\"রাক্ষস\", \"জ্যেষ্ঠা\":\"রাক্ষস\",\n            \"মূলা\":\"রাক্ষস\", \"ধনিষ্ঠা\":\"রাক্ষস\", \"শতভিষা\":\"রাক্ষস\"\n        };\n\n        // নক্ষত্র যোনি\n        this.nakshatraYoni = {\n            \"অশ্বিনী\":\"অশ্ব\", \"শতভিষা\":\"অশ্ব\",\n            \"স্বাতী\":\"মহিষ\", \"হস্তা\":\"মহিষ\",\n            \"পূর্বভাদ্রপদ\":\"সিংহ\", \"ধনিষ্ঠা\":\"সিংহ\",\n            \"ভরণী\":\"হস্তী\", \"রেবতী\":\"হস্তী\",\n            \"কৃত্তিকা\":\"মেষ\", \"পুষ্যা\":\"মেষ\",\n            \"পূর্বাষাঢ়া\":\"বানর\", \"শ্রবণা\":\"বানর\",\n            \"রোহিণী\":\"সর্প\", \"মৃগশিরা\":\"সর্প\",\n            \"জ্যেষ্ঠা\":\"হরিণ\", \"অনুরাধা\":\"হরিণ\",\n            \"আর্দ্রা\":\"কুকুর\", \"মূলা\":\"কুকুর\",\n            \"উত্তরফাল্গুনী\":\"গো\", \"উত্তরভাদ্রপদ\":\"গো\",\n            \"চিত্রা\":\"ব্যাঘ্র\", \"বিশাখা\":\"ব্যাঘ্র\",\n            \"অশ্লেষা\":\"বিড়াল\", \"পুনর্বসু\":\"বিড়াল\",\n            \"মঘা\":\"ইন্দুর\", \"পূর্বফাল্গুনী\":\"ইন্দুর\",\n            \"উত্তরাষাঢ়া\":\"নকুল\"\n        };\n\n        // যোনি শত্রুতা\n        this.yoniEnmity = {\n            \"গো\":\"ব্যাঘ্র\", \"ব্যাঘ্র\":\"গো\", \"হস্তী\":\"সিংহ\", \"সিংহ\":\"হস্তী\",\n            \"অশ্ব\":\"মহিষ\", \"মহিষ\":\"অশ্ব\", \"কুকুর\":\"হরিণ\", \"হরিণ\":\"কুকুর\",\n            \"সর্প\":\"নকুল\", \"নকুল\":\"সর্প\", \"বানর\":\"মেষ\", \"মেষ\":\"বানর\",\n            \"বিড়াল\":\"ইন্দুর\", \"ইন্দুর\":\"বিড়াল\"\n        };\n\n        // নক্ষত্র নাড়ী\n        this.nakshatraNadi = {\n            \"অশ্বিনী\":\"আদ্য\", \"আর্দ্রা\":\"আদ্য\", \"পূর্বভাদ্রপদ\":\"আদ্য\",\n            \"পুনর্বসু\":\"আদ্য\", \"হস্তা\":\"আদ্য\", \"জ্যেষ্ঠা\":\"আদ্য\",\n            \"মূলা\":\"আদ্য\", \"শ্রবণা\":\"আদ্য\", \"রেবতী\":\"আদ্য\",\n            \"ভরণী\":\"মধ্য\", \"মৃগশিরা\":\"মধ্য\", \"পুষ্যা\":\"মধ্য\",\n            \"পূর্বফাল্গুনী\":\"মধ্য\", \"চিত্রা\":\"মধ্য\", \"অনুরাধা\":\"মধ্য\",\n            \"পূর্বাষাঢ়া\":\"মধ্য\", \"ধনিষ্ঠা\":\"মধ্য\", \"উত্তরভাদ্রপদ\":\"মধ্য\",\n            \"কৃত্তিকা\":\"অন্ত্য\", \"রোহিণী\":\"অন্ত্য\", \"অশ্লেষা\":\"অন্ত্য\",\n            \"মঘা\":\"অন্ত্য\", \"উত্তরফাল্গুনী\":\"অন্ত্য\", \"স্বাতী\":\"অন্ত্য\",\n            \"বিশাখা\":\"অন্ত্য\", \"উত্তরাষাঢ়া\":\"অন্ত্য\", \"শতভিষা\":\"অন্ত্য\"\n        };\n\n        // রাশ্যাধিপতি\n        this.rashiLords = {\n            \"মেষ\":\"মঙ্গল\", \"বৃষ\":\"শুক্র\", \"মিথুন\":\"বুধ\", \"কর্কট\":\"চন্দ্র\",\n            \"সিংহ\":\"সূর্য\", \"কন্যা\":\"বুধ\", \"তুলা\":\"শুক্র\", \"বৃশ্চিক\":\"মঙ্গল\",\n            \"ধনু\":\"বৃহস্পতি\", \"মকর\":\"শনি\", \"কুম্ভ\":\"শনি\", \"মীন\":\"বৃহস্পতি\"\n        };\n\n        // গ্রহ মিত্রতা\n        this.planetRelations = {\n            \"সূর্য\":{f:[\"চন্দ্র\",\"মঙ্গল\",\"বৃহস্পতি\"],e:[\"শুক্র\",\"শনি\"]},\n            \"চন্দ্র\":{f:[\"সূর্য\",\"বুধ\"],e:[\"শুক্র\",\"শনি\"]},\n            \"মঙ্গল\":{f:[\"সূর্য\",\"চন্দ্র\",\"বৃহস্পতি\"],e:[\"বুধ\",\"শুক্র\",\"শনি\"]},\n            \"বুধ\":{f:[\"সূর্য\",\"শুক্র\"],e:[\"চন্দ্র\"]},\n            \"বৃহস্পতি\":{f:[\"সূর্য\",\"চন্দ্র\",\"মঙ্গল\"],e:[\"বুধ\",\"শুক্র\"]},\n            \"শুক্র\":{f:[\"বুধ\",\"শনি\"],e:[\"সূর্য\",\"চন্দ্র\"]},\n            \"শনি\":{f:[\"বুধ\",\"শুক্র\"],e:[\"সূর্য\",\"চন্দ্র\",\"মঙ্গল\"]}\n        };\n\n        this.manglikHouses = [1, 2, 4, 7, 8, 12];\n    }\n\n    getNakshatraIndex(nak) { return this.nakshatraNames.indexOf(nak); }\n    getRashiIndex(rashi) { return this.rashiNames.indexOf(rashi); }\n\n    /**\n     * ১. বর্ণকূট (সর্বোচ্চ ১ গুণ)\n     * বরের বর্ণ কন্যার সমান বা উচ্চ হলে শুভ\n     */\n    calcVarna(girlRashi, boyRashi) {\n        const gv = this.rashiVarna[girlRashi] || \"শূদ্র\";\n        const bv = this.rashiVarna[boyRashi] || \"শূদ্র\";\n        const gRank = this.varnaRank[gv] || 1;\n        const bRank = this.varnaRank[bv] || 1;\n\n        let points = 0;\n        if (bRank >= gRank) points = 1;\n        else if (bRank === gRank - 1) points = 0.5;\n\n        const full = bRank > gRank\n            ? `বরের বর্ণ ${bv} এবং কন্যার বর্ণ ${gv}—বরের বর্ণ কন্যার অপেক্ষা শ্রেষ্ঠ, যা সম্পূর্ণ শাস্ত্রসম্মত। এই বর্ণমিলন দাম্পত্য জীবনে সম্মান ও মর্যাদা বয়ে আনে। বর হবেন সংসারের মেরুদণ্ড—যাঁর নেতৃত্বে পরিবার সুখী ও সমৃদ্ধ হবে। কন্যা পাবেন যোগ্য সম্মান ও নিরাপত্তা। যেমন আকাশে সূর্য উদিত হলে চন্দ্রের জ্যোৎস্না আরও মধুর হয়, তেমনি উচ্চবর্ণের স্বামী পেলে নারীর জীবন পূর্ণতা পায়। তবে মনে রাখবেন—বর্ণ দিয়ে মানুষ মাপা যায় না, গুণেই মানুষ প্রকৃত মহৎ হয়।`\n            : bRank === gRank\n            ? `বর ও কন্যা উভয়ের বর্ণ ${bv}—একই বর্ণের মিলন, যা সমমর্যাদার প্রতীক। এই যোগে দাম্পত্য জীবনে কেউ কাউকে ছোট করবে না, কেউ কারও কাছে নিজেকে বড়ও ভাববে না। যেমন দুই সমান শিখার প্রদীপ মিলে এক উজ্জ্বল আলো তৈরি করে, তেমনি সমবর্ণের দম্পতি মিলে এক শক্তিশালী সংসার গড়ে তোলে। সম্মান, শ্রদ্ধা ও বোঝাপড়াই হবে এই সম্পর্কের মূল ভিত্তি।`\n            : `কন্যার বর্ণ ${gv} বরের বর্ণ ${bv} অপেক্ষা উচ্চতর—এটি শাস্ত্রসম্মত নয়। শাস্ত্রমতে কন্যার বর্ণ বরের চেয়ে উচ্চ হলে দাম্পত্য জীবনে অসম্মান, অশান্তি ও মনোমালিন্যের সম্ভাবনা থাকে। তবে এটি কোনো অভিশাপ নয়—ইতিহাস সাক্ষী, বহু সফল দাম্পত্য এই বর্ণ-ব্যবধান অতিক্রম করেছে। যদি প্রেম সত্য হয়, যদি হৃদয়ের বন্ধন অটুট থাকে, তবে বর্ণের এই ব্যবধান নদীর বুকে পাথরের মতো ডুবে যাবে—দেখা যাবে না, শুধু অনুভব করা যাবে।`;\n\n        return { points, max: 1, girlVarna: gv, boyVarna: bv, full };\n    }\n\n    /**\n     * ২. বশ্যকূট (সর্বোচ্চ ২ গুণ)\n     */\n    calcVashya(girlRashi, boyRashi) {\n        const vashyaMap = {\n            \"মেষ\":[\"সিংহ\",\"বৃষ\"], \"বৃষ\":[\"মেষ\",\"কর্কট\"], \"মিথুন\":[\"তুলা\",\"কুম্ভ\",\"কন্যা\"],\n            \"কর্কট\":[\"মকর\",\"মীন\",\"বৃষ\"], \"সিংহ\":[\"মেষ\",\"ধনু\",\"মীন\"],\n            \"কন্যা\":[\"মিথুন\",\"তুলা\",\"কুম্ভ\"], \"তুলা\":[\"কন্যা\",\"কুম্ভ\",\"মিথুন\"],\n            \"বৃশ্চিক\":[\"মেষ\",\"সিংহ\",\"ধনু\"], \"ধনু\":[\"মেষ\",\"সিংহ\"],\n            \"মকর\":[\"কর্কট\",\"মীন\"], \"কুম্ভ\":[\"তুলা\",\"মিথুন\",\"কন্যা\"], \"মীন\":[\"কর্কট\",\"বৃশ্চিক\"]\n        };\n\n        const girlVashya = (vashyaMap[boyRashi]&&vashyaMap[boyRashi].includes(girlRashi)) || false;\n        const boyVashya = (vashyaMap[girlRashi]&&vashyaMap[girlRashi].includes(boyRashi)) || false;\n\n        let points = 0;\n        if (girlVashya && boyVashya) points = 2;\n        else if (girlVashya) points = 1;\n        else if (boyVashya) points = 0.5;\n\n        const full = points === 2\n            ? `পরস্পর সৌখ্য বশ্য—বিরল ও মহাশুভ যোগ। কন্যার রাশি বরের বশ্য এবং বরের রাশিও কন্যার বশ্য। এটি পরম প্রেমের প্রতীক—যেখানে কেউ কাউকে দাসত্ব করে না, বরং দুজনেই একে অপরের প্রতি স্বতঃস্ফূর্তভাবে আকৃষ্ট হয়। যেমন চাঁদ ও জোছনা—একে ছাড়া অপরের অস্তিত্ব অর্থহীন, তেমনি এই দম্পতি পরস্পরের পরিপূরক। এই যোগে দাম্পত্য জীবন হবে স্বর্গীয় সুখে পরিপূর্ণ।`\n            : points === 1\n            ? `কন্যার রাশি বরের বশ্য—একতরফা বশ্যতা, যা শাস্ত্রসম্মত। কন্যা স্বাভাবিকভাবেই স্বামীর প্রতি অনুরক্ত থাকবেন, তাঁর ইচ্ছাকে নিজের ইচ্ছা করে নেবেন। যেমন নদী সাগরের দিকে বয়, যেমন ফুল সূর্যের দিকে ঘোরে—তেমনি কন্যার মন আপনিই স্বামীর দিকে ধাবিত হবে। তবে বরকেও সচেতন থাকতে হবে—বশ্যতার এই উপহারকে কখনো অবদমন বা অত্যাচারে পরিণত করা যাবে না।`\n            : points === 0.5\n            ? `বরের রাশি কন্যার বশ্য—বৈপরীত্যের প্রতীক। এতে স্বামী স্ত্রীর প্রতি কিছুটা নির্ভরশীল থাকবেন, যা দাম্পত্য জীবনে ভারসাম্যহীনতা আনতে পারে। যেমন সিংহ যদি হরিণের পেছনে ছোটে, তবে বনের রাজত্ব টলে যায়—তেমনি এই বশ্যতা সম্পর্কে সম্মানের হানি ঘটাতে পারে। তবে ভালোবাসা যদি গভীর হয়, তবে এটাও এক অনন্য সম্পর্ক হয়ে উঠতে পারে—যেখানে পুরুষ তাঁর নারীর কাছে আত্মসমর্পণ করে প্রকৃত শক্তি খুঁজে পান।`\n            : `বর ও কন্যার রাশি পরস্পর বৈর-ভক্ষ্য—কোনো বশ্যতা নেই। এটি অমিলের ইঙ্গিত—দাম্পত্য জীবনে কলহ, অশান্তি ও একগুঁয়েমির সম্ভাবনা থাকে। যেমন দুই ষাঁড় এক গোয়ালে বাঁধা থাকলে শান্তি থাকে না, তেমনি এই দম্পতির মধ্যে ক্ষমতার দ্বন্দ্ব লেগেই থাকবে। তবে চেষ্টা করলে সবই সম্ভব—পরস্পরকে বোঝার চেষ্টা করুন, শ্রদ্ধা দিন, দেখবেন বশ্যতার থেকেও বড় কিছু জন্ম নিয়েছে—বন্ধুত্ব।`;\n\n        return { points, max: 2, girlVashya, boyVashya, full };\n    }\n\n    /**\n     * ৩. তারাকূট (সর্বোচ্চ ৩ গুণ)\n     */\n    calcTara(girlNak, boyNak) {\n        const gi = this.getNakshatraIndex(girlNak);\n        const bi = this.getNakshatraIndex(boyNak);\n        if (gi === -1 || bi === -1) return { points: 0, max: 3, full: \"নক্ষত্রের তথ্য সঠিক নয়।\" };\n\n        const fromBoy = ((gi - bi + 27) % 27) + 1;\n        const fromGirl = ((bi - gi + 27) % 27) + 1;\n        const taraBoy = fromBoy % 9 === 0 ? 9 : fromBoy % 9;\n        const taraGirl = fromGirl % 9 === 0 ? 9 : fromGirl % 9;\n\n        const badTaras = [3, 5, 7];\n        const boyGood = !badTaras.includes(taraBoy);\n        const girlGood = !badTaras.includes(taraGirl);\n\n        let points = 0;\n        if (boyGood && girlGood) points = 3;\n        else if (boyGood || girlGood) points = 1.5;\n\n        const taraNames = [\"\",\"জন্ম\",\"সম্পদ\",\"বিপৎ\",\"ক্ষেম\",\"প্রত্যরি\",\"সাধক\",\"নিধন\",\"মিত্র\",\"অতিমিত্র\"];\n\n        const full = points === 3\n            ? `বরের নক্ষত্র থেকে কন্যার তারা ${taraNames[taraBoy]} (${taraBoy}) এবং কন্যার নক্ষত্র থেকে বরের তারা ${taraNames[taraGirl]} (${taraGirl})—উভয়ই শুভ তারা। পরস্পর তারাশুদ্ধি সম্পন্ন, যা অত্যন্ত মঙ্গলজনক। এই যোগ দাম্পত্য জীবনে সুস্বাস্থ্য, দীর্ঘায়ু, সৌভাগ্য ও পারস্পরিক সুখ বয়ে আনে। জন্ম তারা হলে কর্মে সাফল্য, সম্পদ তারা হলে ধনাগম, ক্ষেম তারা হলে নিরাপত্তা, মিত্র তারা হলে বন্ধুত্বপূর্ণ সম্পর্ক—সবই মিলেমিশে এক সুন্দর সংসার গড়ে তোলে।`\n            : points === 1.5\n            ? `একজনের তারা শুভ, অপরজনের তারা অশুভ—আংশিক তারাশুদ্ধি। এর ফলে দাম্পত্য জীবনে কিছু প্রতিবন্ধকতা আসতে পারে—স্বাস্থ্যগত সমস্যা, আর্থিক টানাপোড়েন, কিংবা মানসিক অশান্তি। তবে সম্পূর্ণ অন্ধকার নয়—যে প্রদীপ অর্ধেক জ্বলে, তাও পথ দেখায়। সচেতনতা, প্রতিকার ও পরস্পরের প্রতি যত্নবান হলে এই আংশিক অশুভতাকে সম্পূর্ণরূপে জয় করা সম্ভব।`\n            : `উভয়ের তারাই অশুভ—তারাদোষ বিদ্যমান। বিপৎ (৩), প্রত্যরি (৫) ও নিধন (৭) তারা—এই তিন মহাদোষ একত্রে মিলিত হয়েছে। এর ফলে দাম্পত্য জীবনে স্বাস্থ্যহানি, দুর্ঘটনা, আর্থিক সর্বনাশ বা অকালমৃত্যুর মতো গুরুতর বিপদের আশঙ্কা থাকে। এটি উপেক্ষা করা চরম ভুল হবে—বিবাহের পূর্বে অবশ্যই বিশেষ পূজা, দান ও প্রতিকার করতে হবে। মহামৃত্যুঞ্জয় মন্ত্র জপ, রুদ্রাভিষেক ও নবগ্রহ পূজা এই দোষ প্রশমনে সহায়ক।`;\n\n        return { points, max: 3, taraBoy: taraNames[taraBoy], taraGirl: taraNames[taraGirl], full };\n    }\n\n    /**\n     * ৪. যোনিকূট (সর্বোচ্চ ৪ গুণ)\n     */\n    calcYoni(girlNak, boyNak) {\n        const gy = this.nakshatraYoni[girlNak];\n        const by = this.nakshatraYoni[boyNak];\n        if (!gy || !by) return { points: 0, max: 4, full: \"যোনির তথ্য সঠিক নয়।\" };\n\n        let points = 0, relation = \"\";\n        if (gy === by) { points = 4; relation = \"একই যোনি—পরম মিত্র\"; }\n        else if (this.yoniEnmity[gy] === by) { points = 0; relation = \"শত্রু যোনি—মহাবৈর\"; }\n        else if (this.yoniEnmity[by] === gy) { points = 0; relation = \"শত্রু যোনি—মহাবৈর\"; }\n        else { points = 1.5; relation = \"নিরপেক্ষ যোনি—মধ্যম\"; }\n\n        const full = points === 4\n            ? `উভয়ের যোনি ${gy}—একই যোনির মিলন, যা পরম মিত্র যোগ। এই যোগ দাম্পত্য জীবনে গভীর শারীরিক ও মানসিক সামঞ্জস্য বয়ে আনে। যেমন একই প্রজাতির দুই পাখি একই সুরে গান গায়, একই খাদ্য খুঁজে খায়, একই নীড়ে বাস করে—তেমনি সমযোনির দম্পতি সহজেই একে অপরের মন বুঝতে পারে, একে অপরের চাহিদা পূরণ করতে পারে। এদের সম্পর্ক হবে স্বাভাবিক, স্বতঃস্ফূর্ত ও গভীর।`\n            : points === 1.5\n            ? `কন্যার যোনি ${gy} এবং বরের যোনি ${by}—নিরপেক্ষ যোনি, মধ্যম মিলন। যেমন বনের বাঘ ও হরিণের মধ্যে স্বাভাবিক শত্রুতা নেই, আবার গভীর বন্ধুত্বও নেই—তেমনি এই দম্পতির সম্পর্ক মধ্যম মানের হবে। কখনও সুখ, কখনও অশান্তি আসবে। তবে নিরপেক্ষতা মানেই অসম্ভব নয়—প্রচুর ভালোবাসা, যত্ন ও শ্রদ্ধা দিয়ে এই সম্পর্ককে অসাধারণ করে তোলা সম্ভব।`\n            : `কন্যার যোনি ${gy} এবং বরের যোনি ${by}—পরস্পর শত্রু যোনি, মহাবৈর যোগ। এটি অত্যন্ত অশুভ লক্ষণ—যেমন সাপ ও নকুলের মধ্যে স্বাভাবিক শত্রুতা, যেমন বিড়াল ও ইঁদুরের মধ্যে চিরন্তন বৈরিতা, তেমনি এই দম্পতির মধ্যে গভীর অমিল থাকবে। দাম্পত্য জীবনে তীব্র অশান্তি, শারীরিক সমস্যা, এমনকি বিচ্ছেদের সম্ভাবনাও প্রবল। তবে শাস্ত্রে একটি ব্যতিক্রমের কথা বলা হয়েছে—যদি কন্যার রাশি বরের বশ্য হয়, তবে যোনি-বৈরিতার দোষ প্রশমিত হয়। বিশেষ পূজা ও প্রতিকার আবশ্যক।`;\n\n        return { points, max: 4, girlYoni: gy, boyYoni: by, relation, full };\n    }\n\n    /**\n     * ৫. গ্রহমৈত্রীকূট (সর্বোচ্চ ৫ গুণ)\n     */\n    calcGrahaMaitri(girlRashi, boyRashi) {\n        const gl = this.rashiLords[girlRashi];\n        const bl = this.rashiLords[boyRashi];\n        if (!gl || !bl) return { points: 0, max: 5, full: \"রাশিপতির তথ্য সঠিক নয়।\" };\n\n        let points = 0, relation = \"\";\n        if (gl === bl) { points = 5; relation = \"একই রাশিপতি—পরম মিত্র\"; }\n        else if (this.planetRelations[bl]&&this.planetRelations[bl].f&&this.planetRelations[bl].f.includes(gl)) { points = 4; relation = \"বরের রাশিপতি কন্যার রাশিপতির মিত্র\"; }\n        else if (this.planetRelations[gl]&&this.planetRelations[gl].f&&this.planetRelations[gl].f.includes(bl)) { points = 3; relation = \"কন্যার রাশিপতি বরের রাশিপতির মিত্র\"; }\n        else if (this.planetRelations[bl]&&this.planetRelations[bl].e&&this.planetRelations[bl].e.includes(gl)) { points = 0; relation = \"পরস্পর শত্রু\"; }\n        else { points = 2; relation = \"নিরপেক্ষ\"; }\n\n        const full = points === 5\n            ? `কন্যা ও বরের রাশিপতি একই—${gl}। এটি অত্যন্ত শুভ যোগ। একই গ্রহের অধীনে থাকায় উভয়ের চিন্তাভাবনা, জীবনদর্শন, মূল্যবোধ ও মানসিকতা প্রায় একই রকম হবে। যেমন একই সূর্যের আলোয় দুইটি ফুল ফোটে—একটু ভিন্ন মাটিতে, কিন্তু একই আলোর উত্তরাধিকারী। এই দম্পতি সহজেই একে অপরকে বুঝবে, অকারণ কলহ হবে না, সংসার হবে শান্তিপূর্ণ ও সমৃদ্ধ।`\n            : points === 4\n            ? `কন্যার রাশিপতি ${gl} এবং বরের রাশিপতি ${bl}—বরের রাশিপতি কন্যার রাশিপতির মিত্র। এটি শুভ যোগ। যেমন দুই বন্ধু মিলে এক কাজ সহজে করতে পারে, তেমনি এই দুই গ্রহের মিত্রতা দাম্পত্য জীবনে সহযোগিতা ও পারস্পরিক বোঝাপড়া আনবে। বর হবেন কন্যার সবচেয়ে বড় সহায়ক, জীবনসঙ্গী হয়ে উঠবেন জীবনের সবচেয়ে বিশ্বস্ত বন্ধু।`\n            : points === 3\n            ? `কন্যার রাশিপতি ${gl} এবং বরের রাশিপতি ${bl}—কন্যার রাশিপতি বরের রাশিপতির মিত্র। এটি মধ্যম মিত্রতার যোগ। কন্যা হবেন বরের জীবনে সহায়ক শক্তি—যেমন লক্ষ্মী নারায়ণের সহচরী, তেমনি কন্যা বরের উন্নতির পথ প্রশস্ত করবেন। তবে বরকেও নিজের দায়িত্ব বুঝতে হবে—একতরফা সম্পর্ক কখনো টেকে না।`\n            : points === 2\n            ? `কন্যার রাশিপতি ${gl} এবং বরের রাশিপতি ${bl}—নিরপেক্ষ সম্পর্ক। এটি খুব খারাপ নয়, আবার খুব ভালোও নয়। যেমন অপরিচিত দুই পথিক একই পথে হাঁটে কিন্তু কথা বলে না—তেমনি এই দম্পতির মধ্যে প্রথম দিকে তেমন গভীর টান না থাকলেও, সময়ের সাথে সাথে সম্পর্কের গভীরতা বাড়তে পারে। চেষ্টা ও আন্তরিকতা রাখতে হবে।`\n            : `কন্যার রাশিপতি ${gl} এবং বরের রাশিপতি ${bl}—পরস্পর শত্রু। এটি অশুভ যোগ। যেমন সিংহ ও হাতির মধ্যে স্বাভাবিক প্রতিদ্বন্দ্বিতা, তেমনি এই দুই গ্রহের শত্রুতা দাম্পত্য জীবনে অহংকারের সংঘাত, অশান্তি ও বিচ্ছেদ আনতে পারে। তবে রাজযোটক বা অন্যান্য শুভ যোগ থাকলে এই দোষ প্রশমিত হতে পারে। বিশেষ পূজা করে উভয় গ্রহকে শান্ত করা আবশ্যক।`;\n\n        return { points, max: 5, girlLord: gl, boyLord: bl, relation, full };\n    }\n\n    /**\n     * ৬. গণমৈত্রীকূট (সর্বোচ্চ ৬ গুণ)\n     */\n    calcGana(girlNak, boyNak) {\n        const gg = this.nakshatraGana[girlNak];\n        const bg = this.nakshatraGana[boyNak];\n        if (!gg || !bg) return { points: 0, max: 6, full: \"গণের তথ্য সঠিক নয়।\" };\n\n        let points = 0, relation = \"\";\n        if (gg === bg) { points = 6; relation = \"একই গণ—সর্বোত্তম\"; }\n        else if (gg === \"দেব\" && bg === \"নর\") { points = 5; relation = \"দেব-নর—উত্তম\"; }\n        else if (gg === \"নর\" && bg === \"দেব\") { points = 3; relation = \"নর-দেব—মধ্যম\"; }\n        else if (gg === \"দেব\" && bg === \"রাক্ষস\") { points = 1; relation = \"দেব-রাক্ষস—অশুভ\"; }\n        else if (gg === \"রাক্ষস\" && bg === \"দেব\") { points = 0; relation = \"রাক্ষস-দেব—মহাদোষ\"; }\n        else if (gg === \"নর\" && bg === \"রাক্ষস\") { points = 3; relation = \"নর-রাক্ষস—মধ্যম\"; }\n        else if (gg === \"রাক্ষস\" && bg === \"নর\") { points = 1; relation = \"রাক্ষস-নর—অশুভ\"; }\n\n        const full = points === 6\n            ? `উভয়ের গণ ${gg}—একই গণ, সর্বোত্তম মিলন। যেমন দেব-দেব মিলনে স্বর্গীয় পবিত্রতা, নর-নর মিলনে মানবিক বোঝাপড়া, তেমনি সমগণের দম্পতি একই প্রকৃতির হওয়ায় সহজেই একে অপরের সাথে খাপ খাইয়ে নিতে পারে। অকারণ কলহ হবে না, মতবিরোধ হবে ক্ষণস্থায়ী, এবং সংসারে শান্তি বজায় থাকবে।`\n            : points === 5\n            ? `কন্যা দেবগণ এবং বর নরগণ—দেব-নর মিলন, অত্যন্ত শুভ। কন্যার পবিত্রতা ও দেবত্ব বরের মানবিক জীবনকে আলোকিত করবে, আর বরের বাস্তববুদ্ধি ও কর্মঠতা কন্যাকে নিরাপত্তা দেবে। যেমন গঙ্গার পবিত্র জল সাগরের নোনা জলের সাথে মিশেও নিজের পবিত্রতা রাখে, তেমনি এই কন্যা সংসারে থেকেও নিজের দেবীত্ব বজায় রাখবেন।`\n            : points === 3\n            ? `কন্যা নরগণ এবং বর দেবগণ—নর-দেব মিলন, মধ্যম। অথবা নর-রাক্ষস মিলন। এই যোগে সম্পর্ক মধ্যম মানের হবে—চরম সুখ আসবে না, আবার চরম দুঃখও আসবে না। যেমন শরৎকালের আকাশ—কখনও রোদ, কখনও মেঘ, তেমনি এই দাম্পত্য জীবনও কখনও হাসি, কখনও কান্নায় ভরা থাকবে। পরস্পরের প্রতি শ্রদ্ধাই হবে এই সম্পর্কের ভিত্তি।`\n            : points === 1\n            ? `গণ-বৈরিতা বিদ্যমান। দেব ও রাক্ষস, অথবা রাক্ষস ও নরের এই মিলনে স্বাভাবিক অমিল থাকবে—দাম্পত্য জীবনে অশান্তি, কলহ ও মানসিক দূরত্বের সম্ভাবনা প্রবল। বিশেষ পূজা-অর্চনা করে গণদোষ প্রশমিত করা আবশ্যক। শিব-পার্বতী পূজা ও রুদ্রাভিষেক এই দোষ কাটাতে সহায়ক।`\n            : `গণ-মহাবৈরিতা—রাক্ষস ও দেবগণের মিলন। এটি অত্যন্ত অশুভ যোগ। রাক্ষস প্রকৃতির মানুষ দেবপ্রকৃতির মানুষকে সহজে সহ্য করতে পারে না—ফলে সংসারে চরম অশান্তি, এমনকি মৃত্যুও ঘটতে পারে। শাস্ত্রমতে এই গণ মিলনে বিবাহ করা উচিত নয়। যদি একান্তই করতে হয়, তবে অবশ্যই বিশেষ প্রতিকার ও পূজা করতে হবে।`;\n\n        return { points, max: 6, girlGana: gg, boyGana: bg, relation, full };\n    }\n\n    /**\n     * ৭. রাশিকূট / ভকূট (সর্বোচ্চ ৭ গুণ)\n     * রাজযোটক, দ্বিদ্বাদশ, নবপঞ্চম, ষড়ষ্টক\n     */\n    calcRashi(girlRashi, boyRashi) {\n        const gi = this.getRashiIndex(girlRashi);\n        const bi = this.getRashiIndex(boyRashi);\n        if (gi === -1 || bi === -1) return { points: 0, max: 7, full: \"রাশির তথ্য সঠিক নয়।\" };\n\n        const dist = ((bi - gi + 12) % 12) + 1;\n        let points = 0, type = \"\";\n\n        if (dist === 1 || dist === 7) { points = 7; type = \"রাজযোটক (এক-সপ্তম)\"; }\n        else if (dist === 4 || dist === 10) { points = 7; type = \"রাজযোটক (চতুর্থ-দশম)\"; }\n        else if (dist === 3 || dist === 11) { points = 7; type = \"রাজযোটক (তৃতীয়-একাদশ)\"; }\n        else if (dist === 2 || dist === 12) { points = 0; type = \"দ্বিদ্বাদশ দোষ\"; }\n        else if (dist === 5) { points = 0; type = \"পঞ্চম দোষ\"; }\n        else if (dist === 9) { points = 7; type = \"নবম (শুভ)\"; }\n        else if (dist === 6 || dist === 8) { points = 0; type = \"ষড়ষ্টক দোষ\"; }\n\n        const full = points === 7\n            ? `বর ও কন্যার রাশি ${type} অবস্থানে রয়েছে—এটি রাজযোটক যোগ! ভৃগু, অত্রি, গর্গ প্রভৃতি মহর্ষিগণ বলে গেছেন: \"রাজযোটকং যদা দৃষ্ট্বা গ্রহবৈরিতাদিদোষ ন বিদ্যতে\"—অর্থাৎ রাজযোটক বিদ্যমান থাকলে গ্রহ-বৈরিতা, তারাদোষ, গণদোষ, বর্ণদোষ, এমনকি নাড়ীদোষ পর্যন্ত প্রশমিত হয়ে যায়। এই যোগ দাম্পত্য জীবনে রাজকীয় সুখ, বিপুল ঐশ্বর্য, দীর্ঘায়ু, পুত্রবতী ও পতিপ্রিয়া হওয়ার শুভ লক্ষণ বহন করে। যেমন রাজা ও রাণী একাসনে বসে রাজত্ব করেন, তেমনি এই দম্পতি সংসারে সুখ-সমৃদ্ধির সম্রাট ও সম্রাজ্ঞী হয়ে বাস করবেন। এ মিলন স্বর্গীয় আশীর্বাদপুষ্ট।`\n            : `বর ও কন্যার রাশি ${type} অবস্থানে রয়েছে—এটি অশুভ মিলন। দাম্পত্য জীবনে আর্থিক ক্ষতি, অশান্তি, স্বাস্থ্যহানি বা বিচ্ছেদের সম্ভাবনা থাকে। তবে যদি রাশিপতি পরস্পর মিত্র হন বা রাজযোটকের মতোই অন্য কোনো মহাশুভ যোগ বিদ্যমান থাকে, তবে এই দোষ প্রশমিত হতে পারে। বিশেষ লক্ষ্মী-নারায়ণ পূজা, পীতবস্ত্র দান, বৃহস্পতিবার উপবাস ও রুদ্রাভিষেক করলে এই দোষের প্রভাব অনেকখানি কাটানো যায়।`;\n\n        return { points, max: 7, distance: dist, type, full };\n    }\n\n    /**\n     * ৮. ত্রিনাড়ীকূট (সর্বোচ্চ ৮ গুণ)\n     */\n    calcNadi(girlNak, boyNak) {\n        const gn = this.nakshatraNadi[girlNak];\n        const bn = this.nakshatraNadi[boyNak];\n        if (!gn || !bn) return { points: 0, max: 8, full: \"নাড়ীর তথ্য সঠিক নয়।\" };\n\n        let points = 8, type = \"\";\n        if (gn === bn) {\n            points = 0;\n            if (gn === \"আদ্য\") type = \"প্রাণনাড়ী বেধ—স্বামীর অকালমৃত্যুর আশঙ্কা\";\n            else if (gn === \"মধ্য\") type = \"মধ্যনাড়ী বেধ—উভয়ের অকালমৃত্যুর আশঙ্কা\";\n            else type = \"পৃষ্ঠনাড়ী বেধ—কন্যার অকালমৃত্যুর আশঙ্কা\";\n        }\n\n        const full = points === 8\n            ? `কন্যার নাড়ী ${gn} এবং বরের নাড়ী ${bn}—ভিন্ন নাড়ী, শুভ মিলন। নাড়ীবেধ না থাকায় দাম্পত্য জীবনে সুস্বাস্থ্য, দীর্ঘায়ু ও সন্তানসুখ বজায় থাকবে। সন্তান জন্মে কোনো বাধা থাকবে না—পরিবার পরিপূর্ণতা লাভ করবে। যেমন তিনটি পৃথক নদী এসে এক সাগরে মিলিত হয় কিন্তু নিজেদের পৃথক অস্তিত্ব রাখে, তেমনি এই দম্পতি এক হয়েও নিজেদের স্বকীয়তা বজায় রাখবে—এটাই সুখী দাম্পত্যের চাবিকাঠি।`\n            : `কন্যা ও বর উভয়ের নাড়ী ${gn}—একই নাড়ী, ${type}। এটি অত্যন্ত গুরুতর দোষ। প্রাচীন শাস্ত্রে বলা হয়েছে: \"নাড়ীবেধে ভবেৎ ক্লেশো দম্পত্যোঃ সর্বদা ভবেৎ\"—নাড়ীবেধ থাকলে দম্পতির জীবনে চিরকাল ক্লেশ লেগেই থাকে। প্রাণনাড়ীগত হলে স্বামীর, পৃষ্ঠনাড়ীগত হলে কন্যার এবং মধ্যনাড়ীগত হলে উভয়েরই অকালমৃত্যুর আশঙ্কা থাকে। এই দোষকে কখনোই উপেক্ষা করা যাবে না। বিবাহের পূর্বে অবশ্যই কুম্ভবিবাহ, অশ্বত্থবৃক্ষ বা স্বর্ণনির্মিত বিষ্ণুপ্রতিমার সহিত বিবাহ দিয়ে তারপর প্রকৃত বিবাহ করতে হবে। মহামৃত্যুঞ্জয় জপ, স্বর্ণদান ও বিষ্ণুপূজা করা আবশ্যক।`;\n\n        return { points, max: 8, girlNadi: gn, boyNadi: bn, full };\n    }\n\n    /**\n     * মাঙ্গলিক দোষ\n     */\n    calcManglik(marsSign, lagnaSign, gender) {\n        const mi = this.getRashiIndex(marsSign);\n        const li = this.getRashiIndex(lagnaSign);\n        if (mi === -1 || li === -1) return { hasDosha: false, house: -1, full: \"গ্রহের তথ্য সঠিক নয়।\" };\n\n        const house = ((mi - li + 12) % 12) + 1;\n        const hasDosha = this.manglikHouses.includes(house);\n\n        const full = hasDosha\n            ? `${gender === 'girl' ? 'কন্যার' : 'বরের'} লগ্ন থেকে মঙ্গল ${house}ম ভাবে অবস্থিত—মাঙ্গলিক দোষ বিদ্যমান। শাস্ত্রমতে: \"লগ্নে ব্যয়েচ পাতালে যামিত্রেচাষ্টমে কুজে। কন্যা হরতি ভর্তারাং ভর্তা ভার্যাং বিনশ্যতি।\"—অর্থাৎ লগ্ন, দ্বাদশ, চতুর্থ, সপ্তম বা অষ্টমে মঙ্গল থাকলে স্ত্রীর স্বামীনাশ ও স্বামীর স্ত্রীনাশ হয়। তবে উভয়ের মাঙ্গলিক দোষ সমান হলে পরস্পর বাতিল হয়ে যায়। প্রতিকার: কুম্ভবিবাহ, অশ্বত্থবৃক্ষ বা স্বর্ণনির্মিত বিষ্ণুপ্রতিমার সহিত বিবাহ। বরুণমন্ত্র: \"বরুণাঙ্গস্বরূপত্তং জীবনানাং সমাশ্রয়, পতিং জীবয় কন্যায়াঃ চিরপুত্রসুখং কুরু। দেহি বিষো বরং দেব কন্যাংপালয় দুঃখতঃ।\" পাঠ করে কন্যাকে অভিষিক্ত করিবে।`\n            : `${gender === 'girl' ? 'কন্যার' : 'বরের'} লগ্ন থেকে মঙ্গল ${house}ম ভাবে—মাঙ্গলিক দোষ নেই। এটি শুভ লক্ষণ, দাম্পত্য জীবনে এই দোষের কারণে কোনো অশুভ ঘটবে না। নিশ্চিন্তে বিবাহ করা যাবে।`;\n\n        return { hasDosha, house, full };\n    }\n\n    /**\n     * দোষ প্রশমনের প্রতিকার\n     */\n    getRemedies(nadiPoints, rashiPoints, ganaPoints, manglikMatch) {\n        const remedies = [];\n        if (nadiPoints === 0) {\n            remedies.push(\"🕉️ নাড়ীবেধ দোষ প্রশমনে: (ক) কুম্ভবিবাহ—বিবাহের পূর্বে কুম্ভ, অশ্বত্থবৃক্ষ বা স্বর্ণনির্মিত বিষ্ণুপ্রতিমার সহিত বিবাহ দিবে। (খ) মহামৃত্যুঞ্জয় মন্ত্রজপ—'ওঁ ত্র্যম্বকং যজামহে...' নিত্য ১০৮ বার জপ করিবে। (গ) স্বর্ণদান, তিলদান ও বিষ্ণুপূজা করিবে।\");\n        }\n        if (rashiPoints === 0) {\n            remedies.push(\"🕉️ ভকূট/রাশিদোষ প্রশমনে: (ক) লক্ষ্মী-নারায়ণ পূজা ও পীতবস্ত্র দান। (খ) বৃহস্পতিবার উপবাস ও কনকধারা স্তোত্র পাঠ। (গ) মাণিক্য রত্ন ধারণ করিতে পারেন।\");\n        }\n        if (ganaPoints <= 1) {\n            remedies.push(\"🕉️ গণদোষ প্রশমনে: (ক) শিব-পার্বতী পূজা ও রুদ্রাভিষেক। (খ) সোমবার উপবাস ও বেলপাতা নিবেদন। (গ) রুদ্রাক্ষ ধারণ ও 'ওঁ নমঃ শিবায়' জপ।\");\n        }\n        if (!manglikMatch) {\n            remedies.push(\"🕉️ মাঙ্গলিক অমিল প্রশমনে: (ক) কুম্ভবিবাহ ও হনুমান চালিশা পাঠ। (খ) মঙ্গলবার উপবাস ও মসুর ডাল দান। (গ) প্রবাল রত্ন ধারণ ও 'ওঁ অং অঙ্গারকায় নমঃ' জপ।\");\n        }\n        if (remedies.length === 0) {\n            remedies.push(\"✨ এই মিলনে কোনো বিশেষ দোষ নেই—তবুও সুখী দাম্পত্য জীবনের জন্য নিত্য লক্ষ্মী-নারায়ণ পূজা, পিতৃতর্পণ ও অতিথি সেবা করুন। প্রেম, শ্রদ্ধা ও বিশ্বাসই শ্রেষ্ঠ প্রতিকার।\");\n        }\n        return remedies;\n    }\n\n    /**\n     * পূর্ণাঙ্গ যোটক-বিচার\n     */\n    match(girlData, boyData) {\n        const gr = girlData.moonRashi, br = boyData.moonRashi;\n        const gn = girlData.moonNakshatra, bn = boyData.moonNakshatra;\n        const gMars = girlData.marsRashi || girlData.moonRashi;\n        const bMars = boyData.marsRashi || boyData.moonRashi;\n        const gLagna = girlData.lagnaRashi || girlData.moonRashi;\n        const bLagna = boyData.lagnaRashi || boyData.moonRashi;\n\n        const kootas = {\n            varna: this.calcVarna(gr, br),\n            vashya: this.calcVashya(gr, br),\n            tara: this.calcTara(gn, bn),\n            yoni: this.calcYoni(gn, bn),\n            grahaMaitri: this.calcGrahaMaitri(gr, br),\n            gana: this.calcGana(gn, bn),\n            rashi: this.calcRashi(gr, br),\n            nadi: this.calcNadi(gn, bn)\n        };\n\n        const manglik = {\n            girl: this.calcManglik(gMars, gLagna, 'girl'),\n            boy: this.calcManglik(bMars, bLagna, 'boy'),\n            match: this.calcManglik(gMars, gLagna, 'girl').hasDosha === this.calcManglik(bMars, bLagna, 'boy').hasDosha\n        };\n\n        const isRajaYotak = kootas.rashi.points === 7;\n        let total = 0;\n        for (const k of Object.keys(kootas)) total += kootas[k].points;\n\n        const remedies = this.getRemedies(kootas.nadi.points, kootas.rashi.points, kootas.gana.points, manglik.match);\n\n        let verdict = \"\", verdictFull = \"\";\n        if (isRajaYotak && total >= 18) {\n            verdict = \"শ্রেষ্ঠতম (রাজযোটক)\";\n            verdictFull = `👑 রাজযোটক যোগ বিদ্যমান—এটি বিবাহের জন্য পরমোত্তম মিলন। ভৃগু-অত্রি-গর্গাদি ঋষিগণ বলেছেন: \"রাজযোটকং যদা দৃষ্ট্বা গ্রহবৈরিতাদিদোষ বিনশ্যতি\"—রাজযোটক থাকলে অন্যান্য সমস্ত দোষ (বর্ণ, গণ, নাড়ী, তারা, ভকূট) সম্পূর্ণরূপে প্রশমিত হয়ে যায়। এই মিলন দাম্পত্য জীবনে রাজকীয় সুখ, বিপুল ঐশ্বর্য, দীর্ঘায়ু, পুত্রবতী ও পতিপ্রিয়া হওয়ার শুভ লক্ষণ বহন করে। নিঃসন্দেহে এই বিবাহ সম্পন্ন করা যায়—এ মিলন স্বর্গীয় আশীর্বাদপুষ্ট। ${total} গুণের সাথে রাজযোটক যুক্ত হয়ে এর মহিমা বহুগুণে বৃদ্ধি পেয়েছে।`;\n        } else if (total >= 30) {\n            verdict = \"শ্রেষ্ঠতম\";\n            verdictFull = `মোট ${total} গুণ (৩৬-এর মধ্যে)—এটি শ্রেষ্ঠতম মিলন। বিবাহ অত্যন্ত শুভ হবে, দাম্পত্য জীবনে সুখ, শান্তি, প্রেম, সন্তানসুখ ও আর্থিক সমৃদ্ধি বিরাজ করবে। বর-কন্যা পরস্পরের পরিপূরক—একসাথে জীবনের সকল উত্থান-পতন হাসিমুখে অতিক্রম করবেন। এত উচ্চ গুণের মিলন সহজে মেলে না—একে ঈশ্বরের আশীর্বাদ জেনে গ্রহণ করুন।`;\n        } else if (total >= 25) {\n            verdict = \"উত্তম\";\n            verdictFull = `মোট ${total} গুণ (৩৬-এর মধ্যে)—উত্তম মিলন। বিবাহ শুভ হবে, দাম্পত্য জীবনে অধিকাংশ সময় সুখ ও শান্তি বজায় থাকবে। ছোটখাটো অমিল থাকলেও ভালোবাসা, শ্রদ্ধা ও পারস্পরিক বোঝাপড়ার মাধ্যমে সহজেই তা কাটিয়ে ওঠা সম্ভব। প্রতিকারগুলি করলে জীবন আরও মসৃণ হবে—সুখের সাগরে ছোট্ট একটি ঢেউ মাত্র।`;\n        } else if (total >= 18) {\n            verdict = \"মধ্যম\";\n            verdictFull = `মোট ${total} গুণ (৩৬-এর মধ্যে)—মধ্যম মিলন। বিবাহ করা যেতে পারে, তবে দাম্পত্য জীবনে কিছু চ্যালেঞ্জ আসবে। সচেতনতা, পরস্পরের প্রতি শ্রদ্ধা ও উপরের প্রতিকারগুলি গুরুত্ব সহকারে করলে সুখী হওয়া সম্ভব। প্রেম যদি গভীর হয়, তবে মধ্যম গুণও অসাধারণ ফল দিতে পারে—যেমন নিম্নভূমির ফুলও সূর্যের আলোয় ফোটে। তবে বড় সিদ্ধান্ত নেওয়ার আগে অভিজ্ঞ জ্যোতিষীর পরামর্শ নেওয়া শ্রেয়।`;\n        } else {\n            verdict = \"অশুভ\";\n            verdictFull = `মোট ${total} গুণ (৩৬-এর মধ্যে)—অশুভ মিলন। এত কম গুণে বিবাহ করা অত্যন্ত ঝুঁকিপূর্ণ—দাম্পত্য জীবনে তীব্র অশান্তি, স্বাস্থ্যহানি, আর্থিক সর্বনাশ ও বিচ্ছেদের সম্ভাবনা প্রবল। প্রেম যদি সত্যিই গভীর হয়, তবেই কেবল অভিজ্ঞ গুরুর পরামর্শক্রমে বিশেষ প্রতিকার করে তবেই বিবাহ করার কথা ভাববেন। মনে রাখবেন—বিবাহ শুধু দুটি মানুষের মিলন নয়, দুটি পরিবারের, দুটি বংশের মিলন। শুভ চিন্তা করেই সিদ্ধান্ত নিন।`;\n        }\n\n        return { kootas, total, max: 36, verdict, verdictFull, manglik, isRajaYotak, remedies };\n    }\n\n    /**\n     * ফরম্যাট আউটপুট\n     */\n    format(girlName, boyName, result) {\n        const g = girlName || \"কন্যা\", b = boyName || \"বর\";\n        const SEP = \"\\n\" + \"- \".repeat(20) + \"\\n\";\n        let out = \"\\n💑 যোটক-বিচার (অষ্টকূট মিলন)\" + SEP;\n        out += `📊 মোট গুণ: ${result.total} / ${result.max}\\n📋 ফলাফল: ${result.verdict}\\n\\n${result.verdictFull}\\n\\n`;\n\n        out += \"📝 অষ্টকূট বিবরণ:\" + SEP;\n        const kootaDefs = [\n            { name: \"বর্ণকূট\", key: \"varna\", max: 1 },\n            { name: \"বশ্যকূট\", key: \"vashya\", max: 2 },\n            { name: \"তারাকূট\", key: \"tara\", max: 3 },\n            { name: \"যোনিকূট\", key: \"yoni\", max: 4 },\n            { name: \"গ্রহমৈত্রীকূট\", key: \"grahaMaitri\", max: 5 },\n            { name: \"গণমৈত্রীকূট\", key: \"gana\", max: 6 },\n            { name: \"রাশিকূট (ভকূট)\", key: \"rashi\", max: 7 },\n            { name: \"ত্রিনাড়ীকূট\", key: \"nadi\", max: 8 }\n        ];\n\n        for (const k of kootaDefs) {\n            const _ko2=result.kootas[k.key]||{};\n            const pts = (_ko2.points!=null?_ko2.points:0) || 0;\n            const icon = pts === k.max ? \"✨\" : pts === 0 ? \"⚠️\" : \"🔸\";\n            out += `${icon} ${k.name}: ${pts}/${k.max} গুণ\\n`;\n        }\n\n        out += \"\\n📖 বিস্তারিত ফলাফল:\" + SEP;\n        for (const k of kootaDefs) {\n            const _ko3=result.kootas[k.key]||{};\n            out += `\\n🕉️ ${k.name}:\\n${_ko3.full || \"তথ্য নেই\"}\\n`;\n        }\n\n        out += \"\\n🔴 মাঙ্গলিক দোষ:\" + SEP;\n        out += `${result.manglik.girl.full}\\n\\n${result.manglik.boy.full}\\n\\n`;\n        if (result.manglik.match) out += `✅ উভয়ের মাঙ্গলিক অবস্থা সমান — দোষ পরস্পর বাতিল।\\n\\n`;\n        else out += `⚠️ উভয়ের মাঙ্গলিক অবস্থা অসমান — প্রতিকার আবশ্যক।\\n\\n`;\n\n        out += \"🙏 প্রতিকার:\" + SEP;\n        result.remedies.forEach(r => out += r + \"\\n\");\n\n        out += SEP + \"🕉️ ওঁ নমঃ শিবায়। যেখানে প্রেম সত্য, সেখানেই ভগবান।\\nশুভম ভবতু। মাঙ্গল্যম ভবতু।\\n\";\n        return out;\n    }\n}\n\n// ==================== ৯. বিস্তারিত গ্রহ-ভিত্তিক narrative বিশ্লেষণ ====================\n// লক্ষ্য: প্রকৃত গণনাকৃত গ্রহের রাশি/ভাব (getPlanetData থেকে) ব্যবহার করে\n// বিভাগ-ভিত্তিক ব্যক্তিগতকৃত বিশ্লেষণ তৈরি করা — কোনো নতুন/দ্বিতীয় স্কোর তৈরি করা হয় না,\n// অষ্টকূট ফলাফলই (YotakBicharEngine.match) একমাত্র স্কোরের উৎস থাকে।\n\nconst _NR_RASHI_ORDER = [\"মেষ\",\"বৃষ\",\"মিথুন\",\"কর্কট\",\"সিংহ\",\"কন্যা\",\"তুলা\",\"বৃশ্চিক\",\"ধনু\",\"মকর\",\"কুম্ভ\",\"মীন\"];\nconst _NR_OWN_SIGNS = { \"সূর্য\":[\"সিংহ\"], \"চন্দ্র\":[\"কর্কট\"], \"মঙ্গল\":[\"মেষ\",\"বৃশ্চিক\"], \"বুধ\":[\"মিথুন\",\"কন্যা\"], \"বৃহস্পতি\":[\"ধনু\",\"মীন\"], \"শুক্র\":[\"বৃষ\",\"তুলা\"], \"শনি\":[\"মকর\",\"কুম্ভ\"] };\nconst _NR_EXALTED = { \"সূর্য\":\"মেষ\", \"চন্দ্র\":\"বৃষ\", \"মঙ্গল\":\"মকর\", \"বুধ\":\"কন্যা\", \"বৃহস্পতি\":\"কর্কট\", \"শুক্র\":\"মীন\", \"শনি\":\"তুলা\" };\nconst _nrEngine = new YotakBicharEngine();\n\nfunction _nrLon(data, name) {\n    const p = (data.planets || []).find(pl => pl.name === name);\n    return p ? p.lon : null;\n}\nfunction _nrSignIdx(lon) { return Math.floor((((lon % 360) + 360) % 360) / 30); }\nfunction _nrHouse(data, name) {\n    const lon = _nrLon(data, name);\n    if (lon == null || data.lagnaIdx == null) return null;\n    return ((_nrSignIdx(lon) - data.lagnaIdx + 12) % 12) + 1;\n}\nfunction _nrSign(data, name) {\n    const lon = _nrLon(data, name);\n    return lon == null ? null : _NR_RASHI_ORDER[_nrSignIdx(lon)];\n}\nfunction _nrIsStrong(data, planet) {\n    const sign = _nrSign(data, planet);\n    return (_NR_OWN_SIGNS[planet] || []).includes(sign) || _NR_EXALTED[planet] === sign;\n}\n// কন্যার গ্রহ বরের কুষ্ঠিতে (অথবা বিপরীতক্রমে) কোন ভাবে পড়ে\nfunction _nrCrossHouse(planetLon, otherLagnaIdx) {\n    if (planetLon == null || otherLagnaIdx == null) return null;\n    return ((_nrSignIdx(planetLon) - otherLagnaIdx + 12) % 12) + 1;\n}\nfunction _nrIsKendra(h1, h2) {\n    if (h1 == null || h2 == null) return false;\n    const diff = ((h1 - h2) % 12 + 12) % 12;\n    return diff === 0 || diff === 3 || diff === 6 || diff === 9;\n}\n// লগ্ন থেকে কেন্দ্রস্থান (১/৪/৭/১০ ভাব)\nfunction _nrIsKendraHouse(h) {\n    return [1, 4, 7, 10].includes(h);\n}\n// গ্রহের নীচ রাশি (উচ্চ রাশির ঠিক বিপরীত রাশি)\nconst _NR_DEBILITATED = {};\nObject.keys(_NR_EXALTED).forEach(planet => {\n    const exIdx = _NR_RASHI_ORDER.indexOf(_NR_EXALTED[planet]);\n    _NR_DEBILITATED[planet] = _NR_RASHI_ORDER[(exIdx + 6) % 12];\n});\n\nconst NARRATIVE_SECTIONS = [\n    { key: \"emotionalBonding\", title: \"💞 মানসিক বন্ধন\" },\n    { key: \"maritalBliss\", title: \"🌹 দাম্পত্য সুখ ও আকর্ষণ\" },\n    { key: \"financialProsperity\", title: \"💰 আর্থিক সমৃদ্ধি\" },\n    { key: \"progeny\", title: \"👶 সন্তান সম্ভাবনা\" },\n    { key: \"careerSupport\", title: \"💼 ক্যারিয়ার ও পারস্পরিক সহায়তা\" },\n    { key: \"healthLongevity\", title: \"🏥 স্বাস্থ্য ও মানসিক সুস্থতা\" },\n    { key: \"specialYogas\", title: \"✨ বিশেষ শুভ যোগ\" },\n    { key: \"marriageTiming\", title: \"💍 বিবাহের সম্ভাব্য শুভ সময়কাল (দশা বিশ্লেষণ)\" }\n];\n\nconst NARRATIVE_DEFAULTS = {\n    emotionalBonding: \"চন্দ্রের সাধারণ অবস্থানের কারণে মানসিক বন্ধন স্বাভাবিক নিয়মে গড়ে উঠবে। নিয়মিত খোলামেলা আলোচনা ও একসাথে সময় কাটালে সম্পর্কের গভীরতা ধীরে ধীরে বাড়বে।\",\n    maritalBliss: \"শুক্র ও মঙ্গলের সাধারণ অবস্থানের কারণে দাম্পত্য জীবন স্থিতিশীল গতিতে এগোবে। তীব্র আকর্ষণ বা তীব্র দ্বন্দ্ব কোনোটিই প্রকট হবে না — যা দীর্ঘস্থায়ী সম্পর্কের জন্য ভালো লক্ষণ।\",\n    financialProsperity: \"আর্থিক জীবন সাধারণ গতিতে স্থিতিশীল থাকবে। পরিকল্পিত সঞ্চয় ও বিনিয়োগের মাধ্যমে আর্থিক নিরাপত্তা নিশ্চিত করা সম্ভব।\",\n    progeny: \"সন্তানলাভে সাধারণ কোনো বাধা নেই। পঞ্চম ভাবের গড় অবস্থানের কারণে গর্ভধারণ ও সন্তান-পালন স্বাভাবিক গতিতেই হবে।\",\n    careerSupport: \"ক্যারিয়ারে পরস্পরের সহায়তা স্বাভাবিক থাকবে। স্বতন্ত্র পথেই দুজনে নিজ নিজ ক্ষেত্রে উন্নতি করতে পারবেন।\",\n    healthLongevity: \"স্বাস্থ্য সাধারণত ভালো থাকবে। বয়স বাড়ার সাথে সাথে নিয়মিত স্বাস্থ্য পরীক্ষা করানো বুদ্ধিমানের কাজ হবে।\",\n    specialYogas: \"কুষ্ঠিতে অতিরিক্ত কোনো মহাশুভ যোগ চিহ্নিত না হলেও এর অর্থ এই নয় যে মিলন শুভ নয় — অষ্টকূট ও মাঙ্গলিক বিচারই দাম্পত্য জীবনের মূল ভিত্তি নির্ধারণ করে, যা উপরে বিস্তারিতভাবে আলোচিত হয়েছে।\",\n    marriageTiming: \"জন্ম-তথ্যের অভাবে বা দশা-হিসাবে নির্দিষ্ট শুভ সময়কাল চিহ্নিত করা সম্ভব হয়নি। সাধারণভাবে শুক্র, লগ্নেশ বা সপ্তমেশের দশা/অন্তর্দশা চলাকালীন বিবাহের সম্ভাবনা বৃদ্ধি পায়।\"\n};\n\n// প্রতিটি রুল ফাংশন (gd, bd, result) নিয়ে স্ট্রিং, স্ট্রিং-অ্যারে অথবা null রিটার্ন করে\nconst NARRATIVE_RULES = {\n    emotionalBonding: [\n        (gd, bd) => gd.moonRashi && gd.moonRashi === bd.moonRashi\n            ? `উভয়ের চন্দ্র রাশি ${gd.moonRashi} — একই রাশিতে অবস্থিত। এটি একটি দুর্লভ মানসিক সাদৃশ্য যোগ; দুজনের ভাবনা, পছন্দ-অপছন্দ ও মনের গতি প্রায় একই সুরে বাঁধা থাকবে। কথা না বলেও একে অপরের মনের অবস্থা বোঝা সহজ হবে। তবে একঘেয়েমি এড়াতে নতুনত্ব আনার চেষ্টা করুন।`\n            : null,\n        (gd, bd) => {\n            const gi = _NR_RASHI_ORDER.indexOf(gd.moonRashi), bi = _NR_RASHI_ORDER.indexOf(bd.moonRashi);\n            if (gi === -1 || bi === -1) return null;\n            const dist = ((bi - gi + 12) % 12) + 1;\n            if (dist === 9) return `কন্যার রাশি থেকে বরের চন্দ্ররাশি নবম স্থানে — এটি একটি শুভ ভাগ্য-সংযোগ যোগ। এই অবস্থান পরস্পরের প্রতি সহজাত সম্মান ও বিশ্বাস বাড়ায়, এবং একে অপরের আধ্যাত্মিক ও দার্শনিক দৃষ্টিভঙ্গি বিকাশে সহায়ক হয়।`;\n            if (dist === 5 || dist === 6 || dist === 8) return `কন্যা ও বরের চন্দ্ররাশির মধ্যে দূরত্ব শাস্ত্রমতে কিছুটা সতর্কতামূলক। এর প্রভাবে শুরুতে মতের অমিল দেখা দিতে পারে, তবে চন্দ্রের স্বাভাবিক সহনশীলতায় তা সময়ের সাথে কমে আসে — ধৈর্য ও আন্তরিক আলোচনাই এই অমিল দূর করার চাবিকাঠি।`;\n            return null;\n        },\n        (gd, bd) => {\n            const gLon = _nrLon(gd, \"চন্দ্র\");\n            const h = _nrCrossHouse(gLon, bd.lagnaIdx);\n            if ([1,5,9].includes(h)) return `কন্যার চন্দ্র বরের কুষ্ঠিতে ${h===1?'প্রথম':h===5?'পঞ্চম':'নবম'} ভাবে পড়েছে — এটি অত্যন্ত শুভ। কন্যার উপস্থিতি বরের জীবনে মানসিক প্রশান্তি, সৌভাগ্য ও সৃজনশীলতার সঞ্চার করবে।`;\n            return null;\n        },\n        (gd, bd) => {\n            const bLon = _nrLon(bd, \"চন্দ্র\");\n            const h = _nrCrossHouse(bLon, gd.lagnaIdx);\n            if ([1,5,9].includes(h)) return `বরের চন্দ্র কন্যার কুষ্ঠিতে ${h===1?'প্রথম':h===5?'পঞ্চম':'নবম'} ভাবে পড়েছে — এটি অত্যন্ত শুভ। বরের উপস্থিতি কন্যার জীবনে নিরাপত্তা, স্থিতিশীলতা ও আনন্দ বয়ে আনবে।`;\n            return null;\n        }\n    ],\n    maritalBliss: [\n        (gd, bd) => _nrIsStrong(gd, \"শুক্র\") && _nrIsStrong(bd, \"শুক্র\")\n            ? `কন্যা ও বরের শুক্র উভয়েই স্বরাশি বা উচ্চস্থ — দাম্পত্য সুখের জন্য অত্যন্ত শুভ লক্ষণ। দুজনেই রোমান্টিক, রুচিশীল ও সম্পর্ককে সুন্দরভাবে লালন করতে জানেন। তবে অতিরিক্ত ভোগ-বিলাস আর্থিক ভারসাম্য নষ্ট না করে, সেদিকে সতর্ক থাকা ভালো।`\n            : null,\n        (gd, bd) => {\n            const gVenus = _nrSign(gd, \"শুক্র\"), bMars = _nrSign(bd, \"মঙ্গল\");\n            if (gVenus && gVenus === bMars) return `কন্যার শুক্র এবং বরের মঙ্গল একই রাশিতে অবস্থিত — এটি প্রবল শারীরিক ও মানসিক আকর্ষণের যোগ। সম্পর্কের শুরু থেকেই একে অপরের প্রতি গভীর টান অনুভূত হবে। তবে এই তীব্র আকর্ষণ মাঝে মাঝে অধিকারবোধের জন্ম দিতে পারে — পরস্পরকে ব্যক্তিগত স্বাধীনতা দিতে শিখুন।`;\n            return null;\n        },\n        (gd, bd) => {\n            const out = [];\n            [[\"কন্যার\", gd], [\"বরের\", bd]].forEach(([label, data]) => {\n                const sat7 = _nrHouse(data, \"শনি\") === 7, rahu7 = _nrHouse(data, \"রাহু\") === 7;\n                if (sat7 || rahu7) out.push(`${label} সপ্তম ভাবে ${sat7?'শনি':'রাহু'}-র প্রভাব রয়েছে — এটি বিবাহে কিছু বিলম্ব বা প্রথমদিকে সম্পর্কে গাম্ভীর্যের ইঙ্গিত দেয়। তবে এই ধীর-গতির সম্পর্কই সময়ের সাথে সবচেয়ে স্থায়ী ও দায়িত্বপূর্ণ হয়ে ওঠে — তাড়াহুড়ো না করে একে অপরকে বোঝার সময় দিন।`);\n            });\n            return out.length ? out : null;\n        }\n    ],\n    financialProsperity: [\n        (gd, bd) => {\n            const hasBenefic2or11 = d => [2,11].includes(_nrHouse(d,\"বৃহস্পতি\")) || [2,11].includes(_nrHouse(d,\"শুক্র\"));\n            return hasBenefic2or11(gd) && hasBenefic2or11(bd)\n                ? `উভয়ের কুষ্ঠিতেই ধনস্থান (২য়) বা লাভস্থান (১১শ ভাব) শুভ গ্রহ (বৃহস্পতি/শুক্র) দ্বারা প্রভাবিত। বিবাহের পর সঞ্চয় ও আয়ের পথ প্রশস্ত হবে। তবে এই শুভফল ধরে রাখতে নিয়মিত বাজেট তৈরি ও দান-ধর্মের অভ্যাস করা ভালো।`\n                : null;\n        },\n        (gd, bd) => {\n            const out = [];\n            [[\"কন্যার\", gd], [\"বরের\", bd]].forEach(([label, data]) => {\n                const bad8 = [\"শনি\",\"রাহু\",\"মঙ্গল\"].some(p => _nrHouse(data,p) === 8);\n                if (bad8) out.push(`${label} অষ্টম ভাবে পাপগ্রহের প্রভাব রয়েছে — এটি আকস্মিক ব্যয় বা ঋণের সম্ভাবনার ইঙ্গিত দেয়। বড় বিনিয়োগের আগে ভালোভাবে পরিকল্পনা করুন এবং একটি জরুরি সঞ্চয়-তহবিল তৈরি রাখুন।`);\n            });\n            return out.length ? out : null;\n        }\n    ],\n    progeny: [\n        (gd, bd) => {\n            const has5 = d => [5].includes(_nrHouse(d,\"বৃহস্পতি\")) || [5].includes(_nrHouse(d,\"শুক্র\"));\n            return has5(gd) && has5(bd)\n                ? `উভয়ের পঞ্চম ভাব (সন্তানস্থান) বৃহস্পতি বা শুক্র দ্বারা প্রভাবিত — সুসন্তান লাভের শুভ লক্ষণ। সন্তান হবে গুণবান ও বুদ্ধিমান, এবং গর্ভধারণেও বিশেষ জটিলতার সম্ভাবনা কম।`\n                : null;\n        },\n        (gd, bd) => {\n            const out = [];\n            [[\"কন্যার\", gd], [\"বরের\", bd]].forEach(([label, data]) => {\n                const bad5 = _nrHouse(data,\"শনি\")===5 || _nrHouse(data,\"রাহু\")===5;\n                if (bad5) out.push(`${label} পঞ্চম ভাবে শনি বা রাহুর প্রভাব — সন্তানলাভে কিছু বিলম্বের ইঙ্গিত দিতে পারে। তবে এই বিলম্ব আশঙ্কার কারণ নয়; ধৈর্য ও প্রয়োজনে চিকিৎসা-পরামর্শের সাথে এগোলে শুভ ফল আসবে।`);\n            });\n            return out.length ? out : null;\n        },\n        (gd, bd, result) => {\n            const nadi = result && result.kootas && result.kootas.nadi;\n            return nadi && nadi.points === 0\n                ? `অষ্টকূট বিচারে নাড়ীদোষ চিহ্নিত হয়েছে, যা সন্তান ও স্বাস্থ্যের ক্ষেত্রে শাস্ত্রে গুরুত্বপূর্ণ বিবেচ্য। উপরে \"প্রতিকার\" অংশে উল্লিখিত মহামৃত্যুঞ্জয় মন্ত্র ও সংশ্লিষ্ট প্রতিকার অনুসরণ করার পরামর্শ দেওয়া হচ্ছে।`\n                : null;\n        }\n    ],\n    careerSupport: [\n        (gd, bd) => {\n            const out = [];\n            [[\"কন্যার\", gd], [\"বরের\", bd]].forEach(([label, data]) => {\n                const j10 = _nrHouse(data,\"বৃহস্পতি\")===10, v10 = _nrHouse(data,\"শুক্র\")===10;\n                if (j10 || v10) out.push(`${label} ${j10?'বৃহস্পতি':'শুক্র'} দশম ভাবে (কর্মস্থানে) অবস্থিত — সঙ্গীর উপস্থিতি কর্মজীবনে সহায়ক হবে এবং পরামর্শ সাফল্যের সম্ভাবনা বাড়াবে।`);\n            });\n            return out.length ? out : null;\n        },\n        (gd, bd) => {\n            const gl = _nrEngine.rashiLords[gd.moonRashi], bl = _nrEngine.rashiLords[bd.moonRashi];\n            if (!gl || !bl) return null;\n            const friends = gl === bl ||\n                (_nrEngine.planetRelations[gl] && _nrEngine.planetRelations[gl].f && _nrEngine.planetRelations[gl].f.includes(bl)) ||\n                (_nrEngine.planetRelations[bl] && _nrEngine.planetRelations[bl].f && _nrEngine.planetRelations[bl].f.includes(gl));\n            return friends ? `উভয়ের চন্দ্ররাশির অধিপতি গ্রহ পরস্পর মিত্র (বা অভিন্ন) — এটি ক্যারিয়ারে চমৎকার সহযোগিতার যোগ। একজনের সাফল্য অন্যজনের জন্য নতুন সুযোগের দরজা খুলে দেবে।` : null;\n        }\n    ],\n    healthLongevity: [\n        (gd, bd) => {\n            const out = [];\n            [[\"কন্যার\", gd], [\"বরের\", bd]].forEach(([label, data]) => {\n                const lord = _nrEngine.rashiLords[data.lagnaRashi];\n                if (!lord) return;\n                const h = _nrHouse(data, lord);\n                if ([6,8,12].includes(h)) out.push(`${label} লগ্নেশ (${lord}) ${h===6?'ষষ্ঠ':h===8?'অষ্টম':'দ্বাদশ'} ভাবে — এটি স্বাস্থ্যের প্রতি বিশেষ সতর্কতার ইঙ্গিত দেয়। নিয়মিত স্বাস্থ্য পরীক্ষা ও সুশৃঙ্খল জীবনযাপন এই প্রভাব নিয়ন্ত্রণে সহায়ক হবে।`);\n            });\n            return out.length ? out : null;\n        },\n        (gd, bd) => {\n            const out = [];\n            [[\"কন্যার\", gd], [\"বরের\", bd]].forEach(([label, data]) => {\n                if (_nrHouse(data,\"চন্দ্র\") === _nrHouse(data,\"মঙ্গল\")) out.push(`${label} কুষ্ঠিতে চন্দ্র-মঙ্গল যোগ (একই ভাবে) বিদ্যমান — এটি মানসিক অস্থিরতা ও তীব্র আবেগের ইঙ্গিত দেয়। ছোট বিষয়ে রাগ না দেখিয়ে শান্তভাবে আলোচনার অভ্যাস দাম্পত্য জীবনে শান্তি আনবে।`);\n            });\n            return out.length ? out : null;\n        }\n    ],\n    specialYogas: [\n        (gd, bd) => {\n            const out = [];\n            [[\"কন্যার\", gd], [\"বরের\", bd]].forEach(([label, data]) => {\n                if (_nrIsKendra(_nrHouse(data,\"চন্দ্র\"), _nrHouse(data,\"বৃহস্পতি\"))) out.push(`${label} কুষ্ঠিতে গজকেশরী যোগ বিদ্যমান (চন্দ্র-বৃহস্পতি পরস্পর কেন্দ্রস্থানে) — জ্ঞান, সৌভাগ্য ও সুনামের মহাশুভ যোগ। এই প্রভাব দাম্পত্য জীবনেও ইতিবাচকভাবে ছড়িয়ে পড়বে।`);\n            });\n            return out.length ? out : null;\n        },\n        (gd, bd) => {\n            const out = [];\n            [[\"কন্যার\", gd], [\"বরের\", bd]].forEach(([label, data]) => {\n                if (_nrIsKendra(_nrHouse(data,\"শুক্র\"), _nrHouse(data,\"বৃহস্পতি\"))) out.push(`${label} কুষ্ঠিতে শুক্র-বৃহস্পতি পরস্পর কেন্দ্রস্থানে — লক্ষ্মী-নারায়ণ যোগের আভাস। এই দম্পতির গৃহে আর্থিক প্রাচুর্য ও আধ্যাত্মিক প্রশান্তি একত্রে বিরাজ করার সম্ভাবনা থাকে।`);\n            });\n            return out.length ? out : null;\n        },\n        // পঞ্চমহাপুরুষ যোগ — কেন্দ্রস্থানে (১/৪/৭/১০) স্বরাশি বা উচ্চরাশিস্থ গ্রহ\n        (gd, bd) => {\n            const PMY = {\n                \"মঙ্গল\":  { name: \"রুচক\", desc: \"সাহস, নেতৃত্বগুণ ও দৃঢ় ব্যক্তিত্বের মহাশুভ যোগ। জাতক/জাতিকা স্বভাবে তেজস্বী, পরিশ্রমী ও সংগ্রামে অপরাজেয় হবেন—তবে এই তেজ সঙ্গীর প্রতি কোমলতায় পরিণত করাই দাম্পত্য সুখের চাবিকাঠি।\" },\n                \"বুধ\":    { name: \"ভদ্র\", desc: \"তীক্ষ্ণ বুদ্ধি, বাকপটুতা ও বিশ্লেষণী ক্ষমতার মহাশুভ যোগ। যুক্তিনির্ভর সিদ্ধান্ত ও সুন্দর যোগাযোগ-দক্ষতা সংসারে সমস্যা সমাধানে বিশেষ সহায়ক হবে।\" },\n                \"বৃহস্পতি\": { name: \"হংস\", desc: \"জ্ঞান, নৈতিকতা, আধ্যাত্মিকতা ও সৌভাগ্যের মহাশুভ যোগ। জাতক/জাতিকা হবেন সৎ, উদার ও সমাজে সম্মানিত—এই গুণ পরিবারে শান্তি ও প্রতিষ্ঠা বয়ে আনবে।\" },\n                \"শুক্র\":  { name: \"মালব্য\", desc: \"সৌন্দর্য, রুচি, কলা ও বিলাসিতার মহাশুভ যোগ। দাম্পত্য জীবনে রোমান্স, স্বাচ্ছন্দ্য ও শৈল্পিক উপভোগের প্রাচুর্য থাকবে।\" },\n                \"শনি\":    { name: \"শশ\", desc: \"শৃঙ্খলা, ধৈর্য, কঠোর শ্রম ও দীর্ঘমেয়াদী সাফল্যের মহাশুভ যোগ। জাতক/জাতিকা ধীরস্থির ও দায়িত্বশীল হবেন—যা সংসারে স্থিতিশীলতা ও নিরাপত্তা দেবে।\" }\n            };\n            const out = [];\n            [[\"কন্যার\", gd], [\"বরের\", bd]].forEach(([label, data]) => {\n                Object.keys(PMY).forEach(planet => {\n                    const h = _nrHouse(data, planet);\n                    if (_nrIsKendraHouse(h) && _nrIsStrong(data, planet)) {\n                        const y = PMY[planet];\n                        out.push(`${label} কুষ্ঠিতে ${y.name} যোগ বিদ্যমান (${planet} কেন্দ্রস্থানে স্বরাশি/উচ্চরাশিতে) — ${y.desc}`);\n                    }\n                });\n            });\n            return out.length ? out : null;\n        },\n        // বুধাদিত্য যোগ — সূর্য ও বুধ একই রাশিতে\n        (gd, bd) => {\n            const out = [];\n            [[\"কন্যার\", gd], [\"বরের\", bd]].forEach(([label, data]) => {\n                const sunSign = _nrSign(data, \"সূর্য\"), mercurySign = _nrSign(data, \"বুধ\");\n                if (sunSign && sunSign === mercurySign) {\n                    out.push(`${label} কুষ্ঠিতে বুধাদিত্য যোগ বিদ্যমান (সূর্য ও বুধ একই রাশি ${sunSign}-এ) — বুদ্ধিমত্তা, বাকপটুতা, যশ ও নেতৃত্বের শুভ যোগ। সংসারে সিদ্ধান্ত গ্রহণে স্পষ্টতা ও সম্মান বৃদ্ধি পাবে।`);\n                }\n            });\n            return out.length ? out : null;\n        },\n        // নীচভঙ্গ রাজযোগ — নীচ রাশির গ্রহের রাশিপতি কেন্দ্রস্থানে থাকলে নীচত্ব ভঙ্গ হয়\n        (gd, bd) => {\n            const out = [];\n            [[\"কন্যার\", gd], [\"বরের\", bd]].forEach(([label, data]) => {\n                Object.keys(_NR_DEBILITATED).forEach(planet => {\n                    const sign = _nrSign(data, planet);\n                    if (sign && sign === _NR_DEBILITATED[planet]) {\n                        const lord = _nrEngine.rashiLords[sign];\n                        if (_nrIsKendraHouse(_nrHouse(data, lord))) {\n                            out.push(`${label} কুষ্ঠিতে ${planet} নীচ রাশি (${sign}) তে অবস্থিত হলেও তার রাশিপতি (${lord}) কেন্দ্রস্থানে থাকায় নীচভঙ্গ রাজযোগ সৃষ্টি হয়েছে — প্রাথমিক বাধা-বিপত্তি কাটিয়ে জীবনে অভাবনীয় উন্নতি ও সম্মান লাভের ইঙ্গিত। সংগ্রামের পরেই আসবে আসল সাফল্য।`);\n                        }\n                    }\n                });\n            });\n            return out.length ? out : null;\n        }\n    ],\n    marriageTiming: [\n        (gd, bd) => {\n            const out = [];\n            [[\"কন্যার\", gd], [\"বরের\", bd]].forEach(([label, data]) => {\n                const periods = findMarriageFavorablePeriods(data);\n                if (!periods.length) return;\n                const ranges = periods.slice(0, 3)\n                    .map(p => `${_fmtDashaDate(p.start)} – ${_fmtDashaDate(p.end)} (${p.mahaLord}-${p.adLord} দশা)`)\n                    .join(', ');\n                out.push(`${label} কুষ্ঠি অনুযায়ী বিংশোত্তরী দশা বিচারে বিবাহের জন্য সম্ভাব্য শুভ সময়কাল: ${ranges}। এই পর্বগুলোতে শুক্র, লগ্নেশ বা সপ্তমেশের প্রভাব সক্রিয় থাকে, যা বিবাহ-যোগের জন্য অনুকূল। (এটি একটি আনুমানিক জ্যোতিষ-নির্দেশিকা মাত্র — প্রকৃত গোচর ও অন্যান্য যোগ বিচার করে বিশেষজ্ঞ জ্যোতিষীর পরামর্শ নেওয়া উচিত।)`);\n            });\n            return out.length ? out : null;\n        }\n    ]\n};\n\n/**\n * বিভাগ-ভিত্তিক বিস্তারিত narrative বিশ্লেষণ — শুধুমাত্র getPlanetData() থেকে পাওয়া\n * প্রকৃত গণনাকৃত গ্রহ-অবস্থান ব্যবহার করে। অষ্টকূট স্কোর/রায় অপরিবর্তিত থাকে (matchResult থেকে আসে)।\n * @returns {Array<{key:string,title:string,items:string[]}>}\n */\nfunction generateNarrativeAnalysis(girlData, boyData, matchResult) {\n    return NARRATIVE_SECTIONS.map(sec => {\n        const rules = NARRATIVE_RULES[sec.key] || [];\n        let items = [];\n        for (const rule of rules) {\n            let res;\n            try { res = rule(girlData, boyData, matchResult); } catch (e) { res = null; }\n            if (!res) continue;\n            items = items.concat(Array.isArray(res) ? res : [res]);\n        }\n        if (items.length === 0) items.push(NARRATIVE_DEFAULTS[sec.key]);\n        return { key: sec.key, title: sec.title, items };\n    });\n}\n\n// ==================== ১০. কুণ্ডলী বিবরণ তুলনা সারণীর সহায়ক ফাংশন ====================\n// ২৭ নক্ষত্রের বিংশোত্তরী-পতি (অশ্বিনী থেকে শুরু করে ৯-গ্রহের আবর্তন, ৩ বার)\nconst NAKSHATRA_LORDS = [\n    \"কেতু\",\"শুক্র\",\"সূর্য\",\"চন্দ্র\",\"মঙ্গল\",\"রাহু\",\"বৃহস্পতি\",\"শনি\",\"বুধ\",\n    \"কেতু\",\"শুক্র\",\"সূর্য\",\"চন্দ্র\",\"মঙ্গল\",\"রাহু\",\"বৃহস্পতি\",\"শনি\",\"বুধ\",\n    \"কেতু\",\"শুক্র\",\"সূর্য\",\"চন্দ্র\",\"মঙ্গল\",\"রাহু\",\"বৃহস্পতি\",\"শনি\",\"বুধ\"\n];\n\n/** নক্ষত্র-ইন্ডেক্স (০-২৬, getPlanetData().moonNakshatraIndex) থেকে নক্ষত্র-পতি */\nfunction getNakshatraLordName(nakshatraIndex) {\n    if (nakshatraIndex == null || nakshatraIndex < 0 || nakshatraIndex > 26) return \"—\";\n    return NAKSHATRA_LORDS[nakshatraIndex];\n}\n\n/** রাশির নাম থেকে রাশিপতি (লগ্ন পতি / রাশি পতি নির্ণয়ে ব্যবহৃত) */\nfunction getRashiLordName(rashiName) {\n    return _nrEngine.rashiLords[rashiName] || \"—\";\n}\n\n// প্রতিটি কূটের সাথে সম্পর্কিত জীবনক্ষেত্র (Ashtakoota premium সারণীর জন্য)\nconst KOOTA_LIFE_AREAS = {\n    varna: \"কর্ম / পেশা\",\n    vasu: \"আধিপত্য\",\n    tara: \"ভাগ্য / ভাগ্যোন্নতি\",\n    yoni: \"মানসিকতা\",\n    grahaMaitri: \"পারস্পরিক মিল\",\n    gana: \"স্বভাব / আচরণ\",\n    bhakoota: \"প্রেম ও দাম্পত্য\",\n    nadi: \"স্বাস্থ্য ও বংশ\"\n};\n\n// বিংশোত্তরী দশা-পদ্ধতিতে প্রতিটি গ্রহের মহাদশার সময়কাল (বছর, সর্বমোট ১২০ বছর)\nconst VIMSHOTTARI_YEARS = {\n    \"কেতু\":7,\"শুক্র\":20,\"সূর্য\":6,\"চন্দ্র\":10,\"মঙ্গল\":7,\n    \"রাহু\":18,\"বৃহস্পতি\":16,\"শনি\":19,\"বুধ\":17\n};\n\n// নবাংশ রাশির ত্রিগুণ (অগ্নি/পৃথিবী/বায়ু/জল) অনুযায়ী পায়া (ধাতু) নির্ণয়\nconst PAYA_NAMES = [\"স্বর্ণ পায়া\",\"রৌপ্য পায়া\",\"তাম্র পায়া\",\"লৌহ পায়া\"];\n\n/** চন্দ্রের স্ফুট (ডিগ্রি, ০-৩৬০) থেকে নবাংশ-ভিত্তিক পায়া (ধাতু) নির্ণয় */\nfunction getPaya(moonLon) {\n    if (moonLon == null || isNaN(moonLon)) return \"—\";\n    const lon = ((moonLon % 360) + 360) % 360;\n    const signIdx = Math.floor(lon / 30);\n    const degInSign = lon % 30;\n    const navPortion = Math.floor(degInSign / (30 / 9)) % 9;\n    let startIdx;\n    if ([0,3,6,9].includes(signIdx)) startIdx = signIdx;              // চর রাশি — নিজ রাশি থেকে\n    else if ([1,4,7,10].includes(signIdx)) startIdx = (signIdx + 8) % 12; // স্থির রাশি — ৯ম রাশি থেকে\n    else startIdx = (signIdx + 4) % 12;                                // দ্বিস্বভাব রাশি — ৫ম রাশি থেকে\n    const navSignIdx = (startIdx + navPortion) % 12;\n    return PAYA_NAMES[navSignIdx % 4];\n}\n\n/** চন্দ্রের স্ফুট ও নক্ষত্র-ইন্ডেক্স থেকে জন্মকালীন বিংশোত্তরী মহাদশার অবশিষ্ট সময়কাল */\nfunction getDashaBalance(moonLon, nakshatraIndex) {\n    if (moonLon == null || isNaN(moonLon) || nakshatraIndex == null || nakshatraIndex < 0 || nakshatraIndex > 26) return \"—\";\n    const lord = NAKSHATRA_LORDS[nakshatraIndex];\n    const totalYears = VIMSHOTTARI_YEARS[lord];\n    if (!totalYears) return \"—\";\n    const NAK_SPAN = 360 / 27;\n    const lon = ((moonLon % 360) + 360) % 360;\n    const posInNak = lon % NAK_SPAN;\n    const remainingFrac = 1 - (posInNak / NAK_SPAN);\n    const remainingYears = totalYears * remainingFrac;\n    const y = Math.floor(remainingYears);\n    const mFloat = (remainingYears - y) * 12;\n    const m = Math.floor(mFloat);\n    const dDays = Math.round((mFloat - m) * 30);\n    return `${lord} ${y} বছর ${m} মাস ${dDays} দিন`;\n}\n\n// ==================== ১১. বিংশোত্তরী দশা-ক্রম ও বিবাহের সম্ভাব্য শুভ সময়কাল ====================\nconst VIMSHOTTARI_ORDER = [\"কেতু\",\"শুক্র\",\"সূর্য\",\"চন্দ্র\",\"মঙ্গল\",\"রাহু\",\"বৃহস্পতি\",\"শনি\",\"বুধ\"];\nconst _DASHA_DAYS_PER_YEAR = 365.2425;\nconst _BN_MONTHS = [\"জানুয়ারি\",\"ফেব্রুয়ারি\",\"মার্চ\",\"এপ্রিল\",\"মে\",\"জুন\",\"জুলাই\",\"আগস্ট\",\"সেপ্টেম্বর\",\"অক্টোবর\",\"নভেম্বর\",\"ডিসেম্বর\"];\n\nfunction _fmtDashaDate(date) {\n    return `${_BN_MONTHS[date.getUTCMonth()]} ${date.getUTCFullYear()}`;\n}\n\n/**\n * জন্ম-তারিখ, চন্দ্রের স্ফুট ও নক্ষত্র-ইন্ডেক্স থেকে বিংশোত্তরী মহাদশা ও অন্তর্দশার\n * তারিখ-পরিসর গণনা — kundali.html-এর prediction-engine.js (calculateBirthDasha/\n * getCurrentAntarDasha) একই পদ্ধতি অনুসরণ করা হয়েছে: প্রথম (আংশিক) মহাদশার\n * অন্তর্দশাগুলোও সেই মহাদশার অবশিষ্ট সময়কাল অনুযায়ী আনুপাতিকভাবে বিভক্ত হয়\n * @returns {Array<{lord:string, start:Date, end:Date, antardashas:Array<{lord:string,start:Date,end:Date}>}>}\n */\nfunction getVimshottariDashaSequence(moonLon, nakshatraIndex, dobStr) {\n    if (moonLon == null || isNaN(moonLon) || nakshatraIndex == null || nakshatraIndex < 0 || nakshatraIndex > 26 || !dobStr) return [];\n    const [y, mo, d] = dobStr.split(\"-\").map(Number);\n    if (!y || !mo || !d) return [];\n    const birthDate = new Date(Date.UTC(y, mo - 1, d));\n\n    const NAK_SPAN = 360 / 27;\n    const lon = ((moonLon % 360) + 360) % 360;\n    const posInNak = lon % NAK_SPAN;\n    const remainingFrac = 1 - (posInNak / NAK_SPAN);\n    const startIdx = VIMSHOTTARI_ORDER.indexOf(NAKSHATRA_LORDS[nakshatraIndex]);\n\n    const periods = [];\n    let cursor = birthDate.getTime();\n    for (let i = 0; i < 12; i++) {\n        const idx = (startIdx + i) % 9;\n        const lord = VIMSHOTTARI_ORDER[idx];\n        const totalYears = VIMSHOTTARI_YEARS[lord];\n        const years = i === 0 ? totalYears * remainingFrac : totalYears;\n        const start = new Date(cursor);\n        const end = new Date(cursor + years * _DASHA_DAYS_PER_YEAR * 86400000);\n\n        const antardashas = [];\n        let aCursor = cursor;\n        for (let j = 0; j < 9; j++) {\n            const aIdx = (idx + j) % 9;\n            const aLord = VIMSHOTTARI_ORDER[aIdx];\n            const aYears = years * VIMSHOTTARI_YEARS[aLord] / 120;\n            const aStart = new Date(aCursor);\n            let aEnd = new Date(aCursor + aYears * _DASHA_DAYS_PER_YEAR * 86400000);\n            if (j === 8 || aEnd.getTime() >= end.getTime()) aEnd = end;\n            antardashas.push({ lord: aLord, start: aStart, end: aEnd });\n            aCursor = aEnd.getTime();\n        }\n\n        periods.push({ lord, start, end, antardashas });\n        cursor = end.getTime();\n    }\n    return periods;\n}\n\n/**\n * বিবাহযোগ্য বয়সকালে (প্রায় ১৮-৪২ বছর) শুক্র / লগ্নেশ / সপ্তমেশ-সংক্রান্ত\n * মহাদশা-অন্তর্দশা পিরিয়ডসমূহ — বিবাহের সম্ভাব্য শুভ সময়ের আনুমানিক ইঙ্গিত\n * @returns {Array<{mahaLord:string, adLord:string, start:Date, end:Date, ageStart:number, ageEnd:number}>}\n */\nfunction findMarriageFavorablePeriods(data) {\n    if (!data.dob || data.moonLon == null || data.moonNakshatraIndex == null || !data.lagnaRashi) return [];\n    const periods = getVimshottariDashaSequence(data.moonLon, data.moonNakshatraIndex, data.dob);\n    if (!periods.length) return [];\n\n    const lagnaLord = _nrEngine.rashiLords[data.lagnaRashi];\n    const seventhSign = _NR_RASHI_ORDER[(_NR_RASHI_ORDER.indexOf(data.lagnaRashi) + 6) % 12];\n    const seventhLord = _nrEngine.rashiLords[seventhSign];\n    const significators = new Set([\"শুক্র\", lagnaLord, seventhLord].filter(Boolean));\n\n    const [by, bm, bd] = data.dob.split(\"-\").map(Number);\n    const birthDate = new Date(Date.UTC(by, bm - 1, bd));\n    const ageOf = date => (date.getTime() - birthDate.getTime()) / (_DASHA_DAYS_PER_YEAR * 86400000);\n\n    const results = [];\n    periods.forEach(maha => {\n        maha.antardashas.forEach(ad => {\n            const ageStart = ageOf(ad.start), ageEnd = ageOf(ad.end);\n            if (ageEnd < 18 || ageStart > 42) return;\n            if (significators.has(maha.lord) || significators.has(ad.lord)) {\n                results.push({ mahaLord: maha.lord, adLord: ad.lord, start: ad.start, end: ad.end, ageStart, ageEnd });\n            }\n        });\n    });\n    return results;\n}\n\n// Export\nif (typeof module !== \"undefined\" && module.exports) {\n    module.exports = YotakBicharEngine;\n}\n\nconsole.log(\"✅ yotak-bichar.js — YotakBicharEngine লোড সম্পন্ন\");\nconsole.log(\"🔍 ব্যবহার: new YotakBicharEngine().match(girlData, boyData)\");\n\n</script>\n<script>\n/* Nav */\nfunction toggleNav(){var nav=document.getElementById('navMenu'),ov=document.getElementById('navOverlay');nav.classList.toggle('open');ov.classList.toggle('open');document.body.classList.toggle('nav-open',nav.classList.contains('open'));}\nfunction closeNav(){document.getElementById('navMenu').classList.remove('open');document.getElementById('navOverlay').classList.remove('open');document.body.style.overflow='';}\ndocument.addEventListener('click',function(e){var nav=document.getElementById('navMenu'),ham=document.querySelector('.ham');if(nav&&nav.classList.contains('open')&&!nav.contains(e.target)&&ham&&!ham.contains(e.target)){closeNav();}});\ndocument.querySelectorAll('#navMenu a').forEach(function(a){a.addEventListener('click',closeNav);});\n\nconst RASHI_NAMES=[\"মেষ\",\"বৃষ\",\"মিথুন\",\"কর্কট\",\"সিংহ\",\"কন্যা\",\"তুলা\",\"বৃশ্চিক\",\"ধনু\",\"মকর\",\"কুম্ভ\",\"মীন\"];\nconst NAKSHATRA_NAMES=[\"অশ্বিনী\",\"ভরণী\",\"কৃত্তিকা\",\"রোহিণী\",\"মৃগশিরা\",\"আর্দ্রা\",\"পুনর্বসু\",\"পুষ্যা\",\"অশ্লেষা\",\"মঘা\",\"পূর্বফাল্গুনী\",\"উত্তরফাল্গুনী\",\"হস্তা\",\"চিত্রা\",\"স্বাতী\",\"বিশাখা\",\"অনুরাধা\",\"জ্যেষ্ঠা\",\"মূলা\",\"পূর্বাষাঢ়া\",\"উত্তরাষাঢ়া\",\"শ্রবণা\",\"ধনিষ্ঠা\",\"শতভিষা\",\"পূর্বভাদ্রপদ\",\"উত্তরভাদ্রপদ\",\"রেবতী\"];\nconst PLANET_SHORT={\"লগ্ন\":\"ল\",\"সূর্য\":\"রবি\",\"চন্দ্র\":\"চন্দ্র\",\"মঙ্গল\":\"মঙ্গ\",\"বুধ\":\"বুধ\",\"বৃহস্পতি\":\"বৃহ\",\"শুক্র\":\"শুক্র\",\"শনি\":\"শনি\",\"রাহু\":\"রাহু\",\"কেতু\":\"কেতু\"};\nconst PLANET_COLOR={\"সূর্য\":\"#e65c00\",\"চন্দ্র\":\"#2980b9\",\"মঙ্গল\":\"#c0392b\",\"বুধ\":\"#27ae60\",\"বৃহস্পতি\":\"#8e44ad\",\"শুক্র\":\"#e91e8c\",\"শনি\":\"#5d4037\",\"রাহু\":\"#7f8c8d\",\"কেতু\":\"#95a5a6\",\"লগ্ন\":\"#8b0000\"};\n/* D1/D9 (320×320) চার্টের প্রতিটি ঘরের জ্যামিতিক কেন্দ্রবিন্দু (centroid)।\n   পূর্ব ভারতীয় ছকে রাশির অবস্থান সর্বদা নির্দিষ্ট থাকে (০:মেষ উপরে-মাঝে, ১:বৃষ...১১:মীন,\n   ঘড়ির কাঁটার দিকে), তাই আলাদা করে রাশির নাম লেখা হয় না — শুধু লগ্ন ও গ্রহ বসানো হয়। */\nconst CHART_POS=[\n  {x:160,y:53.5},   // ০: মেষ\n  {x:71.33,y:35.67},// ১: বৃষ\n  {x:35.67,y:71.33},// ২: মিথুন\n  {x:53.5,y:160},   // ৩: কর্কট\n  {x:35.67,y:248.67},// ৪: সিংহ\n  {x:71.33,y:284.33},// ৫: কন্যা\n  {x:160,y:266.5},  // ৬: তুলা\n  {x:248.67,y:284.33},// ৭: বৃশ্চিক\n  {x:284.33,y:248.67},// ৮: ধনু\n  {x:266.5,y:160},  // ৯: মকর\n  {x:284.33,y:71.33},// ১০: কুম্ভ\n  {x:248.67,y:35.67} // ১১: মীন\n];\nconst BN_DIGITS=['০','১','২','৩','৪','৫','৬','৭','৮','৯'];\nfunction toBnNum(n){return String(n).split('').map(d=>BN_DIGITS[+d]!==undefined?BN_DIGITS[+d]:d).join('');}\nfunction getNakshatraAndPada(lon){\n  const n=((lon||0)%360+360)%360;\n  const idx=Math.floor(n/(360/27));\n  const pada=Math.floor((n%(360/27))/(360/108))+1;\n  return{name:NAKSHATRA_NAMES[idx%27],pada,idx:idx%27};\n}\n\nfunction getNavamshaRashi(lon){const sign=Math.floor(((lon%360)+360)%360/30)%12,part=Math.floor((((lon%360)+360)%360%30)/(30/9));return(sign%3===0?0:sign%3===1?9:18)+part;}\n\n/* showExtras=true হলে প্রতিটি গ্রহের পাশে জন্ম-নক্ষত্র নম্বর (১-২৭) সুপারস্ক্রিপ্টে ও বক্রী\n   গ্রহের পাশে \"ᴿ\" দেখানো হয় (শুধু D1/রাশিচক্রে)। */\nfunction drawMMChart(labGId,plGId,planets,lagnaIdx,showExtras){\n  const labG=document.getElementById(labGId),plG=document.getElementById(plGId);\n  if(!labG||!plG)return;\n  labG.innerHTML='';plG.innerHTML='';\n  const ns=\"http://www.w3.org/2000/svg\";\n  const rashiMap=Array(12).fill(null).map(()=>[]);\n  if(lagnaIdx>=0&&lagnaIdx<12)rashiMap[lagnaIdx].push({text:\"লগ্ন\",color:PLANET_COLOR[\"লগ্ন\"],isLagna:true});\n  planets.forEach(p=>{\n    if(p.name==='লগ্ন')return; // লগ্ন আলাদাভাবে উপরে যোগ করা হয়েছে\n    const rIdx=Math.floor(((p.lon||0)%360+360)%360/30)%12;\n    const item={text:PLANET_SHORT[p.name]||p.name,color:PLANET_COLOR[p.name]||\"#1a1a2e\"};\n    if(showExtras){\n      item.nakNum=toBnNum(getNakshatraAndPada(p.lon).idx+1);\n      if(p.retro)item.retro=true;\n    }\n    rashiMap[rIdx].push(item);\n  });\n  CHART_POS.forEach((p,i)=>{\n    const items=rashiMap[i],cnt=items.length;\n    if(!cnt)return;\n    const fS=cnt<=1?15:cnt===2?13:cnt===3?12:cnt===4?10.5:cnt===5?9.5:8.5,lH=fS+1.5;\n    items.forEach((it,ni)=>{\n      const t=document.createElementNS(ns,\"text\"),ty=p.y+(ni-(cnt-1)/2)*lH;\n      t.setAttribute(\"x\",p.x);t.setAttribute(\"y\",ty);t.setAttribute(\"text-anchor\",\"middle\");\n      t.setAttribute(\"font-family\",\"Noto Sans Bengali,serif\");\n      const main=document.createElementNS(ns,\"tspan\");\n      main.setAttribute(\"fill\",it.isLagna?\"#8b0000\":it.color);\n      main.setAttribute(\"font-size\",String(fS));main.setAttribute(\"font-weight\",\"bold\");\n      main.textContent=it.text;t.appendChild(main);\n      if(it.nakNum){\n        const sup=document.createElementNS(ns,\"tspan\");\n        sup.setAttribute(\"fill\",\"#9a7b3a\");sup.setAttribute(\"font-size\",String(Math.max(fS*0.62,6.5)));\n        sup.setAttribute(\"font-weight\",\"700\");sup.setAttribute(\"baseline-shift\",\"super\");\n        sup.textContent=it.nakNum;t.appendChild(sup);\n      }\n      if(it.retro){\n        const r=document.createElementNS(ns,\"tspan\");\n        r.setAttribute(\"fill\",\"#c62828\");r.setAttribute(\"font-size\",String(Math.max(fS*0.62,6.5)));\n        r.setAttribute(\"font-weight\",\"900\");r.setAttribute(\"baseline-shift\",\"super\");\n        r.textContent=\"ᴿ\";t.appendChild(r);\n      }\n      plG.appendChild(t);\n    });\n  });\n}\n\nfunction buildPlanetTable(tbodyId,planets,lagnaIdx){\n  const tbody=document.getElementById(tbodyId);if(!tbody)return;tbody.innerHTML='';\n  planets.forEach(p=>{\n    const lon=((p.lon||0)%360+360)%360,ri=Math.floor(lon/30)%12,deg=Math.floor(lon%30),mn=Math.floor((lon%30-deg)*60);\n    const nak=getNakshatraAndPada(lon),house=p.name==='লগ্ন'?'লগ্ন':(((ri-lagnaIdx+12)%12)+1)+'ম';\n    const col=PLANET_COLOR[p.name]||'#333';\n    const retroBadge=p.retro?'<span style=\"display:inline-block;background:#c62828;color:#fff;border-radius:3px;font-size:.6rem;padding:0 4px;margin-left:4px;vertical-align:middle;font-weight:700;letter-spacing:.02em\">R</span>':'';\n    const tr=document.createElement('tr');\n    tr.innerHTML=`<td style=\"color:${col};font-weight:700\">${p.name}${retroBadge}</td><td>${RASHI_NAMES[ri]}</td><td>${deg}°${mn}'</td><td>${nak.name} ${nak.pada}য় পাদ</td><td>${house}</td>`;\n    tbody.appendChild(tr);\n  });\n}\n\nconst TITHI_NAMES=[\"প্রতিপদ\",\"দ্বিতীয়া\",\"তৃতীয়া\",\"চতুর্থী\",\"পঞ্চমী\",\"ষষ্ঠী\",\"সপ্তমী\",\"অষ্টমী\",\"নবমী\",\"দশমী\",\"একাদশী\",\"দ্বাদশী\",\"ত্রয়োদশী\",\"চতুর্দশী\",\"পূর্ণিমা/অমাবস্যা\"];\nconst YOGA_NAMES=[\"বিষ্কুম্ভ\",\"প্রীতি\",\"আয়ুষ্মান\",\"সৌভাগ্য\",\"শোভন\",\"অতিগণ্ড\",\"সুকর্মা\",\"ধৃতি\",\"শূল\",\"গণ্ড\",\"বৃদ্ধি\",\"ধ্রুব\",\"ব্যাঘাত\",\"হর্ষণ\",\"বজ্র\",\"সিদ্ধি\",\"ব্যতীপাত\",\"বরীয়ান\",\"পরিঘ\",\"শিব\",\"সিদ্ধ\",\"সাধ্য\",\"শুভ\",\"শুক্ল\",\"ব্রহ্ম\",\"ইন্দ্র\",\"বৈধৃতি\"];\nconst KARANA_NAMES=[\"বব\",\"বালব\",\"কৌলব\",\"তৈতিল\",\"গর\",\"বণিজ\",\"বিষ্টি\",\"শকুনি\",\"চতুষ্পদ\",\"নাগ\",\"কিন্তুঘ্ন\"];\nconst VARA_NAMES=[\"রবিবার\",\"সোমবার\",\"মঙ্গলবার\",\"বুধবার\",\"বৃহস্পতিবার\",\"শুক্রবার\",\"শনিবার\"];\n/* শাস্ত্রীয় করণ: ৬০ করণের মধ্যে ১=কিন্তুঘ্ন, ৫৮=শকুনি, ৫৯=চতুষ্পদ, ৬০=নাগ (স্থির); বাকি ৫৬টি ৭টি চর করণের আবর্তন */\nfunction getKaranaName(tithiRaw){\n  const num=Math.floor(tithiRaw*2)+1; // ১–৬০\n  if(num===1)return\"কিন্তুঘ্ন\";\n  if(num===58)return\"শকুনি\";\n  if(num===59)return\"চতুষ্পদ\";\n  if(num===60)return\"নাগ\";\n  return KARANA_NAMES[(num-2)%7];\n}\n\nfunction getPlanetData(dob,tob,lat,lon,tzOffset){\n  if(!dob||!tob||isNaN(lat)||isNaN(lon))return null;\n  const tz=isNaN(parseFloat(tzOffset))?5.5:parseFloat(tzOffset);\n  const[y,mo,d]=dob.split('-').map(Number),[h,mi,se]=tob.split(':').map(Number);\n  const jd=JD(y,mo,d)+(h-tz+mi/60+(se||0)/3600)/24,ay=lahiriAY(jd);\n  const sunLon=rev(sunL(jd)-ay),moonLon=rev(moonL(jd)-ay),marsLon=rev(marsL(jd)-ay);\n  const mercLon=rev(mercuryL(jd)-ay),jupLon=rev(jupiterL(jd)-ay),venLon=rev(venusL(jd)-ay);\n  const satLon=rev(saturnL(jd)-ay),rahuLon=rev(rahuL(jd)-ay),ketuLon=rev(rahuLon+180);\n  const lagnaLon=getLagna(jd,lat,lon);\n  const lagnaIdx=Math.floor(lagnaLon/30)%12;\n  const moonIdx=Math.floor(moonLon/(360/27))%27;\n  /* বক্রী গ্রহ সনাক্তকরণ (দৈনিক গতি ঋণাত্মক হলে বক্রী); রাহু/কেতু সর্বদা বক্রী বিবেচিত হলেও চিহ্নিত করা হয় না */\n  const _isRetro=fn=>(((fn(jd+1)-fn(jd))%360+360)%360)>180;\n  const marsRetro=_isRetro(marsL),mercRetro=_isRetro(mercuryL),jupRetro=_isRetro(jupiterL);\n  const venRetro=_isRetro(venusL),satRetro=_isRetro(saturnL);\n  /* পঞ্চাঙ্গ */\n  const tithiRaw=rev(moonLon-sunLon)/12;\n  const tithiNum=Math.ceil(tithiRaw)||1;\n  const tithiName=(tithiNum<=15?TITHI_NAMES[tithiNum-1]:tithiNum===30?TITHI_NAMES[14]:TITHI_NAMES[tithiNum-16])||'—';\n  const pakshaName=tithiNum<=15?'শুক্লপক্ষ':'কৃষ্ণপক্ষ';\n  const yogaIdx=Math.floor(rev(sunLon+moonLon)/(360/27))%27;\n  const vara=Math.floor(jd+1.5)%7;\n  const moonPada=Math.floor((moonLon%(360/27))/((360/27)/4))+1;\n  /* ইষ্টকাল — সূর্যোদয় থেকে জন্মক্ষণ পর্যন্ত অতিক্রান্ত সময় (ঘটি-পল-বিপল) */\n  let ishtakaal='—';\n  const _ss=getSunriseSunset(y,mo,d,lat,lon);\n  if(_ss){\n    let _ig=(jd-_ss.rise)*60;\n    if(_ig<0)_ig+=60;\n    const _gh=Math.floor(_ig),_palF=(_ig-_gh)*60,_pl=Math.floor(_palF),_vp=Math.round((_palF-_pl)*60);\n    ishtakaal=String(_gh).padStart(3,'0')+'-'+String(_pl).padStart(2,'0')+'-'+String(_vp).padStart(2,'0');\n  }\n  return{\n    dob,moonLon,ishtakaal,\n    moonNakshatra:NAKSHATRA_NAMES[moonIdx],moonNakshatraIndex:moonIdx,moonPada,\n    moonRashi:RASHI_NAMES[Math.floor(moonLon/30)%12],\n    sunRashi:RASHI_NAMES[Math.floor(sunLon/30)%12],\n    marsRashi:RASHI_NAMES[Math.floor(marsLon/30)%12],\n    lagnaRashi:RASHI_NAMES[lagnaIdx],lagnaIdx,\n    gana:NAKSHATRA_GANA[NAKSHATRA_NAMES[moonIdx]]||'—',\n    varna:NAKSHATRA_VARNA[NAKSHATRA_NAMES[moonIdx]]||'—',\n    tithi:tithiName,paksha:pakshaName,tithiNum,\n    yoga:YOGA_NAMES[yogaIdx]||'—',\n    karana:getKaranaName(tithiRaw)||'—',\n    vara:VARA_NAMES[vara]||'—',\n    planets:[\n      {name:\"লগ্ন\",lon:lagnaLon},{name:\"সূর্য\",lon:sunLon},{name:\"চন্দ্র\",lon:moonLon},\n      {name:\"মঙ্গল\",lon:marsLon,retro:marsRetro},{name:\"বুধ\",lon:mercLon,retro:mercRetro},{name:\"বৃহস্পতি\",lon:jupLon,retro:jupRetro},\n      {name:\"শুক্র\",lon:venLon,retro:venRetro},{name:\"শনি\",lon:satLon,retro:satRetro},{name:\"রাহু\",lon:rahuLon},{name:\"কেতু\",lon:ketuLon}\n    ]\n  };\n}\n\n/* জন্ম বিবরণ — নাম, জন্ম তারিখ/সময়/স্থান (kundali.html-এর ধাঁচে) */\nfunction buildBirthInfo(name,dob,tob,city,colorClass){\n  let dobStr='—';\n  if(dob){\n    const[y,mo,d]=dob.split('-');\n    dobStr=`${d}/${mo}/${y}`;\n  }\n  const items=[\n    {l:'নাম',v:name||'—'},{l:'জন্ম তারিখ',v:dobStr},\n    {l:'জন্ম সময়',v:tob||'—'},{l:'জন্মস্থান',v:city||'—'},\n  ];\n  return`<div style=\"margin-bottom:10px\"><div style=\"display:grid;grid-template-columns:repeat(2,1fr);gap:6px\">${items.map(it=>`<div style=\"background:#fff;padding:6px 8px;border-radius:7px;border:1px solid ${colorClass}33;text-align:center\"><div style=\"font-size:.62rem;color:${colorClass};font-weight:700;text-transform:uppercase;margin-bottom:1px\">${it.l}</div><div style=\"font-size:.8rem;font-weight:700;color:#2c1810;overflow:hidden;text-overflow:ellipsis;white-space:nowrap\">${it.v}</div></div>`).join('')}</div></div>`;\n}\n\n/* জন্ম তারিখ \"YYYY-MM-DD\" থেকে \"DD : MM : YYYY\" ফরম্যাটে রূপান্তর */\nfunction _mmFmtDateDots(dob){\n  if(!dob)return'—';\n  const[y,mo,d]=dob.split('-');\n  return`${d} : ${mo} : ${y}`;\n}\n\n/* \"কুণ্ডলী বিবরণ\" তুলনা সারণী — কন্যা/বরের জন্ম-বিবরণ ও পঞ্চাঙ্গ পাশাপাশি, প্রিমিয়াম গোল্ড-বর্ডার ছকে */\nfunction buildKundaliDetailsTable(gd,bd,gName,bName,gTob,bTob,gCity,bCity,gLat,gLon,bLat,bLon){\n  const rows=[\n    ['লিঙ্গ','কন্যা','বর',''],\n    ['জন্ম তারিখ',_mmFmtDateDots(document.getElementById('girlDOB').value),_mmFmtDateDots(document.getElementById('boyDOB').value),''],\n    ['জন্ম সময়',gTob||'—',bTob||'—',''],\n    ['জন্ম বার',gd.vara||'—',bd.vara||'—',''],\n    ['ইষ্টকাল',gd.ishtakaal||'—',bd.ishtakaal||'—',''],\n    ['জন্মস্থান',gCity||'—',bCity||'—',''],\n    ['অক্ষাংশ',gLat,bLat,''],\n    ['দ্রাঘিমাংশ',gLon,bLon,''],\n    ['তিথি',gd.tithi||'—',bd.tithi||'—','amber'],\n    ['পক্ষ',gd.paksha||'—',bd.paksha||'—',''],\n    ['যোগ',gd.yoga||'—',bd.yoga||'—',''],\n    ['করণ',gd.karana||'—',bd.karana||'—',''],\n    ['পায়া',getPaya(gd.moonLon),getPaya(bd.moonLon),''],\n    ['দশা অবশিষ্ট',getDashaBalance(gd.moonLon,gd.moonNakshatraIndex),getDashaBalance(bd.moonLon,bd.moonNakshatraIndex),''],\n    ['লগ্ন',gd.lagnaRashi||'—',bd.lagnaRashi||'—','green'],\n    ['লগ্ন পতি',getRashiLordName(gd.lagnaRashi),getRashiLordName(bd.lagnaRashi),''],\n    ['রাশি',gd.moonRashi||'—',bd.moonRashi||'—','blue'],\n    ['রাশি পতি',getRashiLordName(gd.moonRashi),getRashiLordName(bd.moonRashi),''],\n    ['সূর্য রাশি',gd.sunRashi||'—',bd.sunRashi||'—',''],\n    ['নক্ষত্র-পদ',`${gd.moonNakshatra||'—'}${gd.moonPada?' - '+gd.moonPada:''}`,`${bd.moonNakshatra||'—'}${bd.moonPada?' - '+bd.moonPada:''}`,''],\n    ['নক্ষত্র পতি',getNakshatraLordName(gd.moonNakshatraIndex),getNakshatraLordName(bd.moonNakshatraIndex),'']\n  ];\n  const body=rows.map(([label,gv,bv,hl])=>`<tr class=\"${hl?'mm-pc-hl-'+hl:''}\"><td>${label}</td><td>${gv}</td><td>${bv}</td></tr>`).join('');\n  return`<div class=\"mm-pc\">\n    <div class=\"mm-pc-title\">📋 কুণ্ডলী বিবরণ</div>\n    <table><thead><tr><th style=\"text-align:left\">কুণ্ডলী বিবরণ</th><th>${gName} (কন্যা)</th><th>${bName} (বর)</th></tr></thead>\n    <tbody>${body}</tbody></table>\n  </div>`;\n}\n\n/* \"অষ্টকূট গুণ মিলন ছক\" — কূট-ভিত্তিক বিবরণ, জীবনক্ষেত্র, সর্বমোট পয়েন্ট, মঙ্গল দোষ ও চূড়ান্ত সিদ্ধান্ত একসাথে, প্রিমিয়াম গোল্ড-বর্ডার ছকে */\nfunction buildAshtakootaPremiumTable(result,gd,bd,gName,bName){\n  const kN=[\"বর্ণ (Varna)\",\"বশ্য (Vasya)\",\"তারা (Tara)\",\"যোনি (Yoni)\",\"গ্রহমৈত্রী (Maitri)\",\"গণ (Gana)\",\"ভকূট (Bhakoot)\",\"নাড়ী (Nadi)\"];\n  const kM=[1,2,3,4,5,6,7,8];\n  const kK=[\"varna\",\"vasu\",\"tara\",\"yoni\",\"grahaMaitri\",\"gana\",\"bhakoota\",\"nadi\"];\n  const kootas=result.kootas||{};\n  function _kv(k,gFld,bFld,gFb,bFb){\n    const ko=kootas[k]||{};\n    return[(ko[gFld]!=null?ko[gFld]:gFb),(ko[bFld]!=null?ko[bFld]:bFb)];\n  }\n  let rows='';\n  kK.forEach((k,i)=>{\n    const _koo=kootas[k];const pts=_koo!=null?(_koo.points!=null?_koo.points:_koo):0;\n    const sc=typeof pts==='number'?pts:0,mx=_koo&&_koo.max!=null?_koo.max:kM[i];\n    let gv=gd.moonNakshatra,bv=bd.moonNakshatra;\n    if(k==='varna'){[gv,bv]=_kv(k,'girlVarna','boyVarna',gd.moonNakshatra,bd.moonNakshatra);}\n    else if(k==='vasu'){const ko=kootas[k]||{};gv=ko.girlVashya===true?'বশ্য':ko.girlVashya===false?'অবশ্য':gd.moonNakshatra;bv=ko.boyVashya===true?'বশ্য':ko.boyVashya===false?'অবশ্য':bd.moonNakshatra;}\n    else if(k==='tara'){[gv,bv]=_kv(k,'taraGirl','taraBoy',gd.moonNakshatra,bd.moonNakshatra);}\n    else if(k==='yoni'){[gv,bv]=_kv(k,'girlYoni','boyYoni',gd.moonNakshatra,bd.moonNakshatra);}\n    else if(k==='grahaMaitri'){[gv,bv]=_kv(k,'girlLord','boyLord',gd.moonRashi,bd.moonRashi);}\n    else if(k==='gana'){[gv,bv]=_kv(k,'girlGana','boyGana',gd.moonNakshatra,bd.moonNakshatra);}\n    else if(k==='bhakoota'){gv=gd.moonRashi;bv=bd.moonRashi;}\n    else if(k==='nadi'){[gv,bv]=_kv(k,'girlNadi','boyNadi',gd.moonNakshatra,bd.moonNakshatra);}\n    const ptCol=sc>=mx*0.75?'#10B981':sc>=mx*0.4?'#F59E0B':'#EF4444';\n    rows+=`<tr><td>${kN[i]}</td><td>${gv}</td><td>${bv}</td><td>${mx}</td><td style=\"color:${ptCol};font-weight:800\">${sc}</td><td style=\"color:#6B7280;font-size:.8rem\">${KOOTA_LIFE_AREAS[k]}</td></tr>`;\n  });\n\n  const total=result.totalPoints!=null?result.totalPoints:0;\n  const max=result.maxScore||36;\n\n  const gm=checkManglikDosha(gd.marsRashi,gd.lagnaRashi);\n  const bm=checkManglikDosha(bd.marsRashi,bd.lagnaRashi);\n  let manglikText;\n  if(gm.hasDosha&&bm.hasDosha)manglikText=`${gName} ও ${bName} দুজনের কুণ্ডলীতেই <strong style=\"color:#EF4444\">মঙ্গল দোষ</strong> রয়েছে — উভয়ের দোষ পরস্পর বাতিল হয়ে যায়, তাই এই ক্ষেত্রে চিন্তার কারণ নেই।`;\n  else if(gm.hasDosha)manglikText=`${gName}-এর কুণ্ডলীতে <strong style=\"color:#EF4444\">মঙ্গল দোষ (Mangal Dosha)</strong> রয়েছে, কিন্তু ${bName}-এর কুণ্ডলীতে নেই — প্রতিকার বিবেচনা করা যেতে পারে।`;\n  else if(bm.hasDosha)manglikText=`${bName}-এর কুণ্ডলীতে <strong style=\"color:#EF4444\">মঙ্গল দোষ (Mangal Dosha)</strong> রয়েছে, কিন্তু ${gName}-এর কুণ্ডলীতে নেই — প্রতিকার বিবেচনা করা যেতে পারে।`;\n  else manglikText=`${gName} ও ${bName} — কারো কুণ্ডলীতেই <strong style=\"color:#10B981\">মঙ্গল দোষ নেই</strong>। এই বিচারে কোনো বাধা নেই।`;\n\n  const verdictIcon=total>=18?'✔️':'⚠️';\n  const verdictColor=total>=18?'#045F46':'#B45309';\n  const verdictBg=total>=18?'#F0FDF4':'#FFFBEB';\n  const verdictBorder=total>=18?'#A7F3D0':'#FDE68A';\n\n  return`<div class=\"mm-pc\">\n    <div class=\"mm-pc-title\">🕉️ অষ্টকূট গুণ মিলন ছক (Ashtakoota)</div>\n    <table><thead><tr><th style=\"text-align:left\">কূট / গুণ</th><th>কন্যা (${gName})</th><th>বর (${bName})</th><th>সর্বোচ্চ</th><th>প্রাপ্ত পয়েন্ট</th><th>জীবনক্ষেত্র</th></tr></thead>\n    <tbody>${rows}</tbody></table>\n    <div class=\"mm-pc-score-banner\">\n      <span style=\"font-weight:800;font-size:1.02rem\">সর্বমোট প্রাপ্ত মিলন পয়েন্ট:</span>\n      <span class=\"mm-pc-score-val\">${total} / ${max}</span>\n    </div>\n    <div class=\"mm-pc-section\">\n      <div class=\"mm-pc-section-head\">🔴 মঙ্গল দোষ / কুজ দোষ বিচার (Mangal Dosha)</div>\n      <div class=\"mm-pc-section-body\">${manglikText}</div>\n    </div>\n    <div class=\"mm-pc-section\">\n      <div class=\"mm-pc-section-head\">চূড়ান্ত সিদ্ধান্ত (Conclusion)</div>\n      <div class=\"mm-pc-section-body mm-pc-conclusion\" style=\"background:${verdictBg};border-color:${verdictBorder};color:${verdictColor}\">${verdictIcon} ${result.verdictFull||result.verdict||''}</div>\n    </div>\n  </div>`;\n}\n\n/* অষ্টকূট মোট গুণের ভিত্তিতে শাস্ত্রীয় শ্লোক ও ব্যাখ্যা — শুধুমাত্র প্রিন্ট/PDF সংস্করণে দেখানো হয় */\nfunction buildShlokaBox(total){\n  const rules=[\n    {max:18,status:'কনিষ্ঠ / অশুভ',shloka:'অষ্টাদশাংশাদ্বলহীনমত্র কনিষ্ঠমেবং প্রবদন্তি সন্তঃ।',source:'জ্যোতির্নিবন্ধ (কূটবিচার)',\n      text:'১৮ গুণের কম বল প্রাপ্ত হলে জ্ঞানী ব্যক্তিরা তাকে কনিষ্ঠ বা অধম মিলন বলেন। এই মিলন বিবাহিত জীবনের সুখ ও স্থায়িত্বের জন্য অনুকূল নয়।'},\n    {max:25,status:'মধ্যম',shloka:'অষ্টাদশ গুণা যত্র বিবাহো মধ্যমো মতঃ।\\nবিংশাবধির্মধ্যমমেব প্রীত্যা।।',source:'মুহূর্ত চিন্তামণি (বিবাহ প্রকরণ) ও জ্যোতির্নিবন্ধ',\n      text:'১৮ থেকে ২৫ গুণের মধ্যে মিলন হলে তাকে মধ্যম মিলন বলা হয়। এটি দাম্পত্য জীবনে সাধারণ সুখ, প্রীতি ও পারিবারিক শান্তি প্রদান করে।'},\n    {max:36,status:'উত্তম',shloka:'অধিকং চোত্তমমাহুরার্যাঃ।।\\nবিংশত্যা শোভনো দিবি।।',source:'জ্যোতির্নিবন্ধ ও মুহূর্ত চিন্তামণি',\n      text:'২৫ থেকে ৩৬ পর্যন্ত গুণ মিলনকে আর্যগণ এবং ঋষিরা সর্বশ্রেষ্ঠ বা উত্তম মিলন বলে আখ্যা দিয়েছেন। এটি অত্যন্ত শুভ, সমৃদ্ধিদায়ক ও দাম্পত্য জীবনে পরম আনন্দের প্রতীক।'}\n  ];\n  const r=rules.find(x=>total<x.max)||rules[rules.length-1];\n  const shlokaHtml=r.shloka.split('\\n').map(l=>`<div>${l}</div>`).join('');\n  return `\n    <div class=\"mm-shloka-title\">📜 শাস্ত্র অনুযায়ী ফলাফল — <strong>${r.status}</strong></div>\n    <div class=\"mm-shloka-text\">${shlokaHtml}</div>\n    <div class=\"mm-shloka-source\">— ${r.source}</div>\n    <div class=\"mm-shloka-explain\">${r.text}</div>`;\n}\n\n/* স্কোর ও মাঙ্গলিক অবস্থা অনুযায়ী ব্যক্তিগতকৃত CTA — কম স্কোরে প্রতিকার পরামর্শ,\n   বেশি স্কোরে শুভ বিবাহ-লগ্ন/মুহূর্ত নির্ধারণের পরামর্শ */\nfunction buildDynamicCTA(pct,gd,bd,gName,bName){\n  const gm=checkManglikDosha(gd.marsRashi,gd.lagnaRashi);\n  const bm=checkManglikDosha(bd.marsRashi,bd.lagnaRashi);\n  const manglikUnmatched=(gm.hasDosha!==bm.hasDosha);\n  let title,msg,btnLabel;\n  if(pct<50){\n    title='⚠️ এই মিলনে কিছু গুণ মিলছে না';\n    msg=`${gName} ও ${bName}-এর কুষ্ঠিতে কিছু কূট মেলেনি এবং/অথবা মাঙ্গলিক দোষ অসমান — শাস্ত্রসম্মত প্রতিকার নিলে এই দোষ অনেকাংশে কাটানো সম্ভব। ড. প্রদ্যুৎ আচার্যের সাথে সরাসরি কথা বলে বিস্তারিত প্রতিকার জেনে নিন।`;\n    btnLabel='🙏 প্রতিকার পরামর্শ নিন';\n  }else if(pct<72||manglikUnmatched){\n    title='🔎 আরও বিস্তারিত বিচার প্রয়োজন';\n    msg=`মাঝারি মিলনের ক্ষেত্রে মাঙ্গলিক দোষ, গ্রহের বলাবল ও অন্যান্য যোগ একসাথে বিচার করা জরুরি। ${manglikUnmatched?'এই জুটির মাঙ্গলিক অবস্থা অসমান — ':''}ব্যক্তিগত পরামর্শে সম্পূর্ণ ছবি স্পষ্ট হবে।`;\n    btnLabel='💬 বিস্তারিত পরামর্শ নিন';\n  }else{\n    /* উচ্চ স্কোরে আর কোনো CTA কার্ড দেখানো হয় না — ফলাফল ট্যাব পরিষ্কার রাখার জন্য */\n    return'';\n  }\n  return`<div style=\"background:linear-gradient(135deg,#fff8f0,#fff3e0);border:1.5px solid #b8860b;border-radius:14px;padding:16px 18px;margin:14px 0;text-align:center\">\n    <div style=\"font-family:var(--fh);color:#7a2e2e;font-weight:700;font-size:1.02rem;margin-bottom:6px\">${title}</div>\n    <div style=\"color:#5a4a3a;font-size:.88rem;line-height:1.7;margin-bottom:12px\">${msg}</div>\n    <a href=\"https://wa.me/919333122768?text=${encodeURIComponent('নমস্কার, '+gName+' ও '+bName+'-এর কুষ্ঠি মিলন (স্কোর '+Math.round(pct/100*36*10)/10+'/36) নিয়ে পরামর্শ চাই।')}\" target=\"_blank\" rel=\"noopener\" style=\"display:inline-flex;align-items:center;gap:8px;background:linear-gradient(135deg,#25d366,#1ea952);color:#fff;border-radius:10px;padding:10px 22px;font-size:.92rem;font-weight:700;text-decoration:none\"><svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 24 24\" width=\"1em\" height=\"1em\" fill=\"currentColor\" style=\"display:inline-block;vertical-align:-0.125em\"><path d=\"M19.05 4.91A9.82 9.82 0 0 0 12.04 2c-5.46 0-9.91 4.45-9.91 9.91c0 1.75.46 3.45 1.32 4.95L2.05 22l5.25-1.38c1.45.79 3.08 1.21 4.74 1.21c5.46 0 9.91-4.45 9.91-9.91c0-2.65-1.03-5.14-2.9-7.01m-7.01 15.24c-1.48 0-2.93-.4-4.2-1.15l-.3-.18l-3.12.82l.83-3.04l-.2-.31a8.26 8.26 0 0 1-1.26-4.38c0-4.54 3.7-8.24 8.24-8.24c2.2 0 4.27.86 5.82 2.42a8.18 8.18 0 0 1 2.41 5.83c.02 4.54-3.68 8.23-8.22 8.23m4.52-6.16c-.25-.12-1.47-.72-1.69-.81c-.23-.08-.39-.12-.56.12c-.17.25-.64.81-.78.97c-.14.17-.29.19-.54.06c-.25-.12-1.05-.39-1.99-1.23c-.74-.66-1.23-1.47-1.38-1.72c-.14-.25-.02-.38.11-.51c.11-.11.25-.29.37-.43s.17-.25.25-.41c.08-.17.04-.31-.02-.43s-.56-1.34-.76-1.84c-.2-.48-.41-.42-.56-.43h-.48c-.17 0-.43.06-.66.31c-.22.25-.86.85-.86 2.07s.89 2.4 1.01 2.56c.12.17 1.75 2.67 4.23 3.74c.59.26 1.05.41 1.41.52c.59.19 1.13.16 1.56.1c.48-.07 1.47-.6 1.67-1.18c.21-.58.21-1.07.14-1.18s-.22-.16-.47-.28\"/></svg> ${btnLabel}</a>\n  </div>`;\n}\n\n/* প্রকৃত গণনাকৃত গ্রহ-অবস্থান অনুযায়ী বিভাগ-ভিত্তিক ব্যক্তিগতকৃত বিশ্লেষণ (collapsible) —\n   অষ্টকূট স্কোর/রায় অপরিবর্তিত থাকে, এটি সম্পূরক ব্যাখ্যা */\nfunction buildNarrativeAnalysis(sections){\n  return sections.map((sec,i)=>`\n    <details ${i===0?'open':''} style=\"background:#fffdf9;border:1px solid #e8d5c0;border-radius:10px;margin-bottom:8px;overflow:hidden;page-break-inside:avoid;break-inside:avoid\">\n      <summary style=\"cursor:pointer;padding:10px 14px;font-weight:700;color:#7a2e2e;font-family:var(--fh);font-size:.92rem\">${sec.title}</summary>\n      <div style=\"padding:0 14px 12px;color:#5a4a3a;font-size:.86rem;line-height:1.75\">\n        ${sec.items.map(it=>`<p style=\"margin:8px 0\">${it}</p>`).join('')}\n      </div>\n    </details>`).join('');\n}\n\n/* সর্বদা উন্মুক্ত (নন-কোলাপসিবল) কার্ড — জ্যোতিষ যোগ ট্যাবের জন্য */\nfunction buildNarrativeAnalysisOpen(sections){\n  return sections.map(sec=>`\n    <div style=\"background:#fffdf9;border:1px solid #e8d5c0;border-radius:10px;margin-bottom:8px;overflow:hidden;page-break-inside:avoid;break-inside:avoid\">\n      <div style=\"padding:10px 14px;font-weight:700;color:#7a2e2e;font-family:var(--fh);font-size:.92rem;border-bottom:1px solid #f0e4d4\">${sec.title}</div>\n      <div style=\"padding:10px 14px 12px;color:#5a4a3a;font-size:.86rem;line-height:1.75\">\n        ${sec.items.map(it=>`<p style=\"margin:8px 0\">${it}</p>`).join('')}\n      </div>\n    </div>`).join('');\n}\n\nfunction buildMatchHTMLReport(result,gName,bName){\n  const kootaDefs=[\n    {name:'বর্ণকূট',fpKey:'varna',koKey:'varna',max:1,color:'#b8860b'},\n    {name:'বশ্যকূট',fpKey:'vashya',koKey:'vasu',max:2,color:'#7a2e2e'},\n    {name:'তারাকূট',fpKey:'tara',koKey:'tara',max:3,color:'#1565c0'},\n    {name:'যোনিকূট',fpKey:'yoni',koKey:'yoni',max:4,color:'#2e7d32'},\n    {name:'গ্রহমৈত্রীকূট',fpKey:'grahaMaitri',koKey:'grahaMaitri',max:5,color:'#6b21a8'},\n    {name:'গণমৈত্রীকূট',fpKey:'gana',koKey:'gana',max:6,color:'#c62828'},\n    {name:'রাশিকূট (ভকূট)',fpKey:'rashi',koKey:'bhakoota',max:7,color:'#00838f'},\n    {name:'ত্রিনাড়ীকূট',fpKey:'nadi',koKey:'nadi',max:8,color:'#4e342e'},\n  ];\n  const kk=result.kootas||{};\n  const fp=result.fullPredictions||{};\n  let html='';\n  if(result.verdictFull)html+=`<div style=\"margin-bottom:14px;padding:11px 14px;background:#fdf6e3;border-radius:8px;border-left:4px solid #b8860b;font-size:.92rem;font-weight:600;color:#5c3d2e\">${result.verdictFull}</div>`;\n  kootaDefs.forEach(function(k){\n    const ko=kk[k.koKey]||{};\n    const pts=(ko.points!=null?ko.points:0);\n    const icon=pts===k.max?'✅':pts===0?'❌':'⚠️';\n    const full=fp[k.fpKey]||'';\n    if(!full)return;\n    html+=`<div style=\"margin-bottom:12px;padding:11px 13px;background:#fdf8f4;border-radius:8px;border-left:4px solid ${k.color};page-break-inside:avoid;break-inside:avoid\"><div style=\"font-weight:700;color:${k.color};font-size:.9rem;margin-bottom:5px\">${icon} ${k.name} — ${pts}/${k.max} গুণ</div><div style=\"font-size:.87rem;color:#3a2a1a;line-height:1.75\">${full}</div></div>`;\n  });\n  const mg=result.manglik||{};\n  html+=`<div style=\"margin-bottom:12px;padding:11px 13px;background:#fff8f8;border-radius:8px;border-left:4px solid #c0392b;page-break-inside:avoid;break-inside:avoid\"><div style=\"font-weight:700;color:#c0392b;font-size:.9rem;margin-bottom:7px\">🔴 মাঙ্গলিক দোষ বিচার</div><div style=\"margin-bottom:5px;font-size:.87rem;color:#3a2a1a\"><strong>কন্যা (${gName}):</strong> ${(mg.girl&&mg.girl.full)||'—'}</div><div style=\"font-size:.87rem;color:#3a2a1a\"><strong>বর (${bName}):</strong> ${(mg.boy&&mg.boy.full)||'—'}</div></div>`;\n  if(result.remedies&&result.remedies.length){\n    html+=`<div style=\"margin-bottom:12px;padding:11px 13px;background:#f0faf0;border-radius:8px;border-left:4px solid #2e7d32\"><div style=\"font-weight:700;color:#2e7d32;font-size:.9rem;margin-bottom:7px\">🙏 প্রতিকার</div>${result.remedies.map(r=>`<div style=\"font-size:.87rem;color:#3a2a1a;margin-bottom:5px;line-height:1.7\">${r}</div>`).join('')}</div>`;\n  }\n  html+=`<div style=\"text-align:center;margin-top:10px;padding:9px;background:#fdf0e8;border-radius:8px;font-size:.88rem;color:#7a2e2e;font-weight:600\">🕉️ শুভম্ ভবতু &nbsp;·&nbsp; মাঙ্গল্যম্ ভবতু</div>`;\n  return html;\n}\n\n/* ফর্ম ভ্যালিডেশন — খালি/ভুল ফিল্ড ইনলাইনে হাইলাইট ও বার্তা দেখায় */\nfunction _mmValidate(){\n  const fields=[\n    ['girlDOB','জন্ম তারিখ','মেয়ের'],['girlTOB','জন্ম সময়','মেয়ের'],\n    ['girlLat','অক্ষাংশ','মেয়ের'],['girlLon','দ্রাঘিমাংশ','মেয়ের'],\n    ['boyDOB','জন্ম তারিখ','ছেলের'],['boyTOB','জন্ম সময়','ছেলের'],\n    ['boyLat','অক্ষাংশ','ছেলের'],['boyLon','দ্রাঘিমাংশ','ছেলের']\n  ];\n  let firstInvalid=null,msgs=[];\n  const _focusMap={girlDOB:'girlDobDay',girlTOB:'girlTobHour',boyDOB:'boyDobDay',boyTOB:'boyTobHour'};\n  fields.forEach(([id,label,who])=>{\n    const el=document.getElementById(id);\n    if(!el)return;\n    const v=el.value;\n    const invalid=(v===''||v==null)||(el.type==='number'&&isNaN(parseFloat(v)));\n    const focusEl=document.getElementById(_focusMap[id])||el;\n    focusEl.style.borderColor=invalid?'#c62828':'';\n    if(invalid){\n      if(!firstInvalid)firstInvalid=focusEl;\n      msgs.push(who+' '+label);\n    }\n  });\n  return{valid:!msgs.length,firstInvalid,msgs};\n}\n\nfunction _mmShowFormError(msg){\n  let box=document.getElementById('mmFormError');\n  if(!box){\n    box=document.createElement('div');\n    box.id='mmFormError';\n    box.setAttribute('role','alert');\n    box.style.cssText='background:#fff5f5;border:1px solid #c62828;color:#b71c1c;border-radius:8px;padding:10px 14px;margin:0 auto 16px;max-width:360px;font-size:.85rem;text-align:center;font-weight:600';\n    const btn=document.querySelector('.calc-btn');\n    btn.parentNode.insertBefore(box,btn);\n  }\n  if(msg){box.textContent=msg;box.style.display='block';}\n  else box.style.display='none';\n}\n\nfunction runMatchCalc(){\n  const v=_mmValidate();\n  if(!v.valid){\n    _mmShowFormError('⚠️ অনুগ্রহ করে এই তথ্যগুলো দিন: '+v.msgs.join(', '));\n    if(v.firstInvalid)v.firstInvalid.focus();\n    return;\n  }\n  _mmShowFormError(null);\n\n  const btn=document.querySelector('.calc-btn');\n  const origHTML=btn.innerHTML;\n  btn.disabled=true;\n  btn.setAttribute('aria-busy','true');\n  btn.innerHTML='⏳ গণনা হচ্ছে…';\n  /* ভারী VSOP87 গণনার সময় UI ফ্রিজ মনে না হওয়ার জন্য সংক্ষিপ্ত বিলম্ব দিয়ে স্পিনার দেখানো */\n  setTimeout(function(){\n    try{\n      _mmRunCalculation();\n    }finally{\n      btn.disabled=false;\n      btn.removeAttribute('aria-busy');\n      btn.innerHTML=origHTML;\n    }\n  },30);\n}\n\nfunction _mmRunCalculation(){\n  const girlTZ=parseFloat(document.getElementById('girlTZ').value)||5.5;\n  const boyTZ=parseFloat(document.getElementById('boyTZ').value)||5.5;\n  const gd=getPlanetData(document.getElementById('girlDOB').value,document.getElementById('girlTOB').value,parseFloat(document.getElementById('girlLat').value),parseFloat(document.getElementById('girlLon').value),girlTZ);\n  const bd=getPlanetData(document.getElementById('boyDOB').value,document.getElementById('boyTOB').value,parseFloat(document.getElementById('boyLat').value),parseFloat(document.getElementById('boyLon').value),boyTZ);\n  if(!gd||!bd){_mmShowFormError('⚠️ অনুগ্রহ করে উভয়ের সম্পূর্ণ তথ্য দিন।');return;}\n\n  const result=calculateMatchMaking(gd,bd);\n  const gName=document.getElementById('girlName').value||\"কন্যা\";\n  const bName=document.getElementById('boyName').value||\"বর\";\n  const gCity=document.getElementById('girlCity').value;\n  const bCity=document.getElementById('boyCity').value;\n  document.getElementById('girlBirthInfoDiv').innerHTML=buildBirthInfo(gName,document.getElementById('girlDOB').value,document.getElementById('girlTOB').value,gCity,'#c2185b');\n  document.getElementById('boyBirthInfoDiv').innerHTML=buildBirthInfo(bName,document.getElementById('boyDOB').value,document.getElementById('boyTOB').value,bCity,'#1565c0');\n\n  document.getElementById('kundaliDetailsTableDiv').innerHTML=buildKundaliDetailsTable(\n    gd,bd,gName,bName,\n    document.getElementById('girlTOB').value,document.getElementById('boyTOB').value,\n    gCity,bCity,\n    document.getElementById('girlLat').value,document.getElementById('girlLon').value,\n    document.getElementById('boyLat').value,document.getElementById('boyLon').value\n  );\n  document.getElementById('ashtakootaPremiumDiv').innerHTML=buildAshtakootaPremiumTable(result,gd,bd,gName,bName);\n  const total=result.totalPoints||result.totalScore||0;\n  const pct=(total/36)*100;\n  const col=pct>=72?'#2e7d32':pct>=50?'#f57c00':'#c62828';\n  const verdict=pct>=72?'✅ মিলন শুভ':pct>=50?'⚠️ মিলন মধ্যম':'❌ মিলন অশুভ';\n\n  document.getElementById('scoreHero').innerHTML=`\n    <div style=\"font-size:.95rem;color:#5c3d2e;margin-bottom:4px\"><span style=\"color:#c2185b\">কন্যা: <strong>${gName}</strong></span> &nbsp;💑&nbsp; <span style=\"color:#1565c0\">বর: <strong>${bName}</strong></span></div>\n    <div class=\"score-number\" style=\"color:${col}\">${total}<span style=\"font-size:1.5rem;color:#999\">/36</span></div>\n    <div class=\"score-label\">অষ্টকূট মোট নম্বর</div>\n    <div class=\"score-bar\"><div class=\"score-fill\" style=\"width:${pct}%;background:${col}\"></div></div>\n    <div class=\"verdict\" style=\"color:${col}\">${verdict}</div>\n    <div style=\"display:flex;gap:10px;justify-content:center;margin-top:14px;flex-wrap:wrap\">\n      <button onclick=\"goToKundali('girl')\" style=\"background:linear-gradient(135deg,#c2185b,#e91e8c);color:#fff;border:none;padding:9px 18px;border-radius:9px;font-size:.88rem;font-weight:700;cursor:pointer;font-family:inherit\">📜 ${gName}–এর কুষ্ঠি দেখুন</button>\n      <button onclick=\"goToKundali('boy')\" style=\"background:linear-gradient(135deg,#1565c0,#1976d2);color:#fff;border:none;padding:9px 18px;border-radius:9px;font-size:.88rem;font-weight:700;cursor:pointer;font-family:inherit\">📜 ${bName}–এর কুষ্ঠি দেখুন</button>\n      <a href=\"${'https://wa.me/?text='+encodeURIComponent('💑 কুষ্ঠি মিলন ফলাফল\\\\n'+gName+' ও '+bName+': '+total+'/36 — '+verdict.replace(/[✅⚠️❌]/g,'').trim()+'\\\\n\\\\nবিনামূল্যে নিজের কুষ্ঠি মিলন দেখুন:\\\\nhttps://myastrology.in/match-making')}\" target=\"_blank\" rel=\"noopener\" style=\"background:linear-gradient(135deg,#25d366,#1ea952);color:#fff;border:none;padding:9px 18px;border-radius:9px;font-size:.88rem;font-weight:700;text-decoration:none;display:inline-flex;align-items:center;gap:6px;font-family:inherit\">📤 ফলাফল শেয়ার করুন</a>\n    </div>`;\n\n  document.getElementById('mmShlokaBox').innerHTML=buildShlokaBox(total);\n\n  document.getElementById('mmDynamicCTA').innerHTML=buildDynamicCTA(pct,gd,bd,gName,bName);\n\n  // চার্ট আঁকো\n  if(gd.planets){\n    const gNavPlanets=gd.planets.map(p=>({name:p.name,lon:getNavamshaRashi(p.lon)*30}));\n    const gNavLagnaIdx=getNavamshaRashi(gd.planets[0].lon);\n    drawMMChart('girlD1Labels','girlD1Planets',gd.planets,gd.lagnaIdx,true);\n    drawMMChart('girlD9Labels','girlD9Planets',gNavPlanets,gNavLagnaIdx);\n    buildPlanetTable('girlPlanetTbody',gd.planets,gd.lagnaIdx);\n  }\n  if(bd.planets){\n    const bNavPlanets=bd.planets.map(p=>({name:p.name,lon:getNavamshaRashi(p.lon)*30}));\n    const bNavLagnaIdx=getNavamshaRashi(bd.planets[0].lon);\n    drawMMChart('boyD1Labels','boyD1Planets',bd.planets,bd.lagnaIdx,true);\n    drawMMChart('boyD9Labels','boyD9Planets',bNavPlanets,bNavLagnaIdx);\n    buildPlanetTable('boyPlanetTbody',bd.planets,bd.lagnaIdx);\n  }\n\n  const kN=[\"বর্ণ\",\"বশ্য\",\"তারা\",\"যোনি\",\"গ্রহমৈত্রী\",\"গণ\",\"ভকূট\",\"নাড়ী\"];\n  const kM=[1,2,3,4,5,6,7,8];\n  const kK=[\"varna\",\"vasu\",\"tara\",\"yoni\",\"grahaMaitri\",\"gana\",\"bhakoota\",\"nadi\"];\n  const kootas=result.kootas||{};\n  function _kv(k,gFld,bFld,gFb,bFb){\n    const ko=kootas[k]||{};\n    return[(ko[gFld]!=null?ko[gFld]:gFb),(ko[bFld]!=null?ko[bFld]:bFb)];\n  }\n  let rows='';\n  kK.forEach((k,i)=>{\n    const _koo=kootas[k];const pts=_koo!=null?(_koo.points!=null?_koo.points:_koo):0;\n    const sc=typeof pts==='number'?pts:0,mx=kM[i];\n    const cls=sc>=mx*0.75?'good':sc>=mx*0.4?'avg':'bad';\n    const st=sc>=mx*0.75?'✅ শুভ':sc>=mx*0.4?'⚠️ মধ্যম':'❌ অশুভ';\n    let gv=gd.moonNakshatra,bv=bd.moonNakshatra;\n    if(k==='varna'){[gv,bv]=_kv(k,'girlVarna','boyVarna',gd.moonNakshatra,bd.moonNakshatra);}\n    else if(k==='vasu'){const ko=kootas[k]||{};gv=ko.girlVashya===true?'বশ্য':ko.girlVashya===false?'অবশ্য':gd.moonNakshatra;bv=ko.boyVashya===true?'বশ্য':ko.boyVashya===false?'অবশ্য':bd.moonNakshatra;}\n    else if(k==='tara'){[gv,bv]=_kv(k,'taraGirl','taraBoy',gd.moonNakshatra,bd.moonNakshatra);}\n    else if(k==='yoni'){[gv,bv]=_kv(k,'girlYoni','boyYoni',gd.moonNakshatra,bd.moonNakshatra);}\n    else if(k==='grahaMaitri'){[gv,bv]=_kv(k,'girlLord','boyLord',gd.moonRashi,bd.moonRashi);}\n    else if(k==='gana'){[gv,bv]=_kv(k,'girlGana','boyGana',gd.moonNakshatra,bd.moonNakshatra);}\n    else if(k==='bhakoota'){gv=gd.moonRashi;bv=bd.moonRashi;}\n    else if(k==='nadi'){[gv,bv]=_kv(k,'girlNadi','boyNadi',gd.moonNakshatra,bd.moonNakshatra);}\n    rows+=`<tr><td>${kN[i]}</td><td>${gv}</td><td>${bv}</td><td style=\"text-align:center\">${mx}</td><td style=\"text-align:center\"><span class=\"pts ${cls}\">${sc}</span></td><td>${st}</td></tr>`;\n  });\n  rows+=`<tr style=\"font-weight:700;background:#fdf8f2\"><td colspan=\"4\">মোট</td><td style=\"text-align:center;color:${col}\">${total}/36</td><td style=\"color:${col}\">${verdict}</td></tr>`;\n  document.getElementById('kootaTbody').innerHTML=rows;\n\n  const gm=checkManglikDosha(gd.marsRashi,gd.lagnaRashi);\n  const bm=checkManglikDosha(bd.marsRashi,bd.lagnaRashi);\n  let mh='';\n  mh+=`<div class=\"manglik-box ${gm.hasDosha?'manglik-yes':'manglik-no'}\">${gm.hasDosha?'🔴':'🟢'} ${gName}: ${gm.hasDosha?'মাঙ্গলিক দোষ আছে — মঙ্গল '+gd.marsRashi+' রাশিতে':'মাঙ্গলিক দোষ নেই'}</div>`;\n  mh+=`<div class=\"manglik-box ${bm.hasDosha?'manglik-yes':'manglik-no'}\">${bm.hasDosha?'🔴':'🟢'} ${bName}: ${bm.hasDosha?'মাঙ্গলিক দোষ আছে — মঙ্গল '+bd.marsRashi+' রাশিতে':'মাঙ্গলিক দোষ নেই'}</div>`;\n  if(gm.hasDosha&&bm.hasDosha)mh+='<div class=\"manglik-box manglik-cancel\">✨ উভয়ই মাঙ্গলিক — দোষ পরস্পর বাতিল হয়ে যায়</div>';\n  document.getElementById('manglikDiv').innerHTML=mh;\n\n  // কালসর্প যোগ বিচার\n  const gk=checkKaalSarpaYoga(gd.planets);\n  const bk=checkKaalSarpaYoga(bd.planets);\n  let kh='';\n  kh+=`<div class=\"kaal-box ${gk.hasYoga?'kaal-yes':'kaal-no'}\">${gk.hasYoga?'🐍':'🟢'} ${gName}: ${gk.hasYoga?'কালসর্প যোগ আছে'+(gk.type?' ('+gk.type+')':''):'কালসর্প যোগ নেই'}</div>`;\n  kh+=`<div class=\"kaal-box ${bk.hasYoga?'kaal-yes':'kaal-no'}\">${bk.hasYoga?'🐍':'🟢'} ${bName}: ${bk.hasYoga?'কালসর্প যোগ আছে'+(bk.type?' ('+bk.type+')':''):'কালসর্প যোগ নেই'}</div>`;\n  if(gk.hasYoga&&bk.hasYoga)kh+='<div class=\"kaal-box kaal-note\">ℹ️ উভয়ের কুণ্ডলীতেই কালসর্প যোগ বিদ্যমান — দুজনের জীবনেই একই ধরনের গ্রহ-প্রভাব সক্রিয় থাকায় বৈবাহিক জীবনে একে অপরের প্রতিকার-অভিজ্ঞতা সহায়ক হতে পারে। এটি দোষ \"বাতিল\" নয়, বরং উভয় কুণ্ডলীর সাদৃশ্য — বিস্তারিত বিচারের জন্য জ্যোতিষীর পরামর্শ নিন।</div>';\n  else if((gm.hasDosha&&bk.hasYoga)||(bm.hasDosha&&gk.hasYoga))kh+='<div class=\"kaal-box kaal-note\">ℹ️ একজনের মাঙ্গলিক দোষ ও অপরজনের কালসর্প যোগ — দুটি ভিন্ন প্রকৃতির যোগ একসাথে থাকায় সম্মিলিত প্রতিকার ও বিবাহের শুভ তিথি নির্ধারণে বিশেষজ্ঞ পরামর্শ নেওয়া উচিত।</div>';\n  document.getElementById('kaalSarpaDiv').innerHTML=kh;\n\n  // ছেলে/মেয়ের ব্যক্তিগত কুন্ডলি — CTA কার্ড\n  document.getElementById('girlKundaliCtaDiv').innerHTML=`\n    <div class=\"section-title\">👰 ${gName}–এর ব্যক্তিগত কুন্ডলি</div>\n    <p style=\"color:#5c3d2e;font-size:.92rem;line-height:1.8;margin-bottom:6px\">\n      লগ্ন: <strong>${gd.lagnaRashi||'—'}</strong> &nbsp;·&nbsp; রাশি: <strong>${gd.moonRashi||'—'}</strong> &nbsp;·&nbsp; নক্ষত্র: <strong>${gd.moonNakshatra||'—'}${gd.moonPada?' ('+gd.moonPada+'য় পাদ)':''}</strong>\n    </p>\n    <p style=\"color:#8a7458;font-size:.85rem;line-height:1.7;margin-bottom:14px\">সম্পূর্ণ গ্রহ অবস্থান, দশা, দোষ ও বিস্তারিত প্রেডিকশন-সহ ${gName}–এর পূর্ণ জন্মকুণ্ডলি দেখতে নিচের বাটনে ক্লিক করুন।</p>\n    <button onclick=\"goToKundali('girl')\" style=\"background:linear-gradient(135deg,#c2185b,#e91e8c);color:#fff;border:none;padding:10px 22px;border-radius:9px;font-size:.9rem;font-weight:700;cursor:pointer;font-family:inherit\">📜 ${gName}–এর সম্পূর্ণ কুষ্ঠি দেখুন</button>`;\n  document.getElementById('boyKundaliCtaDiv').innerHTML=`\n    <div class=\"section-title\">🤵 ${bName}–এর ব্যক্তিগত কুন্ডলি</div>\n    <p style=\"color:#5c3d2e;font-size:.92rem;line-height:1.8;margin-bottom:6px\">\n      লগ্ন: <strong>${bd.lagnaRashi||'—'}</strong> &nbsp;·&nbsp; রাশি: <strong>${bd.moonRashi||'—'}</strong> &nbsp;·&nbsp; নক্ষত্র: <strong>${bd.moonNakshatra||'—'}${bd.moonPada?' ('+bd.moonPada+'য় পাদ)':''}</strong>\n    </p>\n    <p style=\"color:#8a7458;font-size:.85rem;line-height:1.7;margin-bottom:14px\">সম্পূর্ণ গ্রহ অবস্থান, দশা, দোষ ও বিস্তারিত প্রেডিকশন-সহ ${bName}–এর পূর্ণ জন্মকুণ্ডলি দেখতে নিচের বাটনে ক্লিক করুন।</p>\n    <button onclick=\"goToKundali('boy')\" style=\"background:linear-gradient(135deg,#1565c0,#1976d2);color:#fff;border:none;padding:10px 22px;border-radius:9px;font-size:.9rem;font-weight:700;cursor:pointer;font-family:inherit\">📜 ${bName}–এর সম্পূর্ণ কুষ্ঠি দেখুন</button>`;\n\n  document.getElementById('reportText').innerHTML=buildMatchHTMLReport(result,gName,bName);\n  document.getElementById('narrativeAnalysisDiv').innerHTML=buildNarrativeAnalysis(generateNarrativeAnalysis(gd,bd,result).filter(function(sec){return sec.key==='emotionalBonding';}));\n  document.getElementById('yogaNarrativeDiv').innerHTML=buildNarrativeAnalysisOpen(generateNarrativeAnalysis(gd,bd,result).filter(function(sec){return sec.key!=='emotionalBonding';}));\n\n  /* প্রিন্ট/PDF কভার পেজের জন্য সর্বশেষ গণনার ফলাফল সংরক্ষণ */\n  window._mmLastData={gd,bd,result,gName,bName};\n\n  const ra=document.getElementById('resultsArea');\n  ra.style.display='block';\n  const pdfBtn=document.getElementById('mmPdfBtn');\n  if(pdfBtn)pdfBtn.style.display='block';\n  // Hide form, show \"back to form\" button\n  const mmIn=document.getElementById('mmInputSection');\n  if(mmIn)mmIn.style.display='none';\n  const mmEdit=document.getElementById('mmEditBtn');\n  if(mmEdit)mmEdit.style.display='block';\n  _mmHideSeoFaq();\n  _mmActivatePanel('birth');\n  ra.scrollIntoView({behavior:'smooth'});\n}\n\n/* ══ ট্যাব / মেনু বার ══ */\nfunction _mmActivatePanel(tab){\n  const fh=document.getElementById('mmFormHeader');\n  if(fh)fh.classList.toggle('mm-hide', tab!=='form');\n  document.querySelectorAll('#resultsArea > .mm-tab-panel').forEach(function(p){\n    p.classList.toggle('active', p.id==='mmPanel-'+tab);\n  });\n  document.querySelectorAll('.mm-tab-btn').forEach(function(btn){\n    const isActive=btn.getAttribute('data-tab')===tab;\n    btn.classList.toggle('active', isActive);\n    btn.setAttribute('aria-selected', isActive?'true':'false');\n  });\n}\nfunction _mmSwitchTab(tab){\n  if(tab==='form'){showMMForm();return;}\n  const ra=document.getElementById('resultsArea');\n  if(!ra||ra.style.display==='none'){\n    alert('প্রথমে জন্ম বিবরণ দিয়ে \"মিলন গণনা করুন\" বাটনে ক্লিক করুন।');\n    return;\n  }\n  const mmIn=document.getElementById('mmInputSection');\n  if(mmIn)mmIn.style.display='none';\n  const mmEdit=document.getElementById('mmEditBtn');\n  if(mmEdit)mmEdit.style.display='block';\n  _mmHideSeoFaq();\n  _mmActivatePanel(tab);\n  ra.scrollIntoView({behavior:'smooth'});\n  /* প্রিমিয়াম/স্পেশাল ট্যাবে ক্লিক করলে সরাসরি বিস্তারিত পপআপ খুলবে */\n  if(tab==='premium')_mmOpenBenefits('Prem');\n  else if(tab==='special')_mmOpenBenefits('Spec');\n}\n\n/* \"কুষ্ঠি মিলন গণনা করুন\" বাটনের নিচে — অন্যান্য সার্ভিস পেজে (ছেলের তথ্য সহ) যাওয়ার লিংক */\nfunction _mmGoTo(target){\n  const name=(document.getElementById('boyName').value||'').trim();\n  const dob=document.getElementById('boyDOB').value;\n  const tob=document.getElementById('boyTOB').value;\n  const lat=document.getElementById('boyLat').value;\n  const lon=document.getElementById('boyLon').value;\n  const city=(document.getElementById('boyCity').value||'').trim();\n  const tz=document.getElementById('boyTZ').value||'5.5';\n  const page=target==='namakaran'?'namakaran.html':'kundali.html';\n  if(dob&&tob&&lat&&lon){\n    const params=new URLSearchParams({name,dob,tob,lat,lon,city,gender:'male',tz,auto:'1'});\n    window.location.href=page+'?'+params.toString();\n  } else {\n    window.location.href=page;\n  }\n}\n\n/* \"কুষ্ঠি মিলন গণনা করুন\" বাটনের নিচের প্রিমিয়াম/স্পেশাল কুইক-লিংক —\n   গণনা না করা থাকলে প্রথমে গণনা করে তারপর সরাসরি বিস্তারিত পপআপ খোলে */\nfunction _mmQuickBenefits(kind){\n  const ra=document.getElementById('resultsArea');\n  if(!ra||ra.style.display==='none'){\n    const v=_mmValidate();\n    if(!v.valid){\n      _mmShowFormError('⚠️ অনুগ্রহ করে এই তথ্যগুলো দিন: '+v.msgs.join(', '));\n      if(v.firstInvalid)v.firstInvalid.focus();\n      return;\n    }\n    _mmShowFormError(null);\n    _mmRunCalculation();\n  }\n  _mmSwitchTab(kind==='Prem'?'premium':'special');\n}\n\nfunction _mmHideSeoFaq(){\n  var s=document.getElementById('seoSection');if(s)s.style.display='none';\n  var f=document.getElementById('faqSection');if(f)f.style.display='none';\n}\nfunction _mmShowSeoFaq(){\n  var s=document.getElementById('seoSection');if(s)s.style.display='';\n  var f=document.getElementById('faqSection');if(f)f.style.display='';\n}\nfunction showMMForm(){\n  const mmIn=document.getElementById('mmInputSection');\n  if(mmIn)mmIn.style.display='block';\n  const mmEdit=document.getElementById('mmEditBtn');\n  if(mmEdit)mmEdit.style.display='none';\n  const mmPdf=document.getElementById('mmPdfBtn');\n  if(mmPdf)mmPdf.style.display='none';\n  const ra=document.getElementById('resultsArea');\n  if(ra)ra.style.display='none';\n  _mmShowSeoFaq();\n  _mmActivatePanel('form');\n  window.scrollTo({top:0,behavior:'smooth'});\n}\n\n/* শহর অনুসন্ধান */\nconst COUNTRY_TZ_MM={'ভারত':5.5,'বাংলাদেশ':6.0,'নেপাল':5.75,'পাকিস্তান':5.0,\n  'শ্রীলঙ্কা':5.5,'মিয়ানমার':6.5,'থাইল্যান্ড':7.0,'ভিয়েতনাম':7.0,\n  'সিঙ্গাপুর':8.0,'মালয়েশিয়া':8.0,'চীন':8.0,'হংকং':8.0,'জাপান':9.0,'কোরিয়া':9.0,\n  'সংযুক্ত আরব আমিরাত':4.0,'আরব আমিরাত':4.0,'ওমান':4.0,'সৌদি আরব':3.0,'কাতার':3.0,'কুয়েত':3.0,'বাহরাইন':3.0,\n  'ইরান':3.5,'তুরস্ক':3.0,'মিশর':2.0,'কেনিয়া':3.0,'দক্ষিণ আফ্রিকা':2.0,\n  'যুক্তরাজ্য':0.0,'আয়ারল্যান্ড':0.0,'পর্তুগাল':0.0,\n  'ফ্রান্স':1.0,'জার্মানি':1.0,'ইতালি':1.0,'স্পেন':1.0,\n  'যুক্তরাষ্ট্র':-5.0,'কানাডা':-5.0,'অস্ট্রেলিয়া':10.0,'নিউজিল্যান্ড':12.0};\n\nfunction setupCitySearch(inputId,suggId,latId,lonId,tzId){\n  const inp=document.getElementById(inputId),sugg=document.getElementById(suggId);\n  if(!inp||!sugg)return;\n  inp.addEventListener('input',function(){\n    const q=this.value.trim().toLowerCase();sugg.innerHTML='';\n    if(q.length<2){sugg.style.display='none';return;}\n    const cd=(typeof CITY_DB!=='undefined')?CITY_DB:[];\n    const m=cd.filter(c=>(c.n||'').toLowerCase().startsWith(q)).slice(0,8);\n    if(!m.length){sugg.style.display='none';return;}\n    m.forEach(c=>{\n      const nm=c.n,la=c.lat,lo=c.lng,country=c.country||'';\n      const li=document.createElement('li');li.textContent=nm+(country?' ('+country+')':'');\n      li.addEventListener('click',()=>{\n        inp.value=nm;\n        document.getElementById(latId).value=parseFloat(la).toFixed(4);\n        document.getElementById(lonId).value=parseFloat(lo).toFixed(4);\n        /* Auto-set timezone */\n        if(tzId&&COUNTRY_TZ_MM[country]!==undefined){\n          const tzSel=document.getElementById(tzId);\n          if(tzSel){\n            const tz=COUNTRY_TZ_MM[country];\n            let best=null,bestDiff=99;\n            Array.from(tzSel.options).forEach(o=>{const d=Math.abs(parseFloat(o.value)-tz);if(d<bestDiff){bestDiff=d;best=o.value;}});\n            if(best!==null)tzSel.value=best;\n          }\n        }\n        sugg.style.display='none';\n      });\n      sugg.appendChild(li);\n    });\n    sugg.style.display='block';\n  });\n  document.addEventListener('click',e=>{if(!inp.contains(e.target))sugg.style.display='none';});\n}\nvar _MM_RZP_KEY='rzp_live_SN8p6DJxPYFVL1';\nvar _MM_PROMO='RUDRA51';\n\n/* prompt()/alert() এর বদলে কাস্টম মডাল — প্রোমো কোড ইনপুট */\nfunction _mmPromoModal(onDone){\n  const overlay=document.createElement('div');\n  overlay.setAttribute('role','dialog');\n  overlay.setAttribute('aria-modal','true');\n  overlay.setAttribute('aria-labelledby','mmPromoTitle');\n  overlay.style.cssText='position:fixed;inset:0;background:rgba(30,15,5,.55);display:flex;align-items:center;justify-content:center;z-index:9999;padding:16px';\n  overlay.innerHTML=`\n    <div style=\"background:#fffaf4;border-radius:14px;max-width:360px;width:100%;padding:22px;box-shadow:0 12px 40px rgba(0,0,0,.3);font-family:inherit\">\n      <div id=\"mmPromoTitle\" style=\"font-weight:800;color:#7a2e2e;font-size:1.05rem;margin-bottom:6px;font-family:var(--fh)\">🎟️ প্রোমো কোড</div>\n      <div style=\"font-size:.85rem;color:#5c3d2e;margin-bottom:12px\">প্রোমো কোড থাকলে লিখুন, নইলে সরাসরি পেমেন্টে যান।</div>\n      <input type=\"text\" id=\"mmPromoInput\" placeholder=\"প্রোমো কোড (যদি থাকে)\" style=\"width:100%;padding:10px 12px;border:1px solid #e0c8b0;border-radius:8px;font-size:.95rem;font-family:inherit;margin-bottom:14px;box-sizing:border-box\">\n      <div style=\"display:flex;gap:10px;flex-wrap:wrap\">\n        <button id=\"mmPromoApply\" style=\"flex:1;background:linear-gradient(135deg,#b8860b,#7a5d2e);color:#fff;border:none;padding:10px 14px;border-radius:8px;font-weight:700;cursor:pointer;font-family:inherit;font-size:.9rem\">প্রয়োগ করুন</button>\n        <button id=\"mmPromoSkip\" style=\"flex:1;background:#7a2e2e;color:#fff;border:none;padding:10px 14px;border-radius:8px;font-weight:700;cursor:pointer;font-family:inherit;font-size:.9rem\">পেমেন্টে যান</button>\n      </div>\n      <button id=\"mmPromoClose\" aria-label=\"বন্ধ করুন\" style=\"margin-top:12px;width:100%;background:none;border:none;color:#9a7b3a;font-size:.85rem;cursor:pointer;font-family:inherit\">✕ বাতিল করুন</button>\n      <div style=\"margin-top:14px;padding:10px 12px;background:#fdf3e0;border:1px dashed #d9b76a;border-radius:8px;font-size:.74rem;color:#7a5d2e;line-height:1.7\">\n        💾 <strong>PDF সংরক্ষণের নিয়ম:</strong> পেমেন্ট/প্রোমো প্রয়োগের পর নতুন ট্যাবে রিপোর্ট খুলবে — সেখানে নিচের <strong>\"💾 PDF সংরক্ষণ করুন\"</strong> বাটনে ক্লিক করুন, তারপর প্রিন্ট উইন্ডোতে Destination/Printer-এ <strong>Save as PDF</strong> বেছে <strong>Save</strong>-এ ক্লিক করুন।<br><br>\n        ⏳ রিপোর্ট বড় হওয়ায় <strong>প্রিভিউ আসতে ২-৫ মিনিট পর্যন্ত সময় লাগতে পারে</strong> — ধৈর্য ধরে অপেক্ষা করুন, এই সময় <strong>ব্যাক বাটনে চাপবেন না বা ট্যাব বন্ধ করবেন না</strong>।<br><br>\n        📶 ভালো ওয়াইফাই/ইন্টারনেট সংযোগে এবং ফোন চার্জ থাকা অবস্থায় চেষ্টা করুন। Save এ সমস্যা হলে, লিংকটি <strong>Chrome ব্রাউজারে</strong> খুলে আবার চেষ্টা করুন (অন্য অ্যাপের ভেতরের ব্রাউজারে Save as PDF কাজ না করতে পারে)।\n      </div>\n    </div>`;\n  document.body.appendChild(overlay);\n  const input=overlay.querySelector('#mmPromoInput');\n  input.focus();\n  function close(code){overlay.remove();onDone(code);}\n  overlay.querySelector('#mmPromoApply').addEventListener('click',()=>close(input.value));\n  overlay.querySelector('#mmPromoSkip').addEventListener('click',()=>close(null));\n  overlay.querySelector('#mmPromoClose').addEventListener('click',()=>close(undefined));\n  input.addEventListener('keydown',e=>{if(e.key==='Enter')close(input.value);});\n  overlay.addEventListener('click',e=>{if(e.target===overlay)close(undefined);});\n}\n\nfunction downloadMatchPDF(){\n  const ra=document.getElementById('resultsArea');\n  if(!ra||ra.style.display==='none'){\n    _mmShowFormError('⚠️ প্রথমে কুষ্ঠি মিলন গণনা করুন।');\n    document.querySelector('.calc-btn').scrollIntoView({behavior:'smooth',block:'center'});\n    return;\n  }\n  /* পেমেন্ট-পরবর্তী রি-ডাউনলোড: প্রথমবার পে করার পর একই সেশনে আবার পে না করেই PDF আবার তৈরি/ডাউনলোড করা যাবে */\n  let _alreadyPaid=false;\n  try{_alreadyPaid=sessionStorage.getItem('myastro_match_paid')==='1';}catch(e){}\n  if(_alreadyPaid){_doMatchPrint();return;}\n  _mmPromoModal(function(code){\n    if(code===undefined)return; // বাতিল\n    if(code&&code.trim().toUpperCase()===_MM_PROMO){_doMatchPrint();return;}\n    if(typeof Razorpay!=='undefined'){\n      const rzp=new Razorpay({\n        key:_MM_RZP_KEY,amount:5100,currency:'INR',\n        name:'MyAstrology',description:'কুষ্ঠি মিলন PDF',\n        image:'https://myastrology.in/images/MyAstrology-Ranghat-logo.png',\n        handler:function(){\n          try{sessionStorage.setItem('myastro_match_paid','1');}catch(e){}\n          _doMatchPrint();\n        },\n        modal:{ondismiss:function(){}},\n        theme:{color:'#b8860b'}\n      });\n      rzp.open();\n    } else {\n      _doMatchPrint();\n    }\n  });\n}\nfunction _doMatchPrint(){\n  const ra=document.getElementById('resultsArea');\n  if(!ra)return;\n  const gName=(document.getElementById('girlName')||{}).value||'কন্যা';\n  const bName=(document.getElementById('boyName')||{}).value||'বর';\n  const gDOB=(document.getElementById('girlDOB')||{}).value||'';\n  const gCity=(document.getElementById('girlCity')||{}).value||'';\n  const bDOB=(document.getElementById('boyDOB')||{}).value||'';\n  const bCity=(document.getElementById('boyCity')||{}).value||'';\n  const ld=window._mmLastData||{};\n  const lgd=ld.gd||{},lbd=ld.bd||{},lr=ld.result||{};\n  const lTotal=lr.totalPoints!=null?lr.totalPoints:0;\n  const lMax=lr.maxScore||36;\n  const lPct=(lTotal/36)*100;\n  const lVerdict=lPct>=72?'মিলন শুভ':lPct>=50?'মিলন মধ্যম':'মিলন অশুভ';\n  const raClone=ra.cloneNode(true);\n  raClone.querySelectorAll('#mmPanel-pdf,#mmPanel-premium,#mmPanel-special,#mmDynamicCTA,.mm-promo-mini-wrap').forEach(function(el){\n    el.parentNode&&el.parentNode.removeChild(el);\n  });\n  raClone.querySelectorAll('.mm-tab-panel').forEach(function(el){el.style.display='block';});\n  const payload={\n    girlName:gName,boyName:bName,\n    girlInfo:[gDOB,gCity].filter(Boolean).join(' · '),\n    boyInfo:[bDOB,bCity].filter(Boolean).join(' · '),\n    girlLagna:lgd.lagnaRashi||'—',girlRashi:lgd.moonRashi||'—',girlNakshatra:lgd.moonNakshatra||'—',\n    boyLagna:lbd.lagnaRashi||'—',boyRashi:lbd.moonRashi||'—',boyNakshatra:lbd.moonNakshatra||'—',\n    matchScore:lTotal,matchMax:lMax,matchVerdict:lVerdict,\n    html:raClone.innerHTML\n  };\n  window._matchPrintData=payload;\n  try{localStorage.setItem('match_print_data',JSON.stringify(payload));}catch(e){}\n  const newTab=window.open('match-making-print.html','_blank');\n  if(!newTab){window.print();}\n}\n\nfunction prefillFromURL(){\n  const p=new URLSearchParams(window.location.search);\n  if(!p.get('dob'))return;\n  const gender=p.get('gender')||'male';\n  const prefix=gender==='female'?'girl':'boy';\n  const name=p.get('name')||'';\n  const dob=p.get('dob')||'';\n  const tob=p.get('tob')||'';\n  const lat=p.get('lat')||'';\n  const lon=p.get('lon')||'';\n  const city=p.get('city')||'';\n  const tz=p.get('tz')||'';\n  const nameEl=document.getElementById(prefix+'Name');\n  const dobEl=document.getElementById(prefix+'DOB');\n  const tobEl=document.getElementById(prefix+'TOB');\n  const latEl=document.getElementById(prefix+'Lat');\n  const lonEl=document.getElementById(prefix+'Lon');\n  const cityEl=document.getElementById(prefix+'City');\n  const tzEl=document.getElementById(prefix+'TZ');\n  if(nameEl)nameEl.value=name;\n  if(dobEl){dobEl.setAttribute('value',dob);dobEl.value=dob;dobEl.dispatchEvent(new Event('change'));}\n  if(tobEl){tobEl.setAttribute('value',tob);tobEl.value=tob;}\n  if(latEl)latEl.value=lat;\n  if(lonEl)lonEl.value=lon;\n  if(cityEl)cityEl.value=city;\n  if(tzEl&&tz){\n    const tzNum=parseFloat(tz);\n    let best=null,bestDiff=99;\n    Array.from(tzEl.options).forEach(function(o){\n      const d=Math.abs(parseFloat(o.value)-tzNum);\n      if(d<bestDiff){bestDiff=d;best=o.value;}\n    });\n    if(best!==null)tzEl.value=best;\n  }\n  // অপর পক্ষের প্যানেল হাইলাইট করুন যাতে বোঝা যায় পূরণ করতে হবে\n  const otherPrefix=prefix==='girl'?'boy':'girl';\n  const otherPanel=document.querySelector('.'+otherPrefix+'-panel');\n  if(otherPanel)otherPanel.style.boxShadow='0 0 0 3px #ffd700';\n  const otherName=document.getElementById(otherPrefix+'Name');\n  if(otherName)setTimeout(()=>otherName.focus(),100);\n}\n\n/* ══ তারিখ/সময় ড্রপডাউন <-> hidden ইনপুট সিঙ্ক (kundali.html ধাঁচ) ══ */\nlet _mmFormReady=false;\nfunction _mmSyncDateTime(prefix){\n  if(!_mmFormReady)return;\n  const day=document.getElementById(prefix+'DobDay').value;\n  const month=document.getElementById(prefix+'DobMonth').value;\n  const year=document.getElementById(prefix+'DobYear').value;\n  const hour=document.getElementById(prefix+'TobHour').value;\n  const min=document.getElementById(prefix+'TobMin').value;\n  const sec=document.getElementById(prefix+'TobSec').value||'0';\n  const dobEl=document.getElementById(prefix+'DOB');\n  const tobEl=document.getElementById(prefix+'TOB');\n  dobEl.value=(day&&month&&year)?(year+'-'+String(month).padStart(2,'0')+'-'+String(day).padStart(2,'0')):'';\n  tobEl.value=(hour!==''&&min!=='')?(String(hour).padStart(2,'0')+':'+String(min).padStart(2,'0')+':'+String(sec).padStart(2,'0')):'';\n  saveMMForm();\n}\nfunction _mmReverseSyncDateTime(prefix){\n  const dobVal=(document.getElementById(prefix+'DOB')||{}).value||'';\n  const tobVal=(document.getElementById(prefix+'TOB')||{}).value||'';\n  if(dobVal){\n    const parts=dobVal.split('-');\n    if(parts.length===3){\n      const yEl=document.getElementById(prefix+'DobYear'),mEl=document.getElementById(prefix+'DobMonth'),dEl=document.getElementById(prefix+'DobDay');\n      if(yEl)yEl.value=parts[0];\n      if(mEl)mEl.value=String(parseInt(parts[1],10));\n      if(dEl)dEl.value=String(parseInt(parts[2],10));\n    }\n  }\n  if(tobVal){\n    const tparts=tobVal.split(':');\n    const hEl=document.getElementById(prefix+'TobHour'),miEl=document.getElementById(prefix+'TobMin'),sEl=document.getElementById(prefix+'TobSec');\n    if(hEl&&tparts[0]!=null)hEl.value=String(parseInt(tparts[0],10));\n    if(miEl&&tparts[1]!=null)miEl.value=String(parseInt(tparts[1],10));\n    if(sEl&&tparts[2]!=null)sEl.value=String(parseInt(tparts[2],10));\n  }\n}\n(function(){\n  function fillDay(id){const el=document.getElementById(id);for(let i=1;i<=31;i++){const o=document.createElement('option');o.value=i;o.textContent=i;el.appendChild(o);}}\n  function fillYear(id){const el=document.getElementById(id);for(let y=new Date().getFullYear();y>=1900;y--){const o=document.createElement('option');o.value=y;o.textContent=y;el.appendChild(o);}}\n  function fillHour(id){const el=document.getElementById(id);for(let h=0;h<24;h++){const o=document.createElement('option');o.value=h;o.textContent=String(h).padStart(2,'0');el.appendChild(o);}}\n  function fillMin(id){const el=document.getElementById(id);for(let m=0;m<60;m++){const o=document.createElement('option');o.value=m;o.textContent=String(m).padStart(2,'0');el.appendChild(o);}}\n  function fillSec(id){const el=document.getElementById(id);el.innerHTML='';for(let s=0;s<60;s++){const o=document.createElement('option');o.value=s;o.textContent=s===0?'০০ সে.':String(s).padStart(2,'0');el.appendChild(o);}}\n  ['girl','boy'].forEach(function(p){\n    fillDay(p+'DobDay');\n    fillYear(p+'DobYear');\n    fillHour(p+'TobHour');\n    fillMin(p+'TobMin');\n    fillSec(p+'TobSec');\n  });\n})();\n\n/* ══ GPS লোকেশন অটো-ডিটেক্ট (kundali.html ধাঁচ) ══ */\nfunction _mmGetGPS(prefix){\n  const msg=document.getElementById(prefix+'GpsMsg');\n  if(!navigator.geolocation){if(msg)msg.textContent='❌ এই ব্রাউজার GPS সমর্থন করে না।';return;}\n  if(msg)msg.textContent='⏳ লোকেশন অনুসন্ধান করা হচ্ছে...';\n  navigator.geolocation.getCurrentPosition(\n    function(pos){\n      const la=pos.coords.latitude,lo=pos.coords.longitude;\n      document.getElementById(prefix+'Lat').value=la.toFixed(4);\n      document.getElementById(prefix+'Lon').value=lo.toFixed(4);\n      if(typeof fetch==='undefined'){if(msg)msg.textContent='📍 লোকেশন পাওয়া গেছে';saveMMForm();return;}\n      fetch('https://nominatim.openstreetmap.org/reverse?format=json&lat='+la+'&lon='+lo+'&accept-language=bn')\n        .then(r=>r.json())\n        .then(data=>{\n          const a=data.address||{};\n          const city=a.city||a.town||a.village||a.county||a.state_district||'';\n          if(city){\n            document.getElementById(prefix+'City').value=city;\n            if(msg)msg.textContent='📍 '+city+' পাওয়া গেছে';\n          }else{if(msg)msg.textContent='📍 লোকেশন পাওয়া গেছে';}\n          saveMMForm();\n        })\n        .catch(()=>{if(msg)msg.textContent='📍 লোকেশন পাওয়া গেছে (শহরের নাম পাওয়া যায়নি)';saveMMForm();});\n    },\n    function(err){\n      if(!msg)return;\n      const latVal=document.getElementById(prefix+'Lat').value;\n      if(err.code===1){\n        if(latVal){msg.textContent='';}\n        else msg.textContent='❌ GPS অনুমতি দেননি। ম্যানুয়ালি অক্ষাংশ/দ্রাঘিমাংশ লিখুন।';\n      } else if(err.code===2)msg.textContent='❌ লোকেশন পাওয়া যায়নি। পরে আবার চেষ্টা করুন।';\n      else if(err.code===3)msg.textContent='❌ সময়সীমা শেষ। পুনরায় চেষ্টা করুন।';\n      else msg.textContent='❌ GPS ত্রুটি।';\n      if(msg.textContent)setTimeout(()=>{msg.textContent='';},5000);\n    },\n    {timeout:10000,maximumAge:60000}\n  );\n}\n\ndocument.addEventListener('DOMContentLoaded',function(){\n  setupCitySearch('girlCity','girlCitySugg','girlLat','girlLon','girlTZ');\n  setupCitySearch('boyCity','boyCitySugg','boyLat','boyLon','boyTZ');\n  prefillFromURL();\n  const _restored=restoreMMForm();\n  _mmReverseSyncDateTime('girl');\n  _mmReverseSyncDateTime('boy');\n  /* পূর্বের তথ্য সম্পূর্ণ থাকলে রিফ্রেশের পর আবার পূরণ করতে না হয় — ফলাফল প্রস্তুত করা হয়, কিন্তু\n     ফর্ম পেজেই থাকা হয় (ব্যবহারকারী ট্যাব থেকে ফলাফল দেখতে পারবেন) */\n  if(_restored){\n    const v=_mmValidate();\n    if(v.valid)setTimeout(function(){\n      runMatchCalc();\n      setTimeout(function(){_mmSwitchTab('form');},80);\n    },60);\n  }\n  /* save on any input/change */\n  const MM_FIELDS=['girlName','girlDOB','girlTOB','girlCity','girlLat','girlLon','girlTZ',\n                   'boyName','boyDOB','boyTOB','boyCity','boyLat','boyLon','boyTZ'];\n  MM_FIELDS.forEach(function(id){\n    const el=document.getElementById(id);\n    if(el)el.addEventListener('change',saveMMForm);\n    if(el&&el.tagName==='INPUT')el.addEventListener('input',saveMMForm);\n  });\n  /* ব্রাউজারের নেটিভ ফর্ম-রিস্টোর সম্পন্ন হওয়ার পর সিঙ্ক চালু করা হচ্ছে — রিফ্রেশে ডেটা মুছে যাওয়া রোধ করে */\n  setTimeout(function(){_mmFormReady=true;},0);\n});\n\nfunction goToKundali(gender){\n  const prefix=gender==='girl'?'girl':'boy';\n  const name=(document.getElementById(prefix+'Name')||{}).value||'';\n  const dob=(document.getElementById(prefix+'DOB')||{}).value||'';\n  const tob=(document.getElementById(prefix+'TOB')||{}).value||'';\n  const lat=(document.getElementById(prefix+'Lat')||{}).value||'';\n  const lon=(document.getElementById(prefix+'Lon')||{}).value||'';\n  const city=(document.getElementById(prefix+'City')||{}).value||'';\n  const tz=(document.getElementById(prefix+'TZ')||{}).value||'5.5';\n  const g=gender==='girl'?'female':'male';\n  const params=new URLSearchParams({name,dob,tob,lat,lon,city,gender:g,tz,auto:'1'});\n  /* নতুন ট্যাবে কুন্ডলি পেজ খুলবে — এই ট্যাবে ফর্ম ও ফলাফল অপরিবর্তিত থাকবে */\n  window.open('kundali.html?'+params.toString(),'_blank');\n}\n\n/* ══ প্রিমিয়াম (₹৫০১) / স্পেশাল (₹১৫০১) মিলন রিপোর্ট — অর্ডার ফ্লো ══ */\nvar _MM_PREM_PROMO={Prem:'Rudra501',Spec:'Rudra1501'};\nvar _MM_AMOUNT={Prem:50100,Spec:150100};\nvar _MM_LABEL={Prem:'প্রিমিয়াম মিলন রিপোর্ট',Spec:'স্পেশাল মিলন রিপোর্ট + পরামর্শ'};\nvar _MM_THEME={Prem:'#7b1fa2',Spec:'#7a2e2e'};\n\nfunction _mmOpenBenefits(kind){\n  const ra=document.getElementById('resultsArea');\n  if(!ra||ra.style.display==='none'){alert('প্রথমে মিলন গণনা করুন।');return;}\n  const bv=document.getElementById('_mm'+kind+'Benefits');\n  bv.style.display='flex';\n  setTimeout(()=>bv.style.opacity='1',10);\n}\nfunction _mmCloseBenefits(kind){\n  const bv=document.getElementById('_mm'+kind+'Benefits');\n  bv.style.opacity='0';\n  setTimeout(()=>bv.style.display='none',300);\n}\nfunction _mmApplyPromo(kind){\n  const inp=document.getElementById('_mm'+kind+'Promo');\n  const msg=document.getElementById('_mm'+kind+'PromoMsg');\n  const code=(inp.value||'').trim();\n  if(code.toUpperCase()!==_MM_PREM_PROMO[kind].toUpperCase()){\n    inp.style.borderColor='#f44336';\n    msg.style.color='#f44336';\n    msg.textContent='❌ ভুল প্রোমো কোড।';\n    return;\n  }\n  inp.style.borderColor='#4caf50';\n  msg.style.color='#4caf50';\n  msg.textContent='✅ প্রোমো কোড গৃহীত হয়েছে!';\n  document.getElementById('_mm'+kind+'Pid').value='PROMO-'+_MM_PREM_PROMO[kind]+'-'+Date.now();\n  _mmCloseBenefits(kind);\n  setTimeout(()=>_mmOpenOrder(kind),400);\n}\nfunction _mmStartPayment(kind){\n  _mmCloseBenefits(kind);\n  if(typeof Razorpay==='undefined'){alert('পেমেন্ট গেটওয়ে লোড হচ্ছে… একটু পরে আবার চেষ্টা করুন।');return;}\n  new Razorpay({\n    key:_MM_RZP_KEY,amount:_MM_AMOUNT[kind],currency:'INR',\n    name:'MyAstrology',description:_MM_LABEL[kind],\n    image:'https://myastrology.in/images/MyAstrology-Ranghat-logo.png',\n    prefill:{name:((window._mmLastData||{}).gName||'')+' & '+((window._mmLastData||{}).bName||'')},\n    handler:function(res){\n      document.getElementById('_mm'+kind+'Pid').value=res.razorpay_payment_id;\n      _mmOpenOrder(kind);\n    },\n    theme:{color:_MM_THEME[kind]}\n  }).open();\n}\nfunction _mmOpenOrder(kind){\n  const ov=document.getElementById('_mm'+kind+'Ov');\n  ov.style.display='flex';\n  setTimeout(()=>ov.style.opacity='1',10);\n}\nfunction _mmCloseOrder(kind){\n  const ov=document.getElementById('_mm'+kind+'Ov');\n  ov.style.opacity='0';\n  setTimeout(()=>ov.style.display='none',300);\n}\nfunction _mmSubmitOrder(kind){\n  const email=(document.getElementById('_mm'+kind+'Email').value||'').trim();\n  const phone=(document.getElementById('_mm'+kind+'Phone').value||'').replace(/\\D/g,'').slice(0,10);\n  if(!email||!phone){alert('ইমেইল ও WhatsApp নম্বর আবশ্যক।');return;}\n  const qs=[1,2,3].map(i=>(document.getElementById('_mm'+kind+'Q'+i)||{}).value||'').filter(q=>q.trim());\n  const pid=document.getElementById('_mm'+kind+'Pid').value;\n  const d=window._mmLastData||{};\n  const gd=d.gd||{},bd=d.bd||{},result=d.result||{},gName=d.gName||'কন্যা',bName=d.bName||'বর';\n  const total=result.totalPoints||result.totalScore||0;\n  const btn=document.getElementById('_mm'+kind+'SubBtn');\n  btn.disabled=true;btn.textContent='প্রস্তুত হচ্ছে…';\n\n  try{\n    const orderData={pid,email,phone,questions:qs,kind,gName,bName,gd,bd,result,ts:Date.now()};\n    localStorage.setItem('_mmPremPendingOrder_'+kind,JSON.stringify(orderData));\n    const ra=document.getElementById('resultsArea');\n    if(ra){\n      const clone=ra.cloneNode(true);\n      localStorage.setItem('_mmPremPrintHtml_'+kind,JSON.stringify({gName,bName,html:clone.innerHTML,isPremium:true,kind}));\n    }\n  }catch(e){}\n\n  const NL='\\n';\n  let waMsg='🙏 *'+(kind==='Spec'?'স্পেশাল':'প্রিমিয়াম')+' মিলন রিপোর্ট অর্ডার*'+NL+NL\n    +'👰 কন্যা: '+gName+' | লগ্ন: '+(gd.lagnaRashi||'—')+' | রাশি: '+(gd.moonRashi||'—')+' | নক্ষত্র: '+(gd.moonNakshatra||'—')+NL\n    +'🤵 বর: '+bName+' | লগ্ন: '+(bd.lagnaRashi||'—')+' | রাশি: '+(bd.moonRashi||'—')+' | নক্ষত্র: '+(bd.moonNakshatra||'—')+NL\n    +'⭐ অষ্টকূট স্কোর: '+total+' / ৩৬'+NL\n    +'📧 Email: '+email+NL\n    +'📱 WhatsApp: +91'+phone+NL\n    +'💳 Payment ID: '+pid;\n  if(qs.length)waMsg+=NL+NL+'❓ প্রশ্ন:'+NL+qs.map((q,i)=>(i+1)+'. '+q).join(NL);\n  waMsg+=NL+NL+'অর্ডার নিশ্চিত করুন। ধন্যবাদ 🙏';\n\n  const waUrl='https://wa.me/919333122768?text='+encodeURIComponent(waMsg);\n  _mmShowSuccessOrder(kind,email,waUrl);\n}\nfunction _mmShowSuccessOrder(kind,email,waUrl){\n  document.getElementById('_mm'+kind+'Body').innerHTML=\n    '<div style=\"text-align:center;padding:20px 10px;font-family:\\'Noto Sans Bengali\\',serif\">'\n    +'<div style=\"font-size:3rem;margin-bottom:10px\">✅</div>'\n    +'<h3 style=\"color:#2e7d32;font-size:1.1rem;margin-bottom:8px\">পেমেন্ট সফল!</h3>'\n    +'<p style=\"color:#333;line-height:1.8;font-size:.9rem;margin-bottom:14px\">'\n    +'এখন নিচের বাটনে ক্লিক করে WhatsApp-এ অর্ডারের বিবরণ পাঠান।<br>'\n    +'<span style=\"font-size:.8rem;color:#666\">আপনাদের কুষ্ঠি মিলন তথ্য ও প্রশ্ন স্বয়ংক্রিয়ভাবে যুক্ত হয়ে যাবে।</span></p>'\n    +'<a href=\"'+waUrl+'\" target=\"_blank\" rel=\"noopener\" '\n    +'style=\"display:inline-flex;align-items:center;gap:8px;background:#25d366;color:#fff;'\n    +'padding:12px 24px;border-radius:50px;font-weight:800;font-size:.95rem;text-decoration:none;'\n    +'box-shadow:0 4px 16px rgba(37,211,102,.4);margin-bottom:14px\">'\n    +'<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 24 24\" width=\"1em\" height=\"1em\" fill=\"currentColor\" style=\"display:inline-block;vertical-align:-0.125em\"><path d=\"M19.05 4.91A9.82 9.82 0 0 0 12.04 2c-5.46 0-9.91 4.45-9.91 9.91c0 1.75.46 3.45 1.32 4.95L2.05 22l5.25-1.38c1.45.79 3.08 1.21 4.74 1.21c5.46 0 9.91-4.45 9.91-9.91c0-2.65-1.03-5.14-2.9-7.01m-7.01 15.24c-1.48 0-2.93-.4-4.2-1.15l-.3-.18l-3.12.82l.83-3.04l-.2-.31a8.26 8.26 0 0 1-1.26-4.38c0-4.54 3.7-8.24 8.24-8.24c2.2 0 4.27.86 5.82 2.42a8.18 8.18 0 0 1 2.41 5.83c.02 4.54-3.68 8.23-8.22 8.23m4.52-6.16c-.25-.12-1.47-.72-1.69-.81c-.23-.08-.39-.12-.56.12c-.17.25-.64.81-.78.97c-.14.17-.29.19-.54.06c-.25-.12-1.05-.39-1.99-1.23c-.74-.66-1.23-1.47-1.38-1.72c-.14-.25-.02-.38.11-.51c.11-.11.25-.29.37-.43s.17-.25.25-.41c.08-.17.04-.31-.02-.43s-.56-1.34-.76-1.84c-.2-.48-.41-.42-.56-.43h-.48c-.17 0-.43.06-.66.31c-.22.25-.86.85-.86 2.07s.89 2.4 1.01 2.56c.12.17 1.75 2.67 4.23 3.74c.59.26 1.05.41 1.41.52c.59.19 1.13.16 1.56.1c.48-.07 1.47-.6 1.67-1.18c.21-.58.21-1.07.14-1.18s-.22-.16-.47-.28\"/></svg> WhatsApp-এ অর্ডার পাঠান</a>'\n    +'<p style=\"color:#555;font-size:.8rem;margin-bottom:4px\">ইমেইলেও নিশ্চিতকরণ পাঠানো হবে:</p>'\n    +'<p style=\"color:#7b1fa2;font-weight:700;font-size:.88rem\">'+email+'</p>'\n    +'<button onclick=\"_mmCloseOrder(\\''+kind+'\\')\" style=\"margin-top:14px;padding:8px 22px;background:#f0e8ff;color:#7b1fa2;border:1px solid #d0b0f0;border-radius:8px;cursor:pointer;font-family:inherit;font-size:.85rem\">বন্ধ করুন</button>'\n    +'</div>';\n}\n\nfunction saveMMForm(){\n  const ids=['girlName','girlDOB','girlTOB','girlCity','girlLat','girlLon','girlTZ',\n             'boyName','boyDOB','boyTOB','boyCity','boyLat','boyLon','boyTZ'];\n  const d={};\n  ids.forEach(function(id){const el=document.getElementById(id);if(el)d[id]=el.value;});\n  try{localStorage.setItem('mmForm',JSON.stringify(d));}catch(e){}\n}\n\nfunction restoreMMForm(){\n  let d;\n  try{d=JSON.parse(localStorage.getItem('mmForm')||'null');}catch(e){}\n  if(!d)return false;\n  /* URL prefill (?dob=...) থাকলে সেই পক্ষের ফিল্ড prefillFromURL() পূরণ করবে —\n     বাকি পক্ষের সেভ করা ডেটা localStorage থেকে পুনরুদ্ধার করা হয়, যাতে রিফ্রেশে মুছে না যায় */\n  const p=new URLSearchParams(window.location.search);\n  const skipPrefix=p.get('dob')?((p.get('gender')||'male')==='female'?'girl':'boy'):null;\n  const ids=['girlName','girlDOB','girlTOB','girlCity','girlLat','girlLon','girlTZ',\n             'boyName','boyDOB','boyTOB','boyCity','boyLat','boyLon','boyTZ'];\n  let restoredAny=false;\n  ids.forEach(function(id){\n    if(skipPrefix&&id.indexOf(skipPrefix)===0)return;\n    const el=document.getElementById(id);\n    if(el&&d[id]!=null){el.value=d[id];restoredAny=true;}\n  });\n  return restoredAny;\n}\n</script>\n\n</body>\n</html>\n";
